export const D_PRAC = [{"icon":"car","name":{"CA":"Com arribar","ES":"Cómo llegar","EN":"Getting there","FR":"Comment arriver","DE":"Anreise","NL":"Hoe te komen","PT":"Como chegar"},"tagline":{"CA":"Cotxe, tren i autobús","ES":"Coche, tren y autobús","EN":"Car, train and bus","FR":"Voiture, train et bus","DE":"Auto, Zug und Bus","NL":"Auto, trein en bus","PT":"Carro, comboio e autocarro"},"lead":{"CA":"El delta és un lloc on el cotxe és gairebé imprescindible per moure's bé. El transport públic arriba als pobles principals però no penetra al parc natural. Si vens sense cotxe, combina el tren fins a L'Aldea o l'Ampolla amb bici de lloguer o taxi.","ES":"El delta es un lugar donde el coche es casi imprescindible para moverse bien. El transporte público llega a los pueblos principales pero no penetra al parque natural. Si vienes sin coche, combina el tren hasta L'Aldea o l'Ampolla con bici de alquiler o taxi.","EN":"The delta is a place where a car is almost essential to get around properly. Public transport reaches the main villages but does not penetrate the nature park. If you come without a car, combine the train to L'Aldea or l'Ampolla with a hire bike or taxi.","FR":"Le delta est un endroit où la voiture est presque indispensable pour bien se déplacer. Les transports publics atteignent les principaux villages mais ne pénètrent pas dans le parc naturel. Si vous venez sans voiture, combinez le train jusqu'à L'Aldea ou l'Ampolla avec un vélo de location ou un taxi.","DE":"Das Delta ist ein Ort, an dem ein Auto fast unerlässlich ist, um sich gut zu bewegen. Der öffentliche Nahverkehr erreicht die wichtigsten Dörfer, dringt aber nicht in den Naturpark vor. Wenn Sie ohne Auto kommen, kombinieren Sie den Zug nach L'Aldea oder l'Ampolla mit einem Mietfahrrad oder Taxi.","NL":"De delta is een plek waar een auto bijna onmisbaar is om goed te bewegen. Het openbaar vervoer bereikt de belangrijkste dorpen maar dringt niet door in het natuurpark. Als u zonder auto komt, combineer dan de trein naar L'Aldea of l'Ampolla met een huurfiets of taxi.","PT":"O delta é um lugar onde o carro é quase imprescindível para se mover bem. O transporte público chega às principais vilas mas não penetra no parque natural. Se vieres sem carro, combina o comboio até L'Aldea ou l'Ampolla com bicicleta alugada ou táxi."},"sections":[{"title":{"CA":"Des de Barcelona","ES":"Desde Barcelona","EN":"From Barcelona","FR":"Depuis Barcelone","DE":"Von Barcelona","NL":"Vanuit Barcelona","PT":"Desde Barcelona"},"body":{"CA":"AP-7 sud fins a la sortida 39A (l'Ampolla) o la 40 (Tortosa/Deltebre). Uns 200 km, 2 hores aprox. Alternativa sense peatge: N-340 per la costa, més llarga però amb paisatge. En tren: Euromed o regionals fins a L'Aldea-Amposta-Tortosa; des d'allí taxi o bus HIFE a Deltebre.","ES":"AP-7 sur hasta la salida 39A (l'Ampolla) o la 40 (Tortosa/Deltebre). Unos 200 km, 2 horas aprox. Alternativa sin peaje: N-340 por la costa, más larga pero con paisaje. En tren: Euromed o regionales hasta L'Aldea-Amposta-Tortosa; desde allí taxi o bus HIFE a Deltebre.","EN":"AP-7 south to exit 39A (l'Ampolla) or 40 (Tortosa/Deltebre). About 200 km, approx. 2 hours. Toll-free alternative: N-340 along the coast, longer but scenic. By train: Euromed or regional trains to L'Aldea-Amposta-Tortosa; then taxi or HIFE bus to Deltebre.","FR":"AP-7 sud jusqu'à la sortie 39A (l'Ampolla) ou la 40 (Tortosa/Deltebre). Environ 200 km, 2 heures. Alternative sans péage : N-340 le long de la côte, plus longue mais pittoresque. En train : Euromed ou régionaux jusqu'à L'Aldea-Amposta-Tortosa ; puis taxi ou bus HIFE vers Deltebre.","DE":"AP-7 Richtung Süden bis Ausfahrt 39A (l'Ampolla) oder 40 (Tortosa/Deltebre). Etwa 200 km, ca. 2 Stunden. Mautfreie Alternative: N-340 an der Küste, länger aber malerisch. Mit dem Zug: Euromed oder Regionalzüge nach L'Aldea-Amposta-Tortosa; dann Taxi oder HIFE-Bus nach Deltebre.","NL":"AP-7 richting zuiden tot afrit 39A (l'Ampolla) of 40 (Tortosa/Deltebre). Ongeveer 200 km, ca. 2 uur. Tolvrij alternatief: N-340 langs de kust, langer maar schilderachtig. Per trein: Euromed of regionale treinen naar L'Aldea-Amposta-Tortosa; dan taxi of HIFE-bus naar Deltebre.","PT":"AP-7 sul até à saída 39A (l'Ampolla) ou a 40 (Tortosa/Deltebre). Cerca de 200 km, aprox. 2 horas. Alternativa sem portagem: N-340 pela costa, mais longa mas com paisagem. De comboio: Euromed ou regionais até L'Aldea-Amposta-Tortosa; de lá táxi ou autocarro HIFE a Deltebre."}},{"title":{"CA":"Des de València","ES":"Desde Valencia","EN":"From Valencia","FR":"Depuis Valence","DE":"Von Valencia","NL":"Vanuit Valencia","PT":"Desde Valência"},"body":{"CA":"AP-7 nord fins a la sortida 41 (Amposta / la Ràpita) o la 40 (Deltebre). Uns 200 km, 2-2,5 hores. En tren: Cercanies fins a Castelló, regionals fins a Tortosa o Vinaròs; des d'allí autobús o taxi.","ES":"AP-7 norte hasta la salida 41 (Amposta / la Ràpita) o la 40 (Deltebre). Unos 200 km, 2-2,5 horas. En tren: Cercanías hasta Castellón, regionales hasta Tortosa o Vinaròs; desde allí autobús o taxi.","EN":"AP-7 north to exit 41 (Amposta / la Ràpita) or 40 (Deltebre). About 200 km, 2-2.5 hours. By train: Cercanias to Castellón, regional to Tortosa or Vinaròs; then bus or taxi.","FR":"AP-7 nord jusqu'à la sortie 41 (Amposta / la Ràpita) ou la 40 (Deltebre). Environ 200 km, 2-2,5 heures. En train : Cercanías jusqu'à Castellón, régionaux jusqu'à Tortosa ou Vinaròs ; puis bus ou taxi.","DE":"AP-7 Richtung Norden bis Ausfahrt 41 (Amposta / la Ràpita) oder 40 (Deltebre). Etwa 200 km, 2-2,5 Stunden. Mit dem Zug: Cercanias nach Castellón, Regional nach Tortosa oder Vinaròs; dann Bus oder Taxi.","NL":"AP-7 richting noorden tot afrit 41 (Amposta / la Ràpita) of 40 (Deltebre). Ongeveer 200 km, 2-2,5 uur. Per trein: Cercanias naar Castellón, regionaal naar Tortosa of Vinaròs; dan bus of taxi.","PT":"AP-7 norte até à saída 41 (Amposta / la Ràpita) ou a 40 (Deltebre). Cerca de 200 km, 2-2,5 horas. De comboio: Cercanias até Castelló, regional até Tortosa ou Vinaròs; de lá autocarro ou táxi."}},{"title":{"CA":"Important: el cotxe és clau","ES":"Importante: el coche es clave","EN":"Important: the car is key","FR":"Important : la voiture est essentielle","DE":"Wichtig: Das Auto ist entscheidend","NL":"Belangrijk: de auto is essentieel","PT":"Importante: o carro é fundamental"},"body":{"CA":"El delta no té transport interior organitzat. No hi ha autobusos entre platges, llacunes o miradors. Si vens en tren, el millor és llogar cotxe o bici a l'Ampolla o Deltebre. En bici s'accedeix bé a la majoria d'espais del parc; a cotxe, a tots.","ES":"El delta no tiene transporte interior organizado. No hay autobuses entre playas, lagunas o miradores. Si vienes en tren, lo mejor es alquilar coche o bici en l'Ampolla o Deltebre. En bici se accede bien a la mayoría de espacios del parque; en coche, a todos.","EN":"The delta has no organised internal transport. There are no buses between beaches, lagoons or viewpoints. If you come by train, the best option is to hire a car or bike in l'Ampolla or Deltebre. By bike you can reach most park spaces; by car, all of them.","FR":"Le delta n'a pas de transport intérieur organisé. Il n'y a pas de bus entre les plages, les lagunes ou les belvédères. Si vous venez en train, la meilleure option est de louer une voiture ou un vélo à l'Ampolla ou Deltebre. À vélo, on accède à la plupart des espaces du parc ; en voiture, à tous.","DE":"Das Delta hat keinen organisierten Innenverkehr. Es gibt keine Busse zwischen Stränden, Lagunen oder Aussichtspunkten. Wenn Sie mit dem Zug kommen, ist die beste Option, in l'Ampolla oder Deltebre ein Auto oder Fahrrad zu mieten. Mit dem Fahrrad erreicht man die meisten Parkräume; mit dem Auto alle.","NL":"De delta heeft geen georganiseerd intern vervoer. Er zijn geen bussen tussen stranden, lagunes of uitkijkpunten. Als u met de trein komt, is de beste optie een auto of fiets te huren in l'Ampolla of Deltebre. Per fiets bereikt u de meeste parkruimtes; per auto alle.","PT":"O delta não tem transporte interior organizado. Não há autocarros entre praias, lagoas ou miradouros. Se vieres de comboio, a melhor opção é alugar carro ou bicicleta em l'Ampolla ou Deltebre. De bicicleta acede-se bem à maioria dos espaços do parque; de carro, a todos."}}]},{"icon":"cal","name":{"CA":"Quan anar","ES":"Cuándo ir","EN":"When to go","FR":"Quand aller","DE":"Wann reisen","NL":"Wanneer gaan","PT":"Quando ir"},"tagline":{"CA":"Cada estació té el seu delta","ES":"Cada estación tiene su delta","EN":"Each season has its own delta","FR":"Chaque saison a son delta","DE":"Jede Jahreszeit hat ihr Delta","NL":"Elk seizoen heeft zijn eigen delta","PT":"Cada estação tem o seu delta"},"lead":{"CA":"El delta canvia radicalment amb les estacions: el color dels arrossars, el nombre d'aus, la temperatura i l'ambient varien de manera espectacular. No hi ha una millor època, sinó la millor per als teus interessos.","ES":"El delta cambia radicalmente con las estaciones: el color de los arrozales, el número de aves, la temperatura y el ambiente varían de manera espectacular. No hay una mejor época, sino la mejor para tus intereses.","EN":"The delta changes radically with the seasons: the colour of the rice fields, the number of birds, the temperature and the atmosphere all vary spectacularly. There is no single best time, only the best time for your interests.","FR":"Le delta change radicalement avec les saisons : la couleur des rizières, le nombre d'oiseaux, la température et l'ambiance varient de manière spectaculaire. Il n'y a pas de meilleure période, seulement la meilleure pour vos intérêts.","DE":"Das Delta verändert sich radikal mit den Jahreszeiten: die Farbe der Reisfelder, die Anzahl der Vögel, die Temperatur und die Atmosphäre variieren spektakulär. Es gibt keine einzige beste Zeit, nur die beste für Ihre Interessen.","NL":"De delta verandert radicaal met de seizoenen: de kleur van de rijstvelden, het aantal vogels, de temperatuur en de sfeer variëren spectaculair. Er is geen enkele beste tijd, alleen de beste voor uw interesses.","PT":"O delta muda radicalmente com as estações: a cor dos arrozais, o número de aves, a temperatura e o ambiente variam de forma espetacular. Não há uma melhor época, mas sim a melhor para os seus interesses."},"sections":[{"title":{"CA":"Primavera: el delta s'omple de vida","ES":"Primavera: el delta se llena de vida","EN":"Spring: the delta fills with life","FR":"Printemps : le delta se remplit de vie","DE":"Frühling: Das Delta füllt sich mit Leben","NL":"Lente: de delta vult zich met leven","PT":"Primavera: o delta enche-se de vida"},"body":{"CA":"Abril i maig és quan el delta ofereix el millor equilibri. Les temperatures (15-23°C) són perfectes per anar en bici, a peu o en kayak. Els arrossars s'inunden i comencen a verdejà. Les aus migratòries arriben en grans quantitats: flamencos, cigonyes, becs d'alena, xatracs. Pocs turistes.","ES":"Abril y mayo es cuando el delta ofrece el mejor equilibrio. Las temperaturas (15-23°C) son perfectas para ir en bici, a pie o en kayak. Los arrozales se inundan y empiezan a verdear. Las aves migratorias llegan en grandes cantidades: flamencos, cigüeñas, avocetas, charranes. Pocos turistas.","EN":"April and May is when the delta offers the best balance. Temperatures (15-23°C) are perfect for cycling, walking or kayaking. The rice fields flood and start to green up. Migratory birds arrive in large numbers: flamingos, storks, avocets, terns. Few tourists.","FR":"Avril et mai, c'est quand le delta offre le meilleur équilibre. Les températures (15-23°C) sont parfaites pour faire du vélo, marcher ou faire du kayak. Les rizières s'inondent et commencent à verdir. Les oiseaux migrateurs arrivent en grand nombre : flamants, cigognes, avocettes, sternes. Peu de touristes.","DE":"April und Mai ist, wenn das Delta das beste Gleichgewicht bietet. Die Temperaturen (15-23°C) sind perfekt zum Radfahren, Wandern oder Kajakfahren. Die Reisfelder werden überflutet und beginnen zu grünen. Zugvögel treffen in großer Zahl ein: Flamingos, Störche, Säbelschnäbler, Seeschwalben. Wenige Touristen.","NL":"April en mei is wanneer de delta het beste evenwicht biedt. Temperaturen (15-23°C) zijn perfect voor fietsen, wandelen of kajakken. De rijstvelden worden overstroomd en beginnen te groenen. Trekvogels komen in grote aantallen aan: flamingo's, ooievaars, kluten, sterns. Weinig toeristen.","PT":"Abril e maio é quando o delta oferece o melhor equilíbrio. As temperaturas (15-23°C) são perfeitas para andar de bicicleta, a pé ou de kayak. Os arrozais inundam-se e começam a verdejar. As aves migratórias chegam em grandes quantidades: flamingos, cegonhas, alfaiates, andorinhas-do-mar. Poucos turistas."}},{"title":{"CA":"Tardor: el moment dels arrossars daurats","ES":"Otoño: el momento de los arrozales dorados","EN":"Autumn: the time of golden rice fields","FR":"Automne : le moment des rizières dorées","DE":"Herbst: die Zeit der goldenen Reisfelder","NL":"Herfst: de tijd van de gouden rijstvelden","PT":"Outono: o momento dos arrozais dourados"},"body":{"CA":"Setembre i octubre és quan el paisatge canvia més: els arrossars passen de verd a daurat i els camps s'omplen d'aus migratòries que van cap al sud. La collita de l'arròs (setembre-octubre) és un espectacle únic. La temperatura és suau (18-26°C). Perfecte per a gastronomia, bici i fotografia.","ES":"Septiembre y octubre es cuando el paisaje cambia más: los arrozales pasan de verde a dorado y los campos se llenan de aves migratorias que van hacia el sur. La cosecha del arroz (septiembre-octubre) es un espectáculo único. La temperatura es suave (18-26°C). Perfecto para gastronomía, bici y fotografía.","EN":"September and October is when the landscape changes most: the rice fields go from green to golden and the fields fill with migratory birds heading south. The rice harvest (September-October) is a unique spectacle. Temperatures are mild (18-26°C). Perfect for gastronomy, cycling and photography.","FR":"Septembre et octobre, c'est quand le paysage change le plus : les rizières passent du vert au doré et les champs se remplissent d'oiseaux migrateurs se dirigeant vers le sud. La récolte du riz (septembre-octobre) est un spectacle unique. La température est douce (18-26°C). Parfait pour la gastronomie, le vélo et la photographie.","DE":"September und Oktober ist, wenn sich die Landschaft am meisten verändert: Die Reisfelder wechseln von Grün zu Gold und die Felder füllen sich mit Zugvögeln, die nach Süden ziehen. Die Reisernte (September-Oktober) ist ein einzigartiges Schauspiel. Die Temperatur ist mild (18-26°C). Perfekt für Gastronomie, Radfahren und Fotografie.","NL":"September en oktober is wanneer het landschap het meest verandert: de rijstvelden gaan van groen naar goud en de velden vullen zich met trekvogels die richting het zuiden gaan. De rijstoogst (september-oktober) is een uniek spektakel. De temperatuur is mild (18-26°C). Perfect voor gastronomie, fietsen en fotografie.","PT":"Setembro e outubro é quando a paisagem muda mais: os arrozais passam de verde para dourado e os campos enchem-se de aves migratórias que vão para sul. A colheita do arroz (setembro-outubro) é um espetáculo único. A temperatura é suave (18-26°C). Perfeito para gastronomia, bicicleta e fotografia."}}]},{"icon":"bed","name":{"CA":"On dormir","ES":"Dónde dormir","EN":"Where to stay","FR":"Où dormir","DE":"Wo übernachten","NL":"Waar slapen","PT":"Onde dormir"},"tagline":{"CA":"Hotels, cases rurals, càmpings i barraques","ES":"Hoteles, casas rurales, campings y barracas","EN":"Hotels, rural houses, campsites and barracas","FR":"Hôtels, maisons rurales, campings et barraques","DE":"Hotels, Landhäuser, Campingplätze und Barracas","NL":"Hotels, landhuizen, campings en barracas","PT":"Hotéis, casas rurais, campismo e barraques"},"lead":{"CA":"L'oferta d'allotjament al delta és molt variada: des de grans hotels en línia de mar fins a petites cases rurals enmig dels arrossars, passant per càmpings a la platja i les típiques barraques (cases de palla i fang tradicionals del delta). Hi ha alguna cosa per a cada butxaca i estil.","ES":"La oferta de alojamiento en el delta es muy variada: desde grandes hoteles en línea de mar hasta pequeñas casas rurales en medio de los arrozales, pasando por campings en la playa y las típicas barracas (casas de paja y barro tradicionales del delta). Hay algo para cada bolsillo y estilo.","EN":"The accommodation offer in the delta is very varied: from large seafront hotels to small rural houses in the middle of the rice fields, camping on the beach and the typical barracas (traditional delta houses of straw and mud). There is something for every budget and style.","FR":"L'offre d'hébergement dans le delta est très variée : des grands hôtels en bord de mer aux petites maisons rurales au milieu des rizières, en passant par les campings sur la plage et les typiques barraques (maisons traditionnelles du delta en paille et boue). Il y en a pour tous les budgets et tous les styles.","DE":"Das Unterkunftsangebot im Delta ist sehr vielfältig: von großen Strandhotels bis zu kleinen Landhäusern inmitten der Reisfelder, Campingplätzen am Strand und den typischen Barracas (traditionelle Deltahäuser aus Stroh und Lehm). Es gibt etwas für jedes Budget und jeden Stil.","NL":"Het accommodatieaanbod in de delta is zeer gevarieerd: van grote strandhotels tot kleine landhuizen midden in de rijstvelden, kamperen op het strand en de typische barracas (traditionele deltahuizen van stro en modder). Er is iets voor elk budget en elke stijl.","PT":"A oferta de alojamento no delta é muito variada: desde grandes hotéis em frente ao mar a pequenas casas rurais no meio dos arrozais, passando por campismo na praia e as típicas barraques (casas tradicionais do delta de palha e barro). Há algo para cada bolsa e estilo."},"sections":[{"title":{"CA":"Les barraques del delta","ES":"Las barracas del delta","EN":"The barracas of the delta","FR":"Les barraques du delta","DE":"Die Barracas des Deltas","NL":"De barracas van de delta","PT":"As barraques do delta"},"body":{"CA":"Les barraques eren les cases tradicionals dels pagesos del delta: construïdes de canya, palla i fang, amb sostre de dos aiguavessos molt pronunciats. Avui algunes han estat restaurades com allotjaments rurals amb molt d'encant, i és la manera més autèntica de viure el delta. Busca-les a les plataformes de turisme rural.","ES":"Las barracas eran las casas tradicionales de los payeses del delta: construidas de caña, paja y barro, con techo de dos aguas muy pronunciado. Hoy algunas han sido restauradas como alojamientos rurales con mucho encanto, y es la manera más auténtica de vivir el delta. Búscalas en las plataformas de turismo rural.","EN":"The barracas were the traditional houses of the delta's farmers: built of reed, straw and mud, with a very steeply pitched roof. Today some have been restored as rural accommodation with great charm, and it is the most authentic way to experience the delta. Look for them on rural tourism platforms.","FR":"Les barraques étaient les maisons traditionnelles des paysans du delta : construites en roseau, paille et boue, avec un toit à deux pentes très prononcées. Aujourd'hui, certaines ont été restaurées en hébergements ruraux de grand charme, et c'est la façon la plus authentique de vivre le delta. Cherchez-les sur les plateformes de tourisme rural.","DE":"Die Barracas waren die traditionellen Häuser der Bauern des Deltas: aus Schilf, Stroh und Lehm gebaut, mit einem sehr steil geneigten Dach. Heute sind einige als Landunterkünfte mit viel Charme restauriert worden, und es ist die authentischste Art, das Delta zu erleben. Suchen Sie sie auf Ländlichen Tourismusplattformen.","NL":"De barracas waren de traditionele huizen van de boeren van de delta: gebouwd van riet, stro en modder, met een zeer steil dak. Vandaag zijn sommige gerestaureerd als landelijk verblijf met veel charme, en het is de meest authentieke manier om de delta te beleven. Zoek ze op platforms voor landelijk toerisme.","PT":"As barraques eram as casas tradicionais dos camponeses do delta: construídas de cana, palha e barro, com telhado de duas águas muito pronunciado. Hoje algumas foram restauradas como alojamentos rurais com muito encanto, e é a forma mais autêntica de viver o delta. Procura-as nas plataformas de turismo rural."}},{"title":{"CA":"On allotjar-se segons el teu pla","ES":"Dónde alojarse según tu plan","EN":"Where to stay according to your plan","FR":"Où séjourner selon votre plan","DE":"Wo übernachten je nach Plan","NL":"Waar verblijven volgens uw plan","PT":"Onde ficar segundo o teu plano"},"body":{"CA":"Si vols platges del nord (Fangar, Marquesa, Riumar): allotja't a Deltebre o la urbanització Riumar. Si vols les llacunes del sud (Encanyissada, Tancada, Trabucador): la Ràpita o Poblenou del Delta. Si vols tot: Deltebre és el punt central del delta i el millor punt de partida.","ES":"Si quieres playas del norte (Fangar, Marquesa, Riumar): alójate en Deltebre o la urbanización Riumar. Si quieres las lagunas del sur (Encanyissada, Tancada, Trabucador): la Ràpita o Poblenou del Delta. Si quieres todo: Deltebre es el punto central del delta y el mejor punto de partida.","EN":"If you want northern beaches (Fangar, Marquesa, Riumar): stay in Deltebre or the Riumar urbanization. If you want the southern lagoons (Encanyissada, Tancada, Trabucador): la Ràpita or Poblenou del Delta. If you want everything: Deltebre is the central point of the delta and the best starting point.","FR":"Si vous voulez les plages du nord (Fangar, Marquesa, Riumar) : logez à Deltebre ou à l'urbanisation Riumar. Si vous voulez les lagunes du sud (Encanyissada, Tancada, Trabucador) : la Ràpita ou Poblenou del Delta. Si vous voulez tout : Deltebre est le point central du delta et le meilleur point de départ.","DE":"Wenn Sie die Nordstrände möchten (Fangar, Marquesa, Riumar): Übernachten Sie in Deltebre oder der Siedlung Riumar. Wenn Sie die südlichen Lagunen möchten (Encanyissada, Tancada, Trabucador): la Ràpita oder Poblenou del Delta. Wenn Sie alles wollen: Deltebre ist der zentrale Punkt des Deltas und der beste Ausgangspunkt.","NL":"Als u de noordelijke stranden wilt (Fangar, Marquesa, Riumar): verblijf in Deltebre of de bebouwing Riumar. Als u de zuidelijke lagunes wilt (Encanyissada, Tancada, Trabucador): la Ràpita of Poblenou del Delta. Als u alles wilt: Deltebre is het centrale punt van de delta en het beste startpunt.","PT":"Se queres praias do norte (Fangar, Marquesa, Riumar): fica em Deltebre ou a urbanização Riumar. Se queres as lagoas do sul (Encanyissada, Tancada, Trabucador): la Ràpita ou Poblenou del Delta. Se queres tudo: Deltebre é o ponto central do delta e o melhor ponto de partida."}}]},{"icon":"bag","name":{"CA":"Què portar","ES":"Qué llevar","EN":"What to bring","FR":"Quoi apporter","DE":"Was mitbringen","NL":"Wat mee te nemen","PT":"O que levar"},"tagline":{"CA":"La llista per no arrepentir-se","ES":"La lista para no arrepentirse","EN":"The list so you don't regret it","FR":"La liste pour ne pas regretter","DE":"Die Liste, damit Sie es nicht bereuen","NL":"De lijst zodat u er geen spijt van krijgt","PT":"A lista para não se arrepender"},"lead":{"CA":"El delta és un entorn molt especial: sol, vent, mosquits, camins de fang i platges salvatges. Portar el que toca fa la diferència entre una visita còmoda i una de difícil.","ES":"El delta es un entorno muy especial: sol, viento, mosquitos, caminos de barro y playas salvajes. Llevar lo que toca marca la diferencia entre una visita cómoda y una difícil.","EN":"The delta is a very special environment: sun, wind, mosquitoes, muddy paths and wild beaches. Bringing the right things makes the difference between a comfortable visit and a difficult one.","FR":"Le delta est un environnement très particulier : soleil, vent, moustiques, chemins boueux et plages sauvages. Emporter ce qu'il faut fait la différence entre une visite confortable et une difficile.","DE":"Das Delta ist eine sehr besondere Umgebung: Sonne, Wind, Mücken, schlammige Wege und wilde Strände. Das Richtige mitzubringen macht den Unterschied zwischen einem angenehmen und einem schwierigen Besuch.","NL":"De delta is een heel bijzondere omgeving: zon, wind, muggen, modderige paden en wilde stranden. Het juiste mee te nemen maakt het verschil tussen een comfortabel en een moeilijk bezoek.","PT":"O delta é um ambiente muito especial: sol, vento, mosquitos, caminhos de lama e praias selvagens. Levar o que é preciso faz a diferença entre uma visita confortável e uma difícil."},"sections":[{"title":{"CA":"Mosquits: la realitat del delta","ES":"Mosquitos: la realidad del delta","EN":"Mosquitoes: the reality of the delta","FR":"Moustiques : la réalité du delta","DE":"Mücken: die Realität des Deltas","NL":"Muggen: de realiteit van de delta","PT":"Mosquitos: a realidade do delta"},"body":{"CA":"El delta és un aiguamoll i els mosquits en formen part. A l'estiu i principi de tardor, especialment a les zones de llacunes i arrossars, poden ser molt molestos a la tarda i vespre. Un bon repel·lent (DEET o IR3535) és imprescindible. Les hores de més mosqueig solen ser entre les 19 i les 22 h.","ES":"El delta es un humedal y los mosquitos forman parte de él. En verano y principios de otoño, especialmente en las zonas de lagunas y arrozales, pueden ser muy molestos por la tarde y noche. Un buen repelente (DEET o IR3535) es imprescindible. Las horas de más picadura suelen ser entre las 19 y las 22 h.","EN":"The delta is a wetland and mosquitoes are part of it. In summer and early autumn, especially near the lagoons and rice fields, they can be very bothersome in the afternoon and evening. A good repellent (DEET or IR3535) is essential. The worst hours are usually between 7pm and 10pm.","FR":"Le delta est une zone humide et les moustiques en font partie. En été et début d'automne, surtout près des lagunes et des rizières, ils peuvent être très gênants l'après-midi et le soir. Un bon répulsif (DEET ou IR3535) est indispensable. Les heures les plus piquantes sont généralement entre 19h et 22h.","DE":"Das Delta ist ein Feuchtgebiet und Mücken gehören dazu. Im Sommer und frühen Herbst, besonders in der Nähe von Lagunen und Reisfeldern, können sie nachmittags und abends sehr lästig sein. Ein gutes Abwehrmittel (DEET oder IR3535) ist unverzichtbar. Die schlimmsten Stunden sind normalerweise zwischen 19 und 22 Uhr.","NL":"De delta is een wetland en muggen horen erbij. In zomer en vroege herfst, vooral bij de lagunes en rijstvelden, kunnen ze 's middags en 's avonds erg hinderlijk zijn. Een goed middel (DEET of IR3535) is onmisbaar. De ergste uren zijn meestal tussen 19 en 22 uur.","PT":"O delta é uma zona húmida e os mosquitos fazem parte dele. No verão e início do outono, especialmente nas zonas de lagoas e arrozais, podem ser muito incomodativos à tarde e à noite. Um bom repelente (DEET ou IR3535) é imprescindível. As horas de mais picada costumam ser entre as 19 e as 22 h."}},{"title":{"CA":"El vent: l'altre factor","ES":"El viento: el otro factor","EN":"The wind: the other factor","FR":"Le vent : l'autre facteur","DE":"Der Wind: der andere Faktor","NL":"De wind: de andere factor","PT":"O vento: o outro fator"},"body":{"CA":"La tramuntana (vent del nord-est) és un dels elements més característics del delta. A l'hivern i primavera pot bufar molt fort (40-60 km/h) i fer molt de fred malgrat que el termòmetre digui 15°C. A l'estiu, el vent de llevant refresca les nits. Porta sempre una jaqueta lleugera, fins i tot a l'agost.","ES":"La tramontana (viento del noreste) es uno de los elementos más característicos del delta. En invierno y primavera puede soplar muy fuerte (40-60 km/h) y hacer mucho frío a pesar de que el termómetro diga 15°C. En verano, el viento de levante refresca las noches. Lleva siempre una chaqueta ligera, incluso en agosto.","EN":"The tramontane (north-east wind) is one of the delta's most characteristic elements. In winter and spring it can blow very strongly (40-60 km/h) and feel very cold even if the thermometer reads 15°C. In summer, the easterly wind cools the nights. Always carry a light jacket, even in August.","FR":"La tramontane (vent du nord-est) est l'un des éléments les plus caractéristiques du delta. En hiver et au printemps, elle peut souffler très fort (40-60 km/h) et faire très froid malgré ce qu'indique le thermomètre. En été, le vent d'est rafraîchit les nuits. Apportez toujours une veste légère, même en août.","DE":"Die Tramontana (Nordostwind) ist eines der charakteristischsten Elemente des Deltas. Im Winter und Frühling kann sie sehr stark wehen (40-60 km/h) und trotz des Thermometers sehr kalt sein. Im Sommer kühlt der Ostwind die Nächte ab. Immer eine leichte Jacke mitbringen, auch im August.","NL":"De tramontaan (noordoosten wind) is een van de meest karakteristieke elementen van de delta. In winter en lente kan het heel sterk waaien (40-60 km/h) en heel koud aanvoelen ondanks wat de thermometer aangeeft. In de zomer koelt de oostenwind de nachten af. Altijd een lichte jas meenemen, ook in augustus.","PT":"A tramontana (vento nordeste) é um dos elementos mais característicos do delta. No inverno e primavera pode soprar muito forte (40-60 km/h) e fazer muito frio apesar do que diz o termómetro. No verão, o vento de levante arrefece as noites. Leva sempre um casaco leve, mesmo em agosto."}}]},{"icon":"map","name":{"CA":"Moure's per dins","ES":"Moverse por dentro","EN":"Getting around","FR":"Se déplacer dans le delta","DE":"Sich im Delta bewegen","NL":"Rondkomen in de delta","PT":"Mover-se pelo interior"},"tagline":{"CA":"Cotxe, bici i poc més","ES":"Coche, bici y poco más","EN":"Car, bike and little else","FR":"Voiture, vélo et peu d'autre chose","DE":"Auto, Fahrrad und wenig mehr","NL":"Auto, fiets en weinig meer","PT":"Carro, bicicleta e pouco mais"},"lead":{"CA":"El delta no té transport interior organitzat. No hi ha autobusos entre platges, llacunes o espais naturals. Però és completament pla i té una xarxa densa de camins: la bici és la millor manera de moure's amb calma i a la mesura de les persones.","ES":"El delta no tiene transporte interior organizado. No hay autobuses entre playas, lagunas o espacios naturales. Pero es completamente llano y tiene una densa red de caminos: la bici es la mejor manera de moverse con calma y a la medida de las personas.","EN":"The delta has no organised internal transport. There are no buses between beaches, lagoons or natural spaces. But it is completely flat and has a dense network of paths: the bike is the best way to move calmly and at a human pace.","FR":"Le delta n'a pas de transport intérieur organisé. Il n'y a pas de bus entre les plages, les lagunes ou les espaces naturels. Mais il est complètement plat et dispose d'un réseau dense de chemins : le vélo est la meilleure façon de se déplacer tranquillement et à l'échelle humaine.","DE":"Das Delta hat keinen organisierten Innenverkehr. Es gibt keine Busse zwischen Stränden, Lagunen oder Naturräumen. Aber es ist komplett flach und hat ein dichtes Wegenetz: Das Fahrrad ist die beste Art, ruhig und menschlich zu bewegen.","NL":"De delta heeft geen georganiseerd intern vervoer. Er zijn geen bussen tussen stranden, lagunes of natuurgebieden. Maar het is volledig vlak en heeft een dicht netwerk van paden: de fiets is de beste manier om rustig en op menselijke maat te bewegen.","PT":"O delta não tem transporte interior organizado. Não há autocarros entre praias, lagoas ou espaços naturais. Mas é completamente plano e tem uma rede densa de caminhos: a bicicleta é a melhor forma de se mover com calma e à escala humana."},"sections":[{"title":{"CA":"El pont Lo Passador","ES":"El puente Lo Passador","EN":"The Lo Passador bridge","FR":"Le pont Lo Passador","DE":"Die Brücke Lo Passador","NL":"De Lo Passador brug","PT":"A ponte Lo Passador"},"body":{"CA":"L'únic pont que connecta l'hemidelta nord i el sud és el de Lo Passador, entre Sant Jaume d'Enveja i Deltebre. Si planifiques visitar els dos costats del riu, recorda que has de creuar per aquí o per Amposta. En temporada alta, el pont pot tenir petites cues a l'hora punta.","ES":"El único puente que conecta el hemidelta norte y el sur es el de Lo Passador, entre Sant Jaume d'Enveja y Deltebre. Si planificas visitar los dos lados del río, recuerda que debes cruzar por aquí o por Amposta. En temporada alta, el puente puede tener pequeñas colas en hora punta.","EN":"The only bridge connecting the north and south hemideltas is Lo Passador, between Sant Jaume d'Enveja and Deltebre. If you plan to visit both sides of the river, remember you must cross here or via Amposta. In high season the bridge can have small queues at peak times.","FR":"Le seul pont reliant l'hémidelta nord et l'hémidelta sud est Lo Passador, entre Sant Jaume d'Enveja et Deltebre. Si vous prévoyez de visiter les deux rives du fleuve, rappelez-vous que vous devez traverser ici ou par Amposta. En haute saison, le pont peut avoir de petites files aux heures de pointe.","DE":"Die einzige Brücke, die Nord- und Süd-Hemidelta verbindet, ist Lo Passador, zwischen Sant Jaume d'Enveja und Deltebre. Wenn Sie planen, beide Seiten des Flusses zu besuchen, denken Sie daran, hier oder über Amposta zu überqueren. In der Hochsaison kann die Brücke zu Stoßzeiten kleine Warteschlangen haben.","NL":"De enige brug die het noord- en zuidhemidelta verbindt is Lo Passador, tussen Sant Jaume d'Enveja en Deltebre. Als u van plan bent beide zijden van de rivier te bezoeken, vergeet dan niet dat u hier of via Amposta moet oversteken. In het hoogseizoen kan de brug op piekmomenten kleine files hebben.","PT":"A única ponte que liga o hemidelta norte e sul é a de Lo Passador, entre Sant Jaume d'Enveja e Deltebre. Se planeias visitar os dois lados do rio, lembra que tens de atravessar aqui ou por Amposta. Na época alta, a ponte pode ter pequenas filas nas horas de ponta."}}]},{"icon":"phone","name":{"CA":"Contactes útils","ES":"Contactos útiles","EN":"Useful contacts","FR":"Contacts utiles","DE":"Nützliche Kontakte","NL":"Handige contacten","PT":"Contactos úteis"},"tagline":{"CA":"Números i adreces que convé tenir","ES":"Números y direcciones que conviene tener","EN":"Numbers and addresses worth having","FR":"Numéros et adresses à avoir","DE":"Nummern und Adressen, die man haben sollte","NL":"Nummers en adressen om te hebben","PT":"Números e moradas que convém ter"},"lead":{"CA":"Emergències, centres d'informació del Parc, oficines de turisme, hospitals i serveis clau per a la visita al delta de l'Ebre.","ES":"Emergencias, centros de información del Parque, oficinas de turismo, hospitales y servicios clave para la visita al delta del Ebro.","EN":"Emergencies, Park information centres, tourist offices, hospitals and key services for visiting the Ebro Delta.","FR":"Urgences, centres d'information du Parc, offices de tourisme, hôpitaux et services clés pour la visite du delta de l'Èbre.","DE":"Notfälle, Park-Informationszentren, Touristinformationen, Krankenhäuser und Schlüsseldienste für den Besuch des Ebro-Deltas.","NL":"Noodgevallen, Park-informatiecentra, toeristenbureau, ziekenhuizen en sleuteldiensten voor het bezoeken van de Ebrodelta.","PT":"Emergências, centros de informação do Parque, postos de turismo, hospitais e serviços chave para a visita ao delta do Ebro."},"sections":[{"title":{"CA":"Oficines de turisme per zona","ES":"Oficinas de turismo por zona","EN":"Tourist offices by area","FR":"Offices de tourisme par zone","DE":"Touristinformationen nach Zone","NL":"Toeristenbureau per zone","PT":"Postos de turismo por zona"},"body":{"CA":"· Deltebre: Av. del Canal s/n · Tel. 977 489 679 · Amposta: Plaça de l'Ajuntament · Tel. 977 703 453 · Sant Carles de la Ràpita: Plaça Carles III · Tel. 977 744 624 · L'Ampolla: Plaça del Castell s/n · Tel. 977 460 396 · Tortosa: Pl. de l'Olivera 14 · Tel. 977 449 648","ES":"· Deltebre: Av. del Canal s/n · Tel. 977 489 679 · Amposta: Plaça de l'Ajuntament · Tel. 977 703 453 · Sant Carles de la Ràpita: Plaça Carles III · Tel. 977 744 624 · L'Ampolla: Plaça del Castell s/n · Tel. 977 460 396 · Tortosa: Pl. de l'Olivera 14 · Tel. 977 449 648","EN":"· Deltebre: Av. del Canal s/n · Tel. 977 489 679 · Amposta: Plaça de l'Ajuntament · Tel. 977 703 453 · Sant Carles de la Ràpita: Plaça Carles III · Tel. 977 744 624 · L'Ampolla: Plaça del Castell s/n · Tel. 977 460 396 · Tortosa: Pl. de l'Olivera 14 · Tel. 977 449 648","FR":"· Deltebre : Av. del Canal s/n · Tél. 977 489 679 · Amposta : Plaça de l'Ajuntament · Tél. 977 703 453 · Sant Carles de la Ràpita : Plaça Carles III · Tél. 977 744 624 · L'Ampolla : Plaça del Castell s/n · Tél. 977 460 396 · Tortosa : Pl. de l'Olivera 14 · Tél. 977 449 648","DE":"· Deltebre: Av. del Canal s/n · Tel. 977 489 679 · Amposta: Plaça de l'Ajuntament · Tel. 977 703 453 · Sant Carles de la Ràpita: Plaça Carles III · Tel. 977 744 624 · L'Ampolla: Plaça del Castell s/n · Tel. 977 460 396 · Tortosa: Pl. de l'Olivera 14 · Tel. 977 449 648","NL":"· Deltebre: Av. del Canal s/n · Tel. 977 489 679 · Amposta: Plaça de l'Ajuntament · Tel. 977 703 453 · Sant Carles de la Ràpita: Plaça Carles III · Tel. 977 744 624 · L'Ampolla: Plaça del Castell s/n · Tel. 977 460 396 · Tortosa: Pl. de l'Olivera 14 · Tel. 977 449 648","PT":"· Deltebre: Av. del Canal s/n · Tel. 977 489 679 · Amposta: Plaça de l'Ajuntament · Tel. 977 703 453 · Sant Carles de la Ràpita: Plaça Carles III · Tel. 977 744 624 · L'Ampolla: Plaça del Castell s/n · Tel. 977 460 396 · Tortosa: Pl. de l'Olivera 14 · Tel. 977 449 648"}},{"title":{"CA":"Serveis en temporada alta","ES":"Servicios en temporada alta","EN":"High season services","FR":"Services en haute saison","DE":"Hochsaisondienste","NL":"Hoogseizoensdiensten","PT":"Serviços em época alta"},"body":{"CA":"A l'estiu (juliol-agost) s'activen molts serveis addicionals: Creu Roja a les platges amb Bandera Blava (Riumar, les Delícies, Garbí, Cap Roig, Marjal, Maricel), socorristes en altres platges, i un punt d'informació turística extra a la bassa de la Marquesa. Els centres del Parc Natural amplien horaris.","ES":"En verano (julio-agosto) se activan muchos servicios adicionales: Cruz Roja en las playas con Bandera Azul (Riumar, les Delícies, Garbí, Cap Roig, Marjal, Maricel), socorristas en otras playas, y un punto de información turística extra en la playa de la Marquesa. Los centros del Parque Natural amplían horarios.","EN":"In summer (July-August) many additional services are activated: Red Cross on Blue Flag beaches (Riumar, les Delícies, Garbí, Cap Roig, Marjal, Maricel), lifeguards on other beaches, and an extra tourist information point at the Marquesa beach. The Nature Park centres extend their opening hours.","FR":"En été (juillet-août), de nombreux services supplémentaires sont activés : Croix-Rouge sur les plages Pavillon Bleu (Riumar, les Delícies, Garbí, Cap Roig, Marjal, Maricel), sauveteurs sur d'autres plages, et un point d'information touristique supplémentaire à la plage de la Marquesa. Les centres du Parc naturel prolongent leurs horaires.","DE":"Im Sommer (Juli-August) werden viele zusätzliche Dienste aktiviert: Rotes Kreuz an Blaue-Flagge-Stränden (Riumar, les Delícies, Garbí, Cap Roig, Marjal, Maricel), Rettungsschwimmer an anderen Stränden, und ein zusätzlicher Touristinformationspunkt am Strand Marquesa. Die Naturparkzentren verlängern ihre Öffnungszeiten.","NL":"In de zomer (juli-augustus) worden veel aanvullende diensten geactiveerd: Rode Kruis op Blauwe Vlag-stranden (Riumar, les Delícies, Garbí, Cap Roig, Marjal, Maricel), redders op andere stranden, en een extra toeristeninformatiepunt op het Marquesa-strand. De Natuurparkcentra verlengen hun openingstijden.","PT":"No verão (julho-agosto) ativam-se muitos serviços adicionais: Cruz Vermelha nas praias com Bandeira Azul (Riumar, les Delícies, Garbí, Cap Roig, Marjal, Maricel), nadadores-salvadores noutras praias, e um ponto de informação turística extra na praia da Marquesa. Os centros do Parque Natural alargam os horários."}}]},{"icon":"tel","name":{"CA":"Consells pràctics","ES":"Consejos prácticos","EN":"Practical tips","FR":"Conseils pratiques","DE":"Praktische Tipps","NL":"Praktische tips","PT":"Dicas práticas"},"tagline":{"CA":"WiFi, aigua, divisa, seguretat i més","ES":"WiFi, agua, moneda, seguridad y más","EN":"WiFi, water, money, safety and more","FR":"WiFi, eau, monnaie, sécurité et plus","DE":"WLAN, Wasser, Währung, Sicherheit und mehr","NL":"WiFi, water, valuta, veiligheid en meer","PT":"WiFi, água, moeda, segurança e mais"},"lead":{"CA":"Tot el que necessites saber per no tenir sorpreses al delta: connectivitat, pagaments, sanitat i seguretat al mar.","ES":"Todo lo que necesitas saber para no tener sorpresas en el delta: conectividad, pagos, sanidad y seguridad en el mar.","EN":"Everything you need to know to avoid surprises in the delta: connectivity, payments, healthcare and sea safety.","FR":"Tout ce que vous devez savoir pour éviter les surprises dans le delta: connectivité, paiements, santé et sécurité maritime.","DE":"Alles, was Sie wissen müssen, um Überraschungen im Delta zu vermeiden: Konnektivität, Zahlungen, Gesundheit und Meeressicherheit.","NL":"Alles wat u moet weten om verrassingen in de delta te voorkomen: connectiviteit, betalingen, gezondheidszorg en maritieme veiligheid.","PT":"Tudo o que precisa saber para não ter surpresas no delta: conectividade, pagamentos, saúde e segurança marítima."},"sections":[{"title":{"CA":"WiFi i connectivitat","ES":"WiFi y conectividad","EN":"WiFi and connectivity","FR":"WiFi et connectivité","DE":"WLAN und Konnektivität","NL":"WiFi en connectiviteit","PT":"WiFi e conectividade"},"body":{"CA":"La cobertura mòbil (4G/5G) és bona als pobles principals (la Ràpita, Amposta, Deltebre, l'Ampolla) però irregular o nul·la dins del parc natural i als camins secundaris. Si planifiques excursions, descarrega els mapes offline (maps.me o Google Maps offline). La majoria de bars i restaurants dels pobles ofereixen WiFi gratuït.","ES":"La cobertura móvil (4G/5G) es buena en los pueblos principales pero irregular o nula dentro del parque natural y en los caminos secundarios. Si planificas excursiones, descarga los mapas offline. La mayoría de bares y restaurantes de los pueblos ofrecen WiFi gratuito.","EN":"Mobile coverage (4G/5G) is good in main villages but patchy or absent inside the natural park and on secondary tracks. If planning excursions, download offline maps (maps.me or Google Maps offline). Most village bars and restaurants offer free WiFi.","FR":"La couverture mobile (4G/5G) est bonne dans les villages principaux mais irrégulière ou nulle à l'intérieur du parc naturel. Téléchargez les cartes hors ligne avant d'aller en excursion.","DE":"Mobilfunkempfang (4G/5G) ist in Hauptdörfern gut, aber unzuverlässig oder nicht vorhanden im Naturpark. Laden Sie Offline-Karten herunter, bevor Sie auf Ausflüge gehen.","NL":"Mobiele dekking (4G/5G) is goed in de hoofddorpen maar onregelmatig of afwezig in het natuurpark. Download offline kaarten vóór uitstapjes.","PT":"A cobertura móvel (4G/5G) é boa nas aldeias principais mas irregular ou nula dentro do parque natural. Descarregue mapas offline antes de fazer excursões."}},{"title":{"CA":"Salut i assistència sanitària","ES":"Salud y asistencia sanitaria","EN":"Health and medical assistance","FR":"Santé et assistance médicale","DE":"Gesundheit und ärztliche Versorgung","NL":"Gezondheid en medische bijstand","PT":"Saúde e assistência médica"},"body":{"CA":"L'Hospital de Tortosa Verge de la Cinta (☎ 977 519 100) és el més gran de la comarca, a 30 min del delta. Hi ha CAP (centres d'atenció primària) a Amposta, la Ràpita, Deltebre i l'Ampolla. A l'estiu, guarda metge disponible. Farmàcies als pobles principals. Per al mar: la Creu Roja Espanyola té socorristes a les platges principals a l'estiu. En cas d'accident marítim, truqueu al 112.","ES":"El Hospital de Tortosa Virgen de la Cinta (☏ 977 519 100) es el mayor de la comarca, a 30 min del delta. Hay CAP en Amposta, La Ràpita, Deltebre y L'Ampolla. En verano, médico de guardia disponible. Farmacias en los pueblos principales. Para el mar: la Cruz Roja tiene socorristas en las playas principales en verano.","EN":"Tortosa Virgen de la Cinta Hospital (☏ 977 519 100) is the largest in the area, 30 min from the delta. There are health centres (CAP) in Amposta, La Ràpita, Deltebre and L'Ampolla. In summer, on-duty doctor available. Pharmacies in main villages. For the sea: Red Cross lifeguards are on main beaches in summer. For maritime accidents, call 112.","FR":"L'Hôpital de Tortosa Virge de la Cinta (☏ 977 519 100) est le plus grand de la région, à 30 min du delta. Il y a des centres de santé (CAP) à Amposta, La Ràpita, Deltebre et L'Ampolla. En été, médecin de garde disponible. Croix Rouge Espagnole: secouristes sur les plages principales en été.","DE":"Das Krankenhaus Tortosa Virgen de la Cinta (☏ 977 519 100) ist das größte in der Region, 30 Min. vom Delta. Es gibt Gesundheitszentren (CAP) in Amposta, La Ràpita, Deltebre und L'Ampolla. Im Sommer Bereitschaftsarzt. Spanisches Rotes Kreuz: Rettungsschwimmer an Hauptstränden im Sommer.","NL":"Ziekenhuis Tortosa Virgen de la Cinta (☏ 977 519 100) is het grootste in de regio, 30 min van de delta. Er zijn gezondheidscentra (CAP) in Amposta, La Ràpita, Deltebre en L'Ampolla. In de zomer arts beschikbaar. Rode Kruis: reddingszwemmers op hoofdstranden in de zomer.","PT":"Hospital de Tortosa Virgen de la Cinta (☏ 977 519 100) é o maior da região, a 30 min do delta. Há centros de saúde (CAP) em Amposta, La Ràpita, Deltebre e L'Ampolla. No verão médico de serviço. Cruz Vermelha: nadadores-salvadores nas praias principais no verão."}}]}];

export const D_NAT = [{"icon":"park","name":{"CA":"Parc Natural del Delta de l'Ebre","ES":"Parc Natural del Delta de l'Ebre","EN":"Ebro Delta Nature Park","FR":"Parc naturel du delta de l'Èbre","DE":"Naturpark des Ebro-Deltas","NL":"Natuurpark Delta de l'Ebre","PT":"Parque Natural do Delta do Ebro"},"tagline":{"CA":"La zona humida protegida més gran de Catalunya","ES":"La zona húmeda protegida más grande de Cataluña","EN":"The largest protected wetland in Catalonia","FR":"La plus grande zone humide protégée de Catalogne","DE":"Das größte Schutzfeuchtgebiet Kataloniens","NL":"Het grootste beschermde wetland van Catalonië","PT":"A maior zona húmida protegida da Catalunha"},"lead":{"CA":"7.736 hectàrees al voltant de la desembocadura del riu Ebre. Un dels aiguamolls més importants de la Mediterrània occidental, Reserva de la Biosfera per la UNESCO i Xarxa Natura 2000. Un univers horitzontal on conviuen arrossars, llacunes, dunes, bosc de ribera, illes fluvials i mar.","ES":"7.736 hectáreas en torno a la desembocadura del río Ebro. Uno de los humedales más importantes del Mediterráneo occidental, Reserva de la Biosfera por la UNESCO y Red Natura 2000. Un universo horizontal donde conviven arrozales, lagunas, dunas, bosque de ribera, islas fluviales y mar.","EN":"7,736 hectares around the mouth of the Ebro river. One of the most important wetlands in the western Mediterranean, UNESCO Biosphere Reserve and Natura 2000 network. A horizontal universe where rice fields, lagoons, dunes, riverside forest, fluvial islands and sea coexist.","FR":"7 736 hectares autour de l'embouchure du fleuve Èbre. L'une des zones humides les plus importantes de la Méditerranée occidentale, Réserve de biosphère de l'UNESCO et réseau Natura 2000. Un univers horizontal où cohabitent rizières, lagunes, dunes, forêt riveraine, îles fluviales et mer.","DE":"7.736 Hektar rund um die Mündung des Ebro. Eines der bedeutendsten Feuchtgebiete des westlichen Mittelmeers, UNESCO-Biosphärenreservat und Natura-2000-Netz. Ein horizontales Universum, in dem Reisfelder, Lagunen, Dünen, Auenwald, Flussinseln und Meer koexistieren.","NL":"7.736 hectare rondom de monding van de Ebro. Een van de belangrijkste wetlands van de westelijke Middellandse Zee, UNESCO-Biosfeerreservaat en Natura 2000-netwerk. Een horizontaal universum waar rijstvelden, lagunes, duinen, oeverbossen, riviereilanden en zee samenleven.","PT":"7.736 hectares em torno da foz do rio Ebro. Uma das zonas húmidas mais importantes do Mediterrâneo ocidental, Reserva da Biosfera pela UNESCO e Rede Natura 2000. Um universo horizontal onde convivem arrozais, lagoas, dunas, bosque ripário, ilhas fluviais e mar."},"lat":40.68,"lng":0.73,"tip":{"CA":"El millor moment per entendre el delta és a la tardor, quan els arrossars estan daurats i inundats: es veu perfectament la doble vida del paisatge, entre agricultura i refugi natural.","ES":"El mejor momento para entender el delta es en otoño, cuando los arrozales están dorados e inundados: se ve perfectamente la doble vida del paisaje, entre agricultura y refugio natural.","EN":"The best moment to understand the delta is in autumn, when the rice fields are golden and flooded: you can perfectly see the double life of the landscape, between agriculture and natural refuge.","FR":"Le meilleur moment pour comprendre le delta est en automne, quand les rizières sont dorées et inondées : on voit parfaitement la double vie du paysage, entre agriculture et refuge naturel.","DE":"Der beste Moment, um das Delta zu verstehen, ist im Herbst, wenn die Reisfelder golden und überflutet sind: Man sieht perfekt das Doppelleben der Landschaft zwischen Landwirtschaft und Naturschutzgebiet.","NL":"Het beste moment om de delta te begrijpen is in de herfst, wanneer de rijstvelden goud zijn en overstroomd: je ziet het dubbele leven van het landschap perfect, tussen landbouw en natuurvluchtplek.","PT":"O melhor momento para compreender o delta é no outono, quando os arrozais estão dourados e inundados: vê-se perfeitamente a dupla vida da paisagem, entre agricultura e refúgio natural."}},{"icon":"lagoon","name":{"CA":"L'Encanyissada","ES":"L'Encanyissada","EN":"L'Encanyissada","FR":"L'Encanyissada","DE":"L'Encanyissada","NL":"L'Encanyissada","PT":"L'Encanyissada"},"tagline":{"CA":"La llacuna més gran del delta","ES":"La laguna más grande del delta","EN":"The largest lagoon in the delta","FR":"La plus grande lagune du delta","DE":"Die größte Lagune des Deltas","NL":"De grootste lagune van de delta","PT":"A maior lagoa do delta"},"lead":{"CA":"L'Encanyissada és la llacuna més gran del delta de l'Ebre, dividida en dues cubetes que es comuniquen amb la badia dels Alfacs. Els seus canyissars acullen les majors colònies de nidificació d'ardèids de tot el delta. Cinc miradors i un carril bici la voregen.","ES":"L'Encanyissada es la laguna más grande del delta del Ebro, dividida en dos cubetas que se comunican con la bahía de los Alfacs. Sus cañaverales acogen las mayores colonias de nidificación de ardeidos de todo el delta. Cinco miradores y un carril bici la bordean.","EN":"L'Encanyissada is the largest lagoon in the Ebro Delta, divided into two basins that communicate with the Alfacs bay. Its reedbeds host the largest breeding colonies of herons in the entire delta. Five viewpoints and a cycle path run along it.","FR":"L'Encanyissada est la plus grande lagune du delta de l'Èbre, divisée en deux bassins qui communiquent avec la baie des Alfacs. Ses roselières accueillent les plus grandes colonies de nidification d'ardéidés de tout le delta. Cinq belvédères et une piste cyclable la longent.","DE":"L'Encanyissada ist die größte Lagune im Ebro-Delta, geteilt in zwei Becken, die mit der Alfacs-Bucht kommunizieren. Ihre Schilfrohre beherbergen die größten Brutkolonien von Reihern im gesamten Delta. Fünf Aussichtspunkte und ein Radweg verlaufen entlang.","NL":"L'Encanyissada is de grootste lagune in de Ebrodelta, verdeeld in twee bekkens die communiceren met de Alfacs-baai. Zijn rietlanden herbergen de grootste broedkolonies van reigers in de gehele delta. Vijf uitkijkpunten en een fietspad lopen erlangs.","PT":"A Encanyissada é a maior lagoa do delta do Ebro, dividida em duas cubetas que comunicam com a baía dos Alfacs. Os seus caniçais albergam as maiores colónias de nidificação de ardeídeos de todo o delta. Cinco miradouros e uma ciclovia bordejam-na."},"lat":40.65,"lng":0.675,"tip":{"CA":"La volta completa en bicicleta a l'Encanyissada (uns 15 km) és un dels recorreguts més recomanats del delta: lent, pla i ple d'aus en qualsevol estació.","ES":"La vuelta completa en bicicleta a l'Encanyissada (unos 15 km) es uno de los recorridos más recomendados del delta: lento, llano y lleno de aves en cualquier estación.","EN":"The full cycle loop around l'Encanyissada (about 15 km) is one of the delta's most recommended routes: slow, flat and full of birds in any season.","FR":"Le tour complet à vélo de l'Encanyissada (environ 15 km) est l'un des parcours les plus recommandés du delta : lent, plat et plein d'oiseaux en toute saison.","DE":"Die vollständige Fahrradtour um die Encanyissada (etwa 15 km) ist eine der am meisten empfohlenen Routen des Deltas: langsam, flach und voller Vögel in jeder Jahreszeit.","NL":"De volledige fietstocht rondom l'Encanyissada (ongeveer 15 km) is een van de meest aanbevolen routes van de delta: langzaam, vlak en vol vogels in elk seizoen.","PT":"A volta completa de bicicleta à Encanyissada (cerca de 15 km) é um dos percursos mais recomendados do delta: lento, plano e cheio de aves em qualquer estação."}},{"icon":"lagoon","name":{"CA":"La Tancada","ES":"La Tancada","EN":"La Tancada","FR":"La Tancada","DE":"La Tancada","NL":"La Tancada","PT":"La Tancada"},"tagline":{"CA":"El millor lloc per veure flamencos","ES":"El mejor lugar para ver flamencos","EN":"The best place to see flamingos","FR":"Le meilleur endroit pour voir les flamants roses","DE":"Der beste Ort um Flamingos zu sehen","NL":"De beste plek om flamingo's te zien","PT":"O melhor lugar para ver flamingos"},"lead":{"CA":"La Tancada és la segona llacuna en importància del delta, amb la salinitat més elevada de totes. No té comunicació directa natural amb el mar. Centenars de flamencos rosats hi mengen i descansen gairebé tot l'any. Carril bici i pontets que surten directament sobre l'aigua.","ES":"La Tancada es la segunda laguna en importancia del delta, con la salinidad más elevada de todas. No tiene comunicación directa natural con el mar. Centenares de flamencos rosados comen y descansan en ella casi todo el año. Carril bici y puentes que salen directamente sobre el agua.","EN":"La Tancada is the second most important lagoon in the delta, with the highest salinity of all. It has no direct natural connection to the sea. Hundreds of pink flamingos feed and rest there almost all year round. A cycle path and small bridges lead directly over the water.","FR":"La Tancada est la deuxième lagune en importance du delta, avec la salinité la plus élevée de toutes. Elle n'a pas de communication naturelle directe avec la mer. Des centaines de flamants roses s'y nourrissent et se reposent presque toute l'année. Une piste cyclable et des petits ponts mènent directement sur l'eau.","DE":"La Tancada ist die zweitwichtigste Lagune im Delta mit dem höchsten Salzgehalt von allen. Sie hat keine direkte natürliche Verbindung zum Meer. Hunderte rosa Flamingos fressen und ruhen dort fast das ganze Jahr über. Ein Radweg und kleine Brücken führen direkt über das Wasser.","NL":"La Tancada is de op één na belangrijkste lagune in de delta, met het hoogste zoutgehalte van alle. Het heeft geen directe natuurlijke verbinding met de zee. Honderden roze flamingo's eten en rusten er bijna het hele jaar. Een fietspad en kleine bruggetjes leiden direct over het water.","PT":"A Tancada é a segunda lagoa em importância do delta, com a salinidade mais elevada de todas. Não tem comunicação direta natural com o mar. Centenas de flamingos rosados comem e descansam nela quase todo o ano. Ciclovia e pontes que saem diretamente sobre a água."},"lat":40.647,"lng":0.672,"tip":{"CA":"Arriba a primera hora del matí o al capvespre: la llum és millor i els flamencos estan més actius. Porta prismàtics: t'apropen molt.","ES":"Llega a primera hora de la mañana o al atardecer: la luz es mejor y los flamencos están más activos. Lleva prismáticos: te acercan mucho.","EN":"Arrive in the early morning or at sunset: the light is better and the flamingos are more active. Bring binoculars: they bring you much closer.","FR":"Arrivez tôt le matin ou au coucher du soleil : la lumière est meilleure et les flamants sont plus actifs. Apportez des jumelles : elles vous rapprochent beaucoup.","DE":"Früh morgens oder bei Sonnenuntergang ankommen: Das Licht ist besser und die Flamingos sind aktiver. Fernglas mitbringen: Es bringt Sie viel näher.","NL":"Kom vroeg in de ochtend of bij zonsondergang: het licht is beter en de flamingo's zijn actiever. Verrekijker meenemen: ze brengen je veel dichterbij.","PT":"Chega de manhã cedo ou ao pôr do sol: a luz é melhor e os flamingos estão mais ativos. Leva binóculos: aproximam-te muito."}},{"icon":"lagoon","name":{"CA":"Bassa de les Olles","ES":"Bassa de les Olles","EN":"Bassa de les Olles","FR":"Bassa de les Olles","DE":"Bassa de les Olles","NL":"Bassa de les Olles","PT":"Bassa de les Olles"},"tagline":{"CA":"La llacuna més petita, a tocar de l'Ampolla","ES":"La laguna más pequeña, junto a l'Ampolla","EN":"The smallest lagoon, right by l'Ampolla","FR":"La plus petite lagune, près de l'Ampolla","DE":"Die kleinste Lagune, gleich neben l'Ampolla","NL":"De kleinste lagune, vlak bij l'Ampolla","PT":"A menor lagoa, perto de l'Ampolla"},"lead":{"CA":"La Bassa de les Olles, amb només 54 hectàrees, és la llacuna més petita del Parc Natural. Comunicada amb la badia del Fangar, és el resultat d'una de les desembocadures més antigues de l'Ebre. Perfecta per visitar des de l'Ampolla, ofereix avistament de flamencos, agrons i martins pescadors.","ES":"La Bassa de les Olles, con solo 54 hectáreas, es la laguna más pequeña del Parque Natural. Comunicada con la bahía del Fangar, es el resultado de una de las desembocaduras más antiguas del Ebro. Perfecta para visitar desde l'Ampolla, ofrece avistamiento de flamencos, garzas y martines pescadores.","EN":"La Bassa de les Olles, at just 54 hectares, is the smallest lagoon in the Nature Park. Connected to the Fangar bay, it is the result of one of the Ebro's oldest mouths. Perfect to visit from l'Ampolla, it offers sightings of flamingos, herons and kingfishers.","FR":"La Bassa de les Olles, avec seulement 54 hectares, est la plus petite lagune du Parc naturel. Reliée à la baie du Fangar, c'est le résultat de l'une des plus anciennes embouchures de l'Èbre. Parfaite à visiter depuis l'Ampolla, elle offre l'observation de flamants roses, hérons et martins-pêcheurs.","DE":"La Bassa de les Olles ist mit nur 54 Hektar die kleinste Lagune im Naturpark. Sie ist mit der Fangar-Bucht verbunden und das Ergebnis einer der ältesten Mündungen des Ebro. Sie kann von l'Ampolla aus besucht werden und bietet Sichtungen von Flamingos, Reihern und Eisvögeln.","NL":"La Bassa de les Olles is met slechts 54 hectare de kleinste lagune van het Natuurpark. Verbonden met de baai van Fangar, is het het resultaat van een van de oudste mondingen van de Ebro. Perfect te bezoeken vanuit l'Ampolla, biedt het sightings van flamingo's, reigers en ijsvogels.","PT":"A Bassa de les Olles, com apenas 54 hectares, é a menor lagoa do Parque Natural. Comunicada com a baía do Fangar, é o resultado de uma das desembocaduras mais antigas do Ebro. Perfeita para visitar a partir de l'Ampolla, oferece avistamentos de flamingos, garças e martins-pescadores."},"lat":40.795,"lng":0.72,"tip":{"CA":"Combina la visita a les Olles amb la platja de l'Arenal de l'Ampolla i un àpat al port: és un circuit perfecte de mig dia.","ES":"Combina la visita a las Olles con la playa del Arenal de l'Ampolla y una comida en el puerto: es un circuito perfecto de media mañana.","EN":"Combine the visit to les Olles with the Arenal beach of l'Ampolla and a meal at the harbour: it's a perfect half-day circuit.","FR":"Combinez la visite des Olles avec la plage de l'Arenal de l'Ampolla et un repas au port : c'est un circuit parfait d'une demi-journée.","DE":"Verbinden Sie den Besuch der Olles mit dem Arenal-Strand von l'Ampolla und einem Essen im Hafen: Ein perfekter Halbtagsausflug.","NL":"Combineer het bezoek aan les Olles met het Arenal-strand van l'Ampolla en een maaltijd in de haven: een perfect halfdags circuit.","PT":"Combina a visita às Olles com a praia do Arenal de l'Ampolla e uma refeição no porto: é um circuito perfeito de meio dia."}},{"icon":"lagoon","name":{"CA":"El Garxal","ES":"El Garxal","EN":"El Garxal","FR":"El Garxal","DE":"El Garxal","NL":"El Garxal","PT":"El Garxal"},"tagline":{"CA":"La llacuna més recent, a la desembocadura","ES":"La laguna más reciente, en la desembocadura","EN":"The most recent lagoon, at the river mouth","FR":"La lagune la plus récente, à l'embouchure","DE":"Die jüngste Lagune, an der Flussmündung","NL":"De meest recente lagune, bij de riviermonding","PT":"A lagoa mais recente, na foz do rio"},"lead":{"CA":"El Garxal és la llacuna més nova del delta: va néixer quan l'Ebre va obrir una nova desembocadura cap al nord. Ara és una zona clau de nidificació i de pas d'aus, a tocar del nucli de Riumar. Des d'aquí s'accedeix al mirador del Zigurat i a la desembocadura real del riu.","ES":"El Garxal es la laguna más nueva del delta: nació cuando el Ebro abrió una nueva desembocadura hacia el norte. Ahora es una zona clave de nidificación y de paso de aves, junto al núcleo de Riumar. Desde aquí se accede al mirador del Zigurat y a la desembocadura real del río.","EN":"El Garxal is the delta's newest lagoon: it was born when the Ebro opened a new mouth to the north. It is now a key nesting and bird migration area, next to the Riumar area. From here you can access the Zigurat viewpoint and the actual river mouth.","FR":"El Garxal est la lagune la plus récente du delta : elle est née quand l'Èbre a ouvert une nouvelle embouchure vers le nord. C'est maintenant une zone clé de nidification et de passage des oiseaux, à côté de Riumar. De là, on accède au belvédère du Zigurat et à la vraie embouchure du fleuve.","DE":"El Garxal ist die neueste Lagune des Deltas: Sie entstand, als der Ebro eine neue Mündung nach Norden öffnete. Es ist jetzt ein wichtiges Nistgebiet und Vogelzuggebiet, neben der Siedlung Riumar. Von hier aus erreicht man den Zigurat-Aussichtspunkt und die eigentliche Flussmündung.","NL":"El Garxal is de nieuwste lagune van de delta: het ontstond toen de Ebro een nieuwe monding naar het noorden opende. Het is nu een belangrijk nestgebied en vogeltrekgebied, naast de wijk Riumar. Van hieruit bereikt u het Zigurat-uitzichtpunt en de werkelijke riviermonding.","PT":"O Garxal é a lagoa mais recente do delta: nasceu quando o Ebro abriu uma nova desembocadura para o norte. Agora é uma zona chave de nidificação e de passagem de aves, junto ao núcleo de Riumar. Daqui acede-se ao miradouro do Zigurat e à desembocadura real do rio."},"lat":40.733,"lng":0.842,"tip":{"CA":"El Garxal es pot visitar a peu des de Riumar en un recorregut d'una hora, o es combina perfectament amb la ruta de kayak de la desembocadura.","ES":"El Garxal se puede visitar a pie desde Riumar en un recorrido de una hora, o se combina perfectamente con la ruta de kayak de la desembocadura.","EN":"El Garxal can be visited on foot from Riumar in about an hour, or it pairs perfectly with the river mouth kayak route.","FR":"El Garxal peut être visité à pied depuis Riumar en environ une heure, ou il se combine parfaitement avec la route de kayak de l'embouchure.","DE":"El Garxal kann zu Fuß von Riumar in etwa einer Stunde besucht werden oder kombiniert sich perfekt mit der Kajakroute der Flussmündung.","NL":"El Garxal kan te voet vanuit Riumar in ongeveer een uur worden bezocht of combineert perfect met de kajakroute van de riviermonding.","PT":"O Garxal pode visitar-se a pé desde Riumar num percurso de uma hora, ou combina-se perfeitamente com a rota de kayak da desembocadura."}},{"icon":"island","name":{"CA":"Illa de Buda","ES":"Isla de Buda","EN":"Illa de Buda","FR":"Île de Buda","DE":"Insel Buda","NL":"Eiland Buda","PT":"Ilha de Buda"},"tagline":{"CA":"La major illa de Catalunya","ES":"La mayor isla de Cataluña","EN":"The largest island in Catalonia","FR":"La plus grande île de Catalogne","DE":"Die größte Insel Kataloniens","NL":"Het grootste eiland van Catalonië","PT":"A maior ilha da Catalunha"},"lead":{"CA":"Amb quasi 1.000 hectàrees, l'Illa de Buda és l'illa fluvial més gran de Catalunya. Va néixer per l'acumulació de sediments del riu Ebre al llarg dels segles. Hi ha toros bravos, arrossars, llacunes interiors i grans colònies d'aus. L'accés és restringit; es veu des del barco.","ES":"Con casi 1.000 hectáreas, la Isla de Buda es la isla fluvial más grande de Cataluña. Nació por la acumulación de sedimentos del río Ebro a lo largo de los siglos. Hay toros bravos, arrozales, lagunas interiores y grandes colonias de aves. El acceso es restringido; se ve desde el barco.","EN":"With nearly 1,000 hectares, Illa de Buda is the largest fluvial island in Catalonia. It was formed by the accumulation of Ebro sediments over the centuries. It has fighting bulls, rice fields, interior lagoons and large bird colonies. Access is restricted; it can be seen from the boat.","FR":"Avec près de 1 000 hectares, l'Île de Buda est la plus grande île fluviale de Catalogne. Elle est née de l'accumulation de sédiments de l'Èbre au fil des siècles. On y trouve des taureaux de combat, des rizières, des lagunes intérieures et de grandes colonies d'oiseaux. L'accès est restreint ; elle se voit depuis le bateau.","DE":"Mit fast 1.000 Hektar ist die Insel Buda die größte Flussinsel Kataloniens. Sie entstand durch die Ansammlung von Ebro-Sedimenten über die Jahrhunderte. Es gibt Kampfstiere, Reisfelder, innere Lagunen und große Vogelkolonien. Der Zugang ist eingeschränkt; sie kann vom Boot aus gesehen werden.","NL":"Met bijna 1.000 hectare is Illa de Buda het grootste riviereiland van Catalonië. Het ontstond door de ophoping van Ebro-sedimenten door de eeuwen heen. Er zijn vechtende stieren, rijstvelden, binnenste lagunes en grote vogelkolonies. Toegang is beperkt; het is te zien vanaf de boot.","PT":"Com quase 1.000 hectares, a Ilha de Buda é a maior ilha fluvial da Catalunha. Nasceu pela acumulação de sedimentos do Ebro ao longo dos séculos. Há touros bravos, arrozais, lagoas interiores e grandes colónias de aves. O acesso é restrito; vê-se a partir do barco."},"lat":40.724,"lng":0.856,"tip":{"CA":"La millor manera de veure l'Illa de Buda és la combinació de 4x4 + passeig en barco: veus l'illa des de terra i des del riu. Unes 3,5 hores en total.","ES":"La mejor manera de ver la Isla de Buda es la combinación de 4x4 + paseo en barco: ves la isla desde tierra y desde el río. Unas 3,5 horas en total.","EN":"The best way to see Illa de Buda is the 4x4 + boat trip combination: you see the island from land and from the river. About 3.5 hours in total.","FR":"La meilleure façon de voir l'île de Buda est la combinaison 4x4 + bateau : vous voyez l'île depuis terre et depuis le fleuve. Environ 3,5 heures au total.","DE":"Die beste Art, die Insel Buda zu sehen, ist die 4x4- + Bootsfahrt-Kombination: Sie sehen die Insel vom Land und vom Fluss aus. Insgesamt etwa 3,5 Stunden.","NL":"De beste manier om Illa de Buda te zien is de 4x4 + boottocht combinatie: je ziet het eiland vanaf land en vanuit de rivier. In totaal ongeveer 3,5 uur.","PT":"A melhor forma de ver a Ilha de Buda é a combinação 4x4 + passeio de barco: vês a ilha da terra e do rio. Cerca de 3,5 horas no total."}},{"icon":"spring","name":{"CA":"Ullals de Baltasar","ES":"Ullals de Baltasar","EN":"Ullals de Baltasar","FR":"Ullals de Baltasar","DE":"Ullals de Baltasar","NL":"Ullals de Baltasar","PT":"Ullals de Baltasar"},"tagline":{"CA":"Surgències d'aigua dolça en un delta salobre","ES":"Surgencias de agua dulce en un delta salobre","EN":"Freshwater springs in a brackish delta","FR":"Sources d'eau douce dans un delta saumâtre","DE":"Süßwasserquellen in einem brackigen Delta","NL":"Zoetwaterbronnen in een brakke delta","PT":"Nascentes de água doce num delta salobre"},"lead":{"CA":"Els Ullals de Baltasar són una cinquantena de surgències d'aigua dolça subterrània que emergeixen en plena planura deltaica. L'aigua prové dels aqüífers del Montsià i els Ports, recorre quilòmetres sota terra i brolla a temperatura constant (17-19°C). Un oasi de nenúfars, tortugues i granotes en un delta salobre.","ES":"Los Ullals de Baltasar son unas cincuenta surgencias de agua dulce subterránea que emergen en plena planura deltaica. El agua proviene de los acuíferos del Montsià y los Puertos, recorre kilómetros bajo tierra y brota a temperatura constante (17-19°C). Un oasis de nenúfares, tortugas y ranas en un delta salobre.","EN":"The Ullals de Baltasar are some fifty underground freshwater springs that emerge in the middle of the delta plain. The water comes from the Montsià and Ports aquifers, travels kilometres underground and surfaces at a constant temperature (17-19°C). An oasis of water lilies, turtles and frogs in a brackish delta.","FR":"Les Ullals de Baltasar sont une cinquantaine de sources d'eau douce souterraine qui émergent en pleine plaine deltaïque. L'eau provient des aquifères du Montsià et des Ports, parcourt des kilomètres sous terre et jaillit à une température constante (17-19°C). Une oasis de nénuphars, de tortues et de grenouilles dans un delta saumâtre.","DE":"Die Ullals de Baltasar sind etwa fünfzig unterirdische Süßwasserquellen, die mitten in der Deltaebene auftauchen. Das Wasser stammt aus den Aquiferen des Montsià und der Ports, reist Kilometer unter der Erde und taucht mit konstanter Temperatur (17-19°C) auf. Eine Oase aus Seerosen, Schildkröten und Fröschen in einem brackigen Delta.","NL":"De Ullals de Baltasar zijn ongeveer vijftig ondergrondse zoetwaterbronnen die opkomen midden in de deltavlakte. Het water komt uit de watervoerende lagen van de Montsià en de Ports, reist kilometers ondergronds en borrelt op bij constante temperatuur (17-19°C). Een oase van waterlelies, schildpadden en kikkers in een brakke delta.","PT":"Os Ullals de Baltasar são cerca de cinquenta nascentes de água doce subterrânea que emergem em plena planície deltaica. A água provém dos aquíferos do Montsià e dos Ports, percorre quilómetros sob a terra e brota a temperatura constante (17-19°C). Um oásis de nenúfares, tartarugas e rãs num delta salobre."},"lat":40.622,"lng":0.606,"tip":{"CA":"Els ullals estan millor en primavera i estiu: els nenúfars florits i el cant de les granotes fan de la visita una experiència molt sensorial. Porta repel·lent de mosquits.","ES":"Los ullals están mejor en primavera y verano: los nenúfares en flor y el canto de las ranas hacen de la visita una experiencia muy sensorial. Lleva repelente de mosquitos.","EN":"The ullals are best in spring and summer: flowering water lilies and the song of frogs make the visit a very sensory experience. Bring mosquito repellent.","FR":"Les ullals sont au mieux au printemps et en été : les nénuphars en fleur et le chant des grenouilles font de la visite une expérience très sensorielle. Apportez un répulsif anti-moustiques.","DE":"Die Ullals sind im Frühling und Sommer am schönsten: blühende Seerosen und der Gesang der Frösche machen den Besuch zu einem sehr sinnlichen Erlebnis. Mückenspray mitbringen.","NL":"De ullals zijn het mooist in lente en zomer: bloeiende waterlelies en het gezang van kikkers maken het bezoek tot een zeer zintuiglijke ervaring. Insectenspray meenemen.","PT":"Os ullals estão melhor na primavera e verão: os nenúfares floridos e o canto das rãs tornam a visita uma experiência muito sensorial. Leva repelente de mosquitos."}},{"icon":"restricted","name":{"CA":"Punta de la Banya i Salines","ES":"Punta de la Banya y Salinas","EN":"Punta de la Banya & Salt Flats","FR":"Punta de la Banya et Salins","DE":"Punta de la Banya und Salinen","NL":"Punta de la Banya en Zoutpannen","PT":"Punta de la Banya e Salinas"},"tagline":{"CA":"Reserva natural: 60% de la gavina corsa mundial","ES":"Reserva natural: 60% de la gaviota de Audouin mundial","EN":"Nature reserve: 60% of the world's Audouin's gulls","FR":"Réserve naturelle : 60% de la mouette d'Audouin mondiale","DE":"Naturschutzgebiet: 60% der weltweiten Audouin-Möwen","NL":"Natuurreservaat: 60% van de wereldpopulatie Audouins meeuw","PT":"Reserva natural: 60% da gaivota-de-Audouin mundial"},"lead":{"CA":"La Punta de la Banya és l'espai natural més extens de tot el Parc Natural: 2.700 hectàrees de peninsula tancada per la barra del Trabucador. Reserva Natural Parcial des del 1986, accés restringit. Les Salines de la Trinitat (les úniques operatives del delta, 25.000 t de sal/any) i unes colònies de nidificació d'importància mundial fan d'aquest lloc un dels punts més excepcionals de la Mediterrània.","ES":"La Punta de la Banya es el espacio natural más extenso de todo el Parque Natural: 2.700 hectáreas de península cerrada por la barra del Trabucador. Reserva Natural Parcial desde 1986, acceso restringido. Las Salinas de la Trinidad (las únicas operativas del delta, 25.000 t de sal/año) y unas colonias de nidificación de importancia mundial hacen de este lugar uno de los puntos más excepcionales del Mediterráneo.","EN":"Punta de la Banya is the largest natural space in the entire Nature Park: 2,700 hectares of peninsula closed off by the Trabucador sandbar. Partial Nature Reserve since 1986, restricted access. The Trinitat Salt Flats (the only operational ones in the delta, 25,000 t of salt/year) and bird breeding colonies of world importance make this one of the most exceptional spots in the Mediterranean.","FR":"La Punta de la Banya est l'espace naturel le plus vaste de tout le Parc naturel : 2 700 hectares de péninsule fermée par la barre du Trabucador. Réserve naturelle partielle depuis 1986, accès restreint. Les salines de la Trinitat (les seules opérationnelles du delta, 25 000 t de sel/an) et des colonies de nidification d'importance mondiale font de ce lieu l'un des plus exceptionnels de la Méditerranée.","DE":"Die Punta de la Banya ist der größte Naturraum des gesamten Naturparks: 2.700 Hektar Halbinsel, die durch die Trabucador-Sandbank abgeschlossen wird. Teilnaturschutzgebiet seit 1986, eingeschränkter Zugang. Die Trinitat-Salinen (die einzigen betriebsfähigen im Delta, 25.000 t Salz/Jahr) und Brutkolonien von weltweiter Bedeutung machen diesen Ort zu einem der außergewöhnlichsten Punkte des Mittelmeers.","NL":"Punta de la Banya is de grootste natuurruimte van het gehele Natuurpark: 2.700 hectare schiereiland afgesloten door de Trabucador-zandbank. Gedeeltelijk Natuurreservaat sinds 1986, beperkte toegang. De Trinitat-zoutpannen (de enige operationele in de delta, 25.000 t zout/jaar) en broedkolonies van wereldbelang maken dit een van de meest uitzonderlijke plekken van de Middellandse Zee.","PT":"A Punta de la Banya é o espaço natural mais extenso de todo o Parque Natural: 2.700 hectares de península fechada pela barra do Trabucador. Reserva Natural Parcial desde 1986, acesso restrito. As Salinas da Trinitat (as únicas operacionais do delta, 25.000 t de sal/ano) e colónias de nidificação de importância mundial fazem deste lugar um dos pontos mais excecionais do Mediterrâneo."},"lat":40.59,"lng":0.622,"tip":{"CA":"No es pot entrar a la Banya, però des del mirador del Trabucador es veuen les salines i les aus perfectament. Amb prismàtics, els flamencos i les avocetes s'apropen moltíssim.","ES":"No se puede entrar a la Banya, pero desde el mirador del Trabucador se ven las salinas y las aves perfectamente. Con prismáticos, los flamencos y las avocetas se acercan muchísimo.","EN":"You cannot enter la Banya, but from the Trabucador viewpoint the salt flats and the birds are perfectly visible. With binoculars, flamingos and avocets come very close.","FR":"On ne peut pas entrer à la Banya, mais depuis le belvédère du Trabucador, on voit parfaitement les salines et les oiseaux. Avec des jumelles, les flamants roses et les avocettes se rapprochent beaucoup.","DE":"Man kann la Banya nicht betreten, aber vom Trabucador-Aussichtspunkt aus sind die Salinen und die Vögel perfekt sichtbar. Mit Fernglas kommen Flamingos und Säbelschnäbler sehr nah.","NL":"Je kunt la Banya niet betreden, maar vanaf het Trabucador-uitzichtpunt zijn de zoutpannen en de vogels perfect zichtbaar. Met een verrekijker komen flamingo's en kluten heel dichtbij.","PT":"Não se pode entrar na Banya, mas do miradouro do Trabucador as salinas e as aves são perfeitamente visíveis. Com binóculos, flamingos e alfaiates aproximam-se muito."}},{"icon":"museum","name":{"CA":"Ecomuseu i Casa de Fusta","ES":"Ecomuseo y Casa de Fusta","EN":"Ecomuseum & Casa de Fusta","FR":"Écomusée et Casa de Fusta","DE":"Ecomuseum & Casa de Fusta","NL":"Ecomuseum & Casa de Fusta","PT":"Ecomuseu e Casa de Fusta"},"tagline":{"CA":"Els dos centres d'interpretació del Parc Natural","ES":"Los dos centros de interpretación del Parque Natural","EN":"The two interpretation centres of the Nature Park","FR":"Les deux centres d'interprétation du Parc naturel","DE":"Die zwei Interpretationszentren des Naturparks","NL":"De twee bezoekerscentra van het Natuurpark","PT":"Os dois centros de interpretação do Parque Natural"},"lead":{"CA":"El Parc Natural té dos centres d'informació: l'Ecomuseu a Deltebre (hemidelta nord) i la Casa de Fusta a la bassa de l'Encanyissada (hemidelta sud). Tots dos son gratuïts i el punt de partida ideal per orientar-se i planificar la visita al delta.","ES":"El Parque Natural tiene dos centros de información: el Ecomuseo en Deltebre (hemidelta norte) y la Casa de Fusta en la laguna de l'Encanyissada (hemidelta sur). Ambos son gratuitos y el punto de partida ideal para orientarse y planificar la visita al delta.","EN":"The Nature Park has two information centres: the Ecomuseum in Deltebre (north hemidelta) and the Casa de Fusta by the Encanyissada lagoon (south hemidelta). Both are free and the ideal starting point for getting your bearings and planning your visit to the delta.","FR":"Le Parc naturel dispose de deux centres d'information : l'Écomusée à Deltebre (hémidelta nord) et la Casa de Fusta au bord de la lagune de l'Encanyissada (hémidelta sud). Tous deux sont gratuits et constituent le point de départ idéal pour s'orienter et planifier la visite du delta.","DE":"Der Naturpark hat zwei Informationszentren: das Ecomuseum in Deltebre (Nord-Hemidelta) und das Casa de Fusta an der Encanyissada-Lagune (Süd-Hemidelta). Beide sind kostenlos und der ideale Ausgangspunkt zur Orientierung und Planung des Deltabesuchs.","NL":"Het Natuurpark heeft twee informatiecentra: het Ecomuseum in Deltebre (noord-hemidelta) en het Casa de Fusta bij de Encanyissada-lagune (zuid-hemidelta). Beide zijn gratis en het ideale startpunt om je te oriënteren en je bezoek aan de delta te plannen.","PT":"O Parque Natural tem dois centros de informação: o Ecomuseu em Deltebre (hemidelta norte) e a Casa de Fusta na lagoa da Encanyissada (hemidelta sul). Ambos são gratuitos e o ponto de partida ideal para se orientar e planificar a visita ao delta."},"lat":40.721,"lng":0.772,"tip":{"CA":"Si és la primera vegada al delta, comença per l'Ecomuseu de Deltebre: en 45 minuts t'explica tot el que necessites saber per treure el màxim de la visita.","ES":"Si es la primera vez en el delta, empieza por el Ecomuseo de Deltebre: en 45 minutos te explica todo lo que necesitas saber para sacar el máximo de la visita.","EN":"If it's your first time in the delta, start at the Ecomuseum of Deltebre: in 45 minutes it explains everything you need to know to get the most out of your visit.","FR":"Si c'est la première fois au delta, commencez par l'Écomusée de Deltebre : en 45 minutes, il vous explique tout ce que vous devez savoir pour tirer le meilleur de votre visite.","DE":"Wenn es Ihr erster Besuch im Delta ist, beginnen Sie mit dem Ecomuseum von Deltebre: In 45 Minuten erklärt es alles, was Sie wissen müssen, um das Beste aus Ihrem Besuch herauszuholen.","NL":"Als het uw eerste keer in de delta is, begin dan bij het Ecomuseum van Deltebre: in 45 minuten legt het alles uit wat u moet weten om het meeste uit uw bezoek te halen.","PT":"Se é a primeira vez no delta, começa pelo Ecomuseu de Deltebre: em 45 minutos explica tudo o que precisas saber para tirar o máximo da visita."}}];

export const D_ACT = [{"icon":"bike","name":{"CA":"Bicicleta","ES":"Bicicleta","EN":"Cycling","FR":"Vélo","DE":"Fahrrad","NL":"Fietsen","PT":"Bicicleta"},"tagline":{"CA":"La millor manera de descobrir el delta","ES":"La mejor manera de descubrir el delta","EN":"The best way to discover the delta","FR":"La meilleure façon de découvrir le delta","DE":"Die beste Art, das Delta zu entdecken","NL":"De beste manier om de delta te ontdekken","PT":"A melhor forma de descobrir o delta"},"lead":{"CA":"El delta és pla, els camins estan ben senyalitzats i els paisatges canvien a cada revolt: arrossars, llacunes, platges i el riu. En bici tot és a mida humana, i fins i tot els nens petits poden pedalar sense problemes.","ES":"El delta es llano, los caminos están bien señalizados y los paisajes cambian en cada recodo: arrozales, lagunas, playas y el río. En bici todo está a escala humana, y hasta los niños pequeños pueden pedalear sin problemas.","EN":"The delta is flat, the paths are well signposted and the landscapes change at every bend: rice fields, lagoons, beaches and the river. By bike everything is human-scale, and even young children can pedal without any problem.","FR":"Le delta est plat, les chemins sont bien balisés et les paysages changent à chaque virage : rizières, lagunes, plages et le fleuve. À vélo, tout est à échelle humaine, et même les jeunes enfants peuvent pédaler sans problème.","DE":"Das Delta ist flach, die Wege sind gut ausgeschildert und die Landschaften wechseln bei jeder Biegung: Reisfelder, Lagunen, Strände und der Fluss. Mit dem Fahrrad ist alles menschlich, und sogar kleine Kinder können problemlos radeln.","NL":"De delta is vlak, de paden zijn goed bewegwijzerd en de landschappen veranderen bij elke bocht: rijstvelden, lagunes, stranden en de rivier. Op de fiets is alles op menselijke schaal, en zelfs jonge kinderen kunnen zonder problemen fietsen.","PT":"O delta é plano, os caminhos estão bem sinalizados e as paisagens mudam a cada curva: arrozais, lagoas, praias e o rio. De bicicleta tudo está à escala humana, e até as crianças pequenas podem pedalar sem problemas."}},{"icon":"kayak","name":{"CA":"Kayak i piragua","ES":"Kayak y piragua","EN":"Kayaking","FR":"Kayak","DE":"Kajak","NL":"Kayakken","PT":"Kayak"},"tagline":{"CA":"El delta des de l'aigua","ES":"El delta desde el agua","EN":"The delta from the water","FR":"Le delta vu de l'eau","DE":"Das Delta vom Wasser aus","NL":"De delta vanuit het water","PT":"O delta a partir da água"},"lead":{"CA":"Remejar pel riu Ebre, per les lagunas o per la desembocadura és una de les experiències més intenses del delta. L'aigua tranquil·la del riu permet apropar-se a la fauna i als paisatges d'una manera impossible per terra.","ES":"Remar por el río Ebro, por las lagunas o por la desembocadura es una de las experiencias más intensas del delta. El agua tranquila del río permite acercarse a la fauna y los paisajes de una manera imposible por tierra.","EN":"Paddling along the Ebro river, through the lagoons or at the mouth is one of the most intense experiences in the delta. The calm river water allows you to get close to wildlife and landscapes in a way impossible on land.","FR":"Pagayer sur le fleuve Èbre, dans les lagunes ou à l'embouchure est l'une des expériences les plus intenses du delta. Les eaux calmes du fleuve permettent de s'approcher de la faune et des paysages d'une façon impossible à terre.","DE":"Auf dem Ebro, durch die Lagunen oder an der Mündung zu paddeln ist eines der intensivsten Erlebnisse im Delta. Das ruhige Flusswasser ermöglicht es, der Tierwelt und den Landschaften auf eine Weise nahezukommen, die zu Land unmöglich ist.","NL":"Peddelen op de Ebro, door de lagunes of aan de monding is een van de meest intense ervaringen in de delta. Het rustige rivierwater stelt je in staat om op een manier dichtbij de fauna en landschappen te komen die te land onmogelijk is.","PT":"Remar pelo rio Ebro, pelas lagoas ou pela foz é uma das experiências mais intensas do delta. A água tranquila do rio permite aproximar-se da fauna e das paisagens de uma forma impossível em terra."}},{"icon":"boat","name":{"CA":"Passeig en barca","ES":"Paseo en barca","EN":"Boat trip","FR":"Promenade en bateau","DE":"Bootsfahrt","NL":"Boottocht","PT":"Passeio de barco"},"tagline":{"CA":"Fins a la desembocadura de l'Ebre","ES":"Hasta la desembocadura del Ebro","EN":"To the mouth of the Ebro","FR":"Jusqu'à l'embouchure de l'Èbre","DE":"Bis zur Mündung des Ebro","NL":"Naar de monding van de Ebro","PT":"Até à foz do Ebro"},"lead":{"CA":"Un creuer fluvial d'uns 45 minuts des de Deltebre que porta fins a la desembocadura del riu Ebre: la Illa de Buda (la més gran de Catalunya), el Garxal i la gola on el riu s'abraça amb el Mediterrani. Amb guia i audioguia.","ES":"Un crucero fluvial de unos 45 minutos desde Deltebre que lleva hasta la desembocadura del río Ebro: la Isla de Buda (la más grande de Cataluña), el Garxal y la gola donde el río se abraza con el Mediterráneo. Con guía y audioguía.","EN":"A river cruise of about 45 minutes from Deltebre that takes you to the Ebro's mouth: Illa de Buda (the largest island in Catalonia), el Garxal and the gola where the river meets the Mediterranean. With guide and audio guide.","FR":"Une croisière fluviale d'environ 45 minutes depuis Deltebre qui mène jusqu'à l'embouchure de l'Èbre : l'Illa de Buda (la plus grande île de Catalogne), el Garxal et la gola où le fleuve embrasse la Méditerranée. Avec guide et audioguide.","DE":"Eine Flusskreuzfahrt von etwa 45 Minuten von Deltebre, die zur Mündung des Ebro führt: Illa de Buda (die größte Insel Kataloniens), el Garxal und die Gola, wo der Fluss das Mittelmeer trifft. Mit Führer und Audioguide.","NL":"Een riviercruise van ongeveer 45 minuten vanuit Deltebre naar de monding van de Ebro: Illa de Buda (het grootste eiland van Catalonië), el Garxal en de gola waar de rivier de Middellandse Zee ontmoet. Met gids en audiogids.","PT":"Um cruzeiro fluvial de cerca de 45 minutos desde Deltebre que leva até à foz do Ebro: a Illa de Buda (a maior ilha da Catalunha), o Garxal e a gola onde o rio se abraça com o Mediterrâneo. Com guia e audioguia."}},{"icon":"kite","name":{"CA":"Kitesurf i windsurf","ES":"Kitesurf y windsurf","EN":"Kitesurfing & windsurfing","FR":"Kitesurf et windsurf","DE":"Kitesurfen & Windsurfen","NL":"Kitesurfen & windsurfen","PT":"Kitesurf e windsurf"},"tagline":{"CA":"Dos spots mítics: Trabucador i Riumar","ES":"Dos spots míticos: Trabucador y Riumar","EN":"Two legendary spots: Trabucador and Riumar","FR":"Deux spots légendaires : Trabucador et Riumar","DE":"Zwei Kult-Spots: Trabucador und Riumar","NL":"Twee legendarische spots: Trabucador en Riumar","PT":"Dois spots míticos: Trabucador e Riumar"},"lead":{"CA":"El delta de l'Ebre és un dels millors llocs de kitesurf i windsurf del Mediterrani. Vent constant, aigues poc profundes i dos spots molt ben diferenciats: el Trabucador per aprendre i navegar protegit, Riumar per a la desembocadura i el mar obert.","ES":"El delta del Ebro es uno de los mejores lugares de kitesurf y windsurf del Mediterráneo. Viento constante, aguas poco profundas y dos spots muy bien diferenciados: el Trabucador para aprender y navegar protegido, Riumar para la desembocadura y el mar abierto.","EN":"The Ebro Delta is one of the best kitesurfing and windsurfing spots in the Mediterranean. Constant wind, shallow waters and two very distinct spots: el Trabucador for learning and sheltered sailing, Riumar for the open sea and river mouth.","FR":"Le delta de l'Èbre est l'un des meilleurs spots de kitesurf et windsurf de la Méditerranée. Vent constant, eaux peu profondes et deux spots très bien différenciés : le Trabucador pour apprendre et naviguer à l'abri, Riumar pour l'embouchure et la pleine mer.","DE":"Das Ebro-Delta ist einer der besten Kitesurfing- und Windsurfingspots im Mittelmeer. Konstanter Wind, flaches Wasser und zwei sehr unterschiedliche Spots: El Trabucador zum Lernen und geschützten Segeln, Riumar für die Mündung und offene See.","NL":"De Ebrodelta is een van de beste kitesurfing- en windsurfingspots in de Middellandse Zee. Constante wind, ondiep water en twee heel verschillende spots: El Trabucador om te leren en beschermd te zeilen, Riumar voor de monding en de open zee.","PT":"O delta do Ebro é um dos melhores lugares de kitesurf e windsurf do Mediterrâneo. Vento constante, águas pouco profundas e dois spots muito bem diferenciados: el Trabucador para aprender e navegar protegido, Riumar para a foz e o mar aberto."}},{"icon":"bird","name":{"CA":"Observació d'aus","ES":"Observación de aves","EN":"Birdwatching","FR":"Observation d'oiseaux","DE":"Vogelbeobachtung","NL":"Vogelspotten","PT":"Observação de aves"},"tagline":{"CA":"Més de 360 espècies en un sol delta","ES":"Más de 360 especies en un solo delta","EN":"More than 360 species in a single delta","FR":"Plus de 360 espèces dans un seul delta","DE":"Mehr als 360 Arten in einem einzigen Delta","NL":"Meer dan 360 soorten in één delta","PT":"Mais de 360 espécies num só delta"},"lead":{"CA":"De les 600 espècies d'aus registrades a Europa, més de 360 s'han vist al delta de l'Ebre. Els flamencos, la garsa morada, el charrán, l'àguila pescadora i el bernat pescaire conviven en un dels humedals més importants d'Europa occidental.","ES":"De las 600 especies de aves registradas en Europa, más de 360 se han visto en el delta del Ebro. Los flamencos, la garza purpúrea, el charrán, el águila pescadora y la garza real conviven en uno de los humedales más importantes de Europa occidental.","EN":"Of the 600 bird species recorded in Europe, more than 360 have been sighted in the Ebro Delta. Flamingos, purple herons, terns, ospreys and grey herons coexist in one of the most important wetlands in Western Europe.","FR":"Des 600 espèces d'oiseaux recensées en Europe, plus de 360 ont été aperçues dans le delta de l'Èbre. Flamants roses, hérons pourprés, sternes, balbuzards pêcheurs et hérons cendrés coexistent dans l'un des zones humides les plus importantes d'Europe occidentale.","DE":"Von den 600 in Europa registrierten Vogelarten wurden mehr als 360 im Ebro-Delta gesichtet. Flamingos, Purpurreiher, Seeschwalben, Fischadler und Graureiher koexistieren in einem der bedeutendsten Feuchtgebiete Westeuropas.","NL":"Van de 600 vogelsoorten die in Europa zijn geregistreerd, zijn er meer dan 360 gesignaleerd in de Ebrodelta. Flamingo's, purperende reigers, sterns, visarenden en blauwe reigers leven samen in een van de belangrijkste wetlands van West-Europa.","PT":"Das 600 espécies de aves registadas na Europa, mais de 360 foram avistadas no delta do Ebro. Flamingos, garças-purpúreas, andorinhas-do-mar, águias-pescadoras e garças-reais convivem num dos zonas húmidas mais importantes da Europa ocidental."}},{"icon":"jeep","name":{"CA":"Excursió en 4x4","ES":"Excursión en 4x4","EN":"4x4 excursion","FR":"Excursion en 4x4","DE":"4x4-Ausflug","NL":"4x4-excursie","PT":"Excursão em 4x4"},"tagline":{"CA":"Els racons inaccessibles del delta","ES":"Los rincones inaccesibles del delta","EN":"The inaccessible corners of the delta","FR":"Les recoins inaccessibles du delta","DE":"Die unzugänglichen Winkel des Deltas","NL":"De ontoegankelijke hoeken van de delta","PT":"Os cantos inacessíveis do delta"},"lead":{"CA":"Algunes de les zones més belles del delta no són accessibles a peu ni en bici: pistes de sorra, camins inundats i paratges protegits. El 4x4 guiat permet arribar a llocs que la majoria de visitants mai veuen.","ES":"Algunas de las zonas más bellas del delta no son accesibles a pie ni en bici: pistas de arena, caminos inundados y parajes protegidos. El 4x4 guiado permite llegar a lugares que la mayoría de visitantes nunca ven.","EN":"Some of the delta's most beautiful areas are not accessible on foot or by bike: sand tracks, flooded paths and protected areas. A guided 4x4 allows you to reach places most visitors never see.","FR":"Certaines des plus belles zones du delta ne sont pas accessibles à pied ou à vélo : pistes de sable, chemins inondés et espaces protégés. Le 4x4 guidé permet d'atteindre des endroits que la plupart des visiteurs ne voient jamais.","DE":"Einige der schönsten Gebiete des Deltas sind weder zu Fuß noch mit dem Fahrrad zugänglich: Sandpisten, überschwemmte Wege und Schutzgebiete. Ein geführtes 4x4 ermöglicht es, Orte zu erreichen, die die meisten Besucher nie sehen.","NL":"Sommige van de mooiste gebieden van de delta zijn niet toegankelijk te voet of per fiets: zandpaden, overstroomde wegen en beschermde gebieden. Een begeleide 4x4 stelt je in staat plaatsen te bereiken die de meeste bezoekers nooit zien.","PT":"Algumas das zonas mais bonitas do delta não são acessíveis a pé nem de bicicleta: pistas de areia, caminhos inundados e paragens protegidas. O 4x4 guiado permite chegar a lugares que a maioria dos visitantes nunca vê."}},{"icon":"sup","name":{"CA":"Paddle surf (SUP)","ES":"Paddle surf (SUP)","EN":"Paddleboarding (SUP)","FR":"Paddle surf (SUP)","DE":"Paddleboarding (SUP)","NL":"Paddleboarden (SUP)","PT":"Paddle surf (SUP)"},"tagline":{"CA":"Peu dret sobre l'Ebre i la badia","ES":"De pie sobre el Ebro y la bahía","EN":"Standing on the Ebro and the bay","FR":"Debout sur l'Èbre et la baie","DE":"Stehend auf dem Ebro und der Bucht","NL":"Staand op de Ebro en de baai","PT":"De pé sobre o Ebro e a baía"},"lead":{"CA":"El paddle surf (SUP) ha crescut molt al delta en els últims anys. Les aigues tranquil·les del riu Ebre i la badia dels Alfacs el fan accessible per a tothom, inclosos nens, i és una manera diferent de moure's pel delta.","ES":"El paddle surf (SUP) ha crecido mucho en el delta en los últimos años. Las aguas tranquilas del río Ebro y la bahía de los Alfacs lo hacen accesible para todos, incluidos niños, y es una manera diferente de moverse por el delta.","EN":"Paddleboarding (SUP) has grown a lot in the delta in recent years. The calm waters of the Ebro and the Alfacs bay make it accessible to everyone, including children, and it's a different way to move around the delta.","FR":"Le paddle surf (SUP) a beaucoup évolué dans le delta ces dernières années. Les eaux calmes du fleuve Èbre et de la baie des Alfacs le rendent accessible à tous, y compris les enfants, et c'est une façon différente de se déplacer dans le delta.","DE":"Paddleboarding (SUP) ist im Delta in den letzten Jahren stark gewachsen. Die ruhigen Gewässer des Ebro und der Alfacs-Bucht machen es für alle zugänglich, auch für Kinder, und es ist eine andere Art, sich im Delta zu bewegen.","NL":"Paddleboarden (SUP) is de afgelopen jaren sterk gegroeid in de delta. Het rustige water van de Ebro en de Alfacs-baai maken het toegankelijk voor iedereen, inclusief kinderen, en het is een andere manier om door de delta te bewegen.","PT":"O paddle surf (SUP) cresceu muito no delta nos últimos anos. As águas calmas do Ebro e da baía dos Alfacs tornam-no acessível a todos, incluindo crianças, e é uma forma diferente de se mover pelo delta."}},{"icon":"horse","name":{"CA":"A cavall","ES":"A caballo","EN":"Horse riding","FR":"À cheval","DE":"Zu Pferd","NL":"Te paard","PT":"A cavalo"},"tagline":{"CA":"El delta al pas per arrossars i platges","ES":"El delta al paso por arrozales y playas","EN":"The delta at a walk through rice fields and beaches","FR":"Le delta au pas à travers rizières et plages","DE":"Das Delta im Schritt durch Reisfelder und Strände","NL":"De delta in stap door rijstvelden en stranden","PT":"O delta a passo por arrozais e praias"},"lead":{"CA":"Recórrer el delta a cavall és una de les activitats més singulars que ofereix el parc. Els cavalls es mouen per camins de terra entre arrossars i llacunes, arriben a platges verges i donen una perspectiva completament diferent del territori.","ES":"Recorrer el delta a caballo es una de las actividades más singulares que ofrece el parque. Los caballos se mueven por caminos de tierra entre arrozales y lagunas, llegan a playas vírgenes y dan una perspectiva completamente diferente del territorio.","EN":"Exploring the delta on horseback is one of the most unique activities the park offers. Horses move along dirt tracks between rice fields and lagoons, reach virgin beaches and give a completely different perspective of the territory.","FR":"Parcourir le delta à cheval est l'une des activités les plus singulières du parc. Les chevaux se déplacent sur des chemins de terre entre rizières et lagunes, atteignent des plages vierges et offrent une perspective entièrement différente du territoire.","DE":"Das Delta zu Pferd zu erkunden ist eine der einzigartigsten Aktivitäten, die der Park bietet. Die Pferde bewegen sich auf Erdwegen zwischen Reisfeldern und Lagunen, erreichen unberührte Strände und geben eine völlig andere Perspektive des Gebietes.","NL":"De delta te paard verkennen is een van de meest unieke activiteiten die het park biedt. De paarden bewegen over onverharde wegen tussen rijstvelden en lagunes, bereiken maagdelijke stranden en geven een heel ander perspectief op het gebied.","PT":"Percorrer o delta a cavalo é uma das atividades mais singulares que o parque oferece. Os cavalos movem-se por caminhos de terra entre arrozais e lagoas, chegam a praias virgens e dão uma perspetiva completamente diferente do território."}},{"icon":"hike","name":{"CA":"Senderisme costaner · GR-92","ES":"Senderismo costero · GR-92","EN":"Coastal hiking · GR-92","FR":"Randonnée côtière · GR-92","DE":"Küstenwandern · GR-92","NL":"Kustw andelen · GR-92","PT":"Caminhada costeira · GR-92"},"tagline":{"CA":"16,5 km de cales verges i penya-segats entre l'Ampolla i l'Ametlla","ES":"16,5 km de calas vírgenes y acantilados entre l'Ampolla y l'Ametlla","EN":"16.5 km of virgin coves and cliffs between l'Ampolla and l'Ametlla","FR":"16,5 km de criques vierges et falaises entre l'Ampolla et l'Ametlla","DE":"16,5 km jungfräuliche Buchten und Klippen zwischen l'Ampolla und l'Ametlla","NL":"16,5 km maagdelijke baaien en kliffen tussen l'Ampolla en l'Ametlla","PT":"16,5 km de enseadas virgens e penhascos entre l'Ampolla e l'Ametlla"},"lead":{"CA":"L'etapa 29 del GR-92 és una de les més belles del camí de ronda mediterrani. 16,5 km de litoral salvatge entre cales verges, penya-segats vermells, pins i mar cristallí que connecten l'Ampolla amb l'Ametlla de Mar. Part del sender europeu E-10.","ES":"La etapa 29 del GR-92 es una de las más bellas del camino de ronda mediterráneo. 16,5 km de litoral salvaje entre calas vírgenes, acantilados rojos, pinos y mar cristalino que conectan l'Ampolla con l'Ametlla de Mar. Parte del sendero europeo E-10.","EN":"Stage 29 of the GR-92 is one of the finest of the Mediterranean coastal path. 16.5 km of wild coastline between virgin coves, red cliffs, pine forests and crystal-clear sea linking l'Ampolla with l'Ametlla de Mar. Part of the European E-10 trail.","FR":"L'étape 29 du GR-92 est l'une des plus belles du chemin de ronde méditerranéen. 16,5 km de littoral sauvage entre criques vierges, falaises rouges, pins et mer cristalline reliant l'Ampolla à l'Ametlla de Mar. Partie du sentier européen E-10.","DE":"Etappe 29 des GR-92 ist eine der schönsten des mediterränen Küstenpfades. 16,5 km wilde Küste zwischen jungfräulichen Buchten, roten Klippen, Kiefernwäldern und kristallklarem Meer. Teil des europäischen E-10.","NL":"Etappe 29 van de GR-92 is een van de mooiste van het Mediterrane kustpad. 16,5 km wilde kustlijn tussen maagdelijke baaien, rode kliffen, dennenbossen en kristalhelder water. Deel van het Europese E-10.","PT":"A etapa 29 do GR-92 é uma das mais belas do caminho de ronda mediterrâneo. 16,5 km de litoral selvagem entre enseadas virgens, penhascos vermelhos, pinhais e mar cristalino. Parte da rota europeia E-10."}}];

export const D_PUEB = [{"name":{"CA":"Deltebre","ES":"Deltebre","EN":"Deltebre","FR":"Deltebre","DE":"Deltebre","NL":"Deltebre","PT":"Deltebre"},"tagline":{"CA":"El cor del hemidelta nord","ES":"El corazón del hemidelta norte","EN":"The heart of the north hemidelta","FR":"Le cœur de l'hémidelta nord","DE":"Das Herz des Nordhemideltas","NL":"Het hart van het noordhemidelta","PT":"O coração do hemidelta norte"},"lead":{"CA":"Deltebre és el principal municipi del delta, nascut el 1977 quan els barris de Jesús i Maria i la Cava es van segregar de Tortosa. Dividit pel canal de la Dreta, és la porta d'entrada al Parc Natural, seu de l'Ecomuseu i punt de sortida de les excursions en barco.","ES":"Deltebre es el principal municipio del delta, nacido en 1977 cuando los barrios de Jesús i Maria y la Cava se segregaron de Tortosa. Dividido por el canal de la Dreta, es la puerta de entrada al Parque Natural, sede del Ecomuseo y punto de salida de las excursiones en barco.","EN":"Deltebre is the delta's main municipality, born in 1977 when the barrios of Jesús i Maria and la Cava separated from Tortosa. Divided by the Dreta canal, it is the gateway to the Nature Park, home of the Ecomuseum and starting point for boat trips.","FR":"Deltebre est la principale commune du delta, née en 1977 quand les quartiers de Jesús i Maria et la Cava se sont séparés de Tortosa. Divisé par le canal de la Dreta, c'est la porte d'entrée du Parc naturel, siège de l'Écomusée et point de départ des excursions en bateau.","DE":"Deltebre ist die wichtigste Gemeinde des Deltas, geboren 1977, als sich die Stadtviertel Jesús i Maria und la Cava von Tortosa trennten. Geteilt durch den Dreta-Kanal, ist es das Tor zum Naturpark, Heimat des Ecomuseums und Startpunkt für Bootsausflüge.","NL":"Deltebre is de belangrijkste gemeente van de delta, geboren in 1977 toen de wijken Jesús i Maria en la Cava zich afscheidden van Tortosa. Verdeeld door het Dreta-kanaal, is het de toegangspoort tot het Natuurpark, thuisbasis van het Ecomuseum en startpunt voor boottochten.","PT":"Deltebre é o principal município do delta, nascido em 1977 quando os bairros de Jesús i Maria e la Cava se separaram de Tortosa. Dividido pelo canal da Dreta, é a porta de entrada ao Parque Natural, sede do Ecomuseu e ponto de partida das excursões de barco."},"lat":40.721,"lng":0.772},{"name":{"CA":"Sant Jaume d'Enveja","ES":"Sant Jaume d'Enveja","EN":"Sant Jaume d'Enveja","FR":"Sant Jaume d'Enveja","DE":"Sant Jaume d'Enveja","NL":"Sant Jaume d'Enveja","PT":"Sant Jaume d'Enveja"},"tagline":{"CA":"L'altra riba, el Trabucador i la calma","ES":"La otra orilla, el Trabucador y la calma","EN":"The other bank, El Trabucador and calm","FR":"L'autre rive, El Trabucador et la tranquillité","DE":"Das andere Ufer, El Trabucador und Ruhe","NL":"De andere oever, El Trabucador en rust","PT":"A outra margem, o Trabucador e a calma"},"lead":{"CA":"Al sud del riu, davant de Deltebre, Sant Jaume d'Enveja és el municipi que dona accés al Trabucador, a la platja de l'Eucaliptus i a la Tancada. Més rural i tranquil que el seu veí del nord, és el punt de partida natural per explorar el hemidelta sud.","ES":"Al sur del río, frente a Deltebre, Sant Jaume d'Enveja es el municipio que da acceso al Trabucador, la playa del Eucaliptus y la Tancada. Más rural y tranquilo que su vecino del norte, es el punto de partida natural para explorar el hemidelta sur.","EN":"South of the river, facing Deltebre, Sant Jaume d'Enveja is the municipality that gives access to El Trabucador, the Eucaliptus beach and la Tancada. More rural and calm than its northern neighbour, it is the natural starting point for exploring the south hemidelta.","FR":"Au sud du fleuve, en face de Deltebre, Sant Jaume d'Enveja est la commune qui donne accès au Trabucador, la plage d'Eucaliptus et la Tancada. Plus rural et tranquille que son voisin du nord, c'est le point de départ naturel pour explorer l'hémidelta sud.","DE":"Südlich des Flusses, gegenüber von Deltebre, ist Sant Jaume d'Enveja die Gemeinde, die Zugang zu El Trabucador, dem Eucaliptus-Strand und la Tancada bietet. Ländlicher und ruhiger als sein nördlicher Nachbar, ist es der natürliche Ausgangspunkt für die Erkundung des Südhemideltas.","NL":"Ten zuiden van de rivier, tegenover Deltebre, is Sant Jaume d'Enveja de gemeente die toegang biedt tot El Trabucador, het Eucaliptus-strand en la Tancada. Landelijker en rustiger dan zijn noordelijke buur, is het het natuurlijke startpunt voor het verkennen van het zuidhemidelta.","PT":"A sul do rio, em frente a Deltebre, Sant Jaume d'Enveja é o município que dá acesso ao Trabucador, a praia do Eucaliptus e a Tancada. Mais rural e tranquilo do que o seu vizinho do norte, é o ponto de partida natural para explorar o hemidelta sul."},"lat":40.713,"lng":0.765},{"name":{"CA":"Amposta","ES":"Amposta","EN":"Amposta","FR":"Amposta","DE":"Amposta","NL":"Amposta","PT":"Amposta"},"tagline":{"CA":"Capital del Montsià, pont penjant i cultura","ES":"Capital del Montsià, puente colgante y cultura","EN":"Capital of Montsià, suspension bridge and culture","FR":"Capitale du Montsià, pont suspendu et culture","DE":"Hauptstadt des Montsià, Hängebrücke und Kultur","NL":"Hoofdstad van Montsià, hangbrug en cultuur","PT":"Capital do Montsià, ponte suspensa e cultura"},"lead":{"CA":"Amposta és la porta d'entrada al hemidelta sud i la capital del Montsià, la comarca més meridional de Catalunya. La seva icona és el Pont Penjant (1921), el segon pont de formigó armat del món i durant anys el rècord de fonamentació a major fondària. Seu del Museu de les Terres de l'Ebre i del MónNatura Delta.","ES":"Amposta es la puerta de entrada al hemidelta sur y la capital del Montsià, la comarca más meridional de Cataluña. Su icono es el Pont Penjant (1921), el segundo puente de hormigón armado del mundo y durante años el récord de cimentación a mayor profundidad. Sede del Museo de les Terres de l'Ebre y del MónNatura Delta.","EN":"Amposta is the gateway to the south hemidelta and the capital of the Montsià, the southernmost region of Catalonia. Its icon is the Pont Penjant (1921), the world's second reinforced concrete suspension bridge and for years the record holder for deepest foundations. Home of the Museu de les Terres de l'Ebre and MónNatura Delta.","FR":"Amposta est la porte d'entrée de l'hémidelta sud et la capitale du Montsià, la région la plus méridionale de Catalogne. Son icône est le Pont Penjant (1921), le deuxième pont suspendu en béton armé du monde et pendant des années le record de fondations à la plus grande profondeur. Siège du Museu de les Terres de l'Ebre et de MónNatura Delta.","DE":"Amposta ist das Tor zum Südhemidelta und die Hauptstadt des Montsià, der südlichsten Region Kataloniens. Sein Wahrzeichen ist der Pont Penjant (1921), die weltweit zweite Stahlbetonhängebrücke und jahrelang der Rekordhalter für die tiefsten Fundamente. Heimat des Museu de les Terres de l'Ebre und MónNatura Delta.","NL":"Amposta is de toegangspoort tot het zuidhemidelta en de hoofdstad van de Montsià, de meest zuidelijke regio van Catalonië. Zijn icoon is de Pont Penjant (1921), de tweede gewapend-betonnen hangbrug ter wereld en jarenlang de recordhouder voor de diepste funderingen. Thuisbasis van het Museu de les Terres de l'Ebre en MónNatura Delta.","PT":"Amposta é a porta de entrada ao hemidelta sul e a capital do Montsià, a comarca mais meridional da Catalunha. O seu ícone é o Pont Penjant (1921), a segunda ponte suspensa de betão armado do mundo e durante anos o recorde de fundação a maior profundidade. Sede do Museu de les Terres de l'Ebre e do MónNatura Delta."},"lat":40.706,"lng":0.58},{"name":{"CA":"Sant Carles de la Ràpita","ES":"Sant Carles de la Ràpita","EN":"Sant Carles de la Ràpita","FR":"Sant Carles de la Ràpita","DE":"Sant Carles de la Ràpita","NL":"Sant Carles de la Ràpita","PT":"Sant Carles de la Ràpita"},"tagline":{"CA":"El port somiat de Carles III i el marisc de la badia","ES":"El puerto soñado de Carlos III y el marisco de la bahía","EN":"Carlos III's dream port and the bay's seafood","FR":"Le port rêvé de Carlos III et les fruits de mer de la baie","DE":"Carlos III.s Traumhafen und die Meeresfrüchte der Bucht","NL":"Carlos III's droomhaven en de zeevruchten van de baai","PT":"O porto sonhado de Carlos III e o marisco da baía"},"lead":{"CA":"Al segle XVIII el rei Carles III va voler convertir el petit nucli de pescadors de la Ràpita en un dels grans ports del Mediterrani. El pla no es va acabar de concretar, però va deixar empremtes en el traçat urbà, la Plaça Carles III i el canal de navegació. Avui és el gran port pesquer del delta, famós per l'arròs, el marisc i el langostí.","ES":"En el siglo XVIII el rey Carlos III quiso convertir el pequeño núcleo de pescadores de la Ràpita en uno de los grandes puertos del Mediterráneo. El plan no llegó a concretarse, pero dejó huellas en el trazado urbano, la Plaça Carles III y el canal de navegación. Hoy es el gran puerto pesquero del delta, famoso por el arroz, el marisco y el langostino.","EN":"In the 18th century King Carlos III wanted to turn la Ràpita's small fishing community into one of the great ports of the Mediterranean. The plan never fully materialised, but it left traces in the urban layout, Plaça Carles III and the navigation canal. Today it is the delta's great fishing port, famous for rice, seafood and prawns.","FR":"Au XVIIIe siècle, le roi Carlos III voulait transformer le petit noyau de pêcheurs de la Ràpita en l'un des grands ports de la Méditerranée. Le plan ne s'est pas concrétisé, mais il a laissé des traces dans le tissu urbain, la Plaça Carles III et le canal de navigation. Aujourd'hui, c'est le grand port de pêche du delta, célèbre pour le riz, les fruits de mer et les crevettes.","DE":"Im 18. Jahrhundert wollte König Carlos III. die kleine Fischergemeinde von la Ràpita zu einem der großen Häfen des Mittelmeers machen. Der Plan wurde nie vollständig umgesetzt, hinterließ aber Spuren im Stadtbild, dem Plaça Carles III und dem Navigationskanal. Heute ist es der große Fischerhafen des Deltas, bekannt für Reis, Meeresfrüchte und Garnelen.","NL":"In de 18e eeuw wilde koning Carlos III de kleine vissergemeenschap van la Ràpita omvormen tot een van de grote havens van de Middellandse Zee. Het plan is nooit volledig uitgekomen, maar heeft sporen nagelaten in het stedelijk weefsel, Plaça Carles III en het navigatiekanaal. Vandaag is het de grote vissershaven van de delta, beroemd om rijst, zeevruchten en garnalen.","PT":"No século XVIII o rei Carlos III quis transformar o pequeno núcleo de pescadores da Ràpita num dos grandes portos do Mediterrâneo. O plano não se concretizou totalmente, mas deixou marcas no traçado urbano, a Plaça Carles III e o canal de navegação. Hoje é o grande porto pesqueiro do delta, famoso pelo arroz, o marisco e o langostim."},"lat":40.621,"lng":0.598},{"name":{"CA":"L'Ampolla","ES":"L'Ampolla","EN":"L'Ampolla","FR":"L'Ampolla","DE":"L'Ampolla","NL":"L'Ampolla","PT":"L'Ampolla"},"tagline":{"CA":"La porta nord del delta, poble mariner","ES":"La puerta norte del delta, pueblo marinero","EN":"The northern gateway to the delta, a fishing village","FR":"La porte nord du delta, village de pêcheurs","DE":"Das nördliche Tor zum Delta, ein Fischerdorf","NL":"De noordelijke toegangspoort van de delta, een visserdorp","PT":"A porta norte do delta, vila piscatória"},"lead":{"CA":"L'Ampolla és el primer poble del delta per a qui ve de Barcelona: 'la porta del delta'. Antic hostal a la carretera de Tortosa a València, va créixer amb la pesca fins a convertir-se en un petit poble mariner de gran encant. Cap Roig (Bandera Blava), les Avellanes i la Bassa de les Olles en fan un punt de partida ideal per explorar el nord del parc.","ES":"L'Ampolla es el primer pueblo del delta para quien viene de Barcelona: 'la puerta del delta'. Antiguo hostal en la carretera de Tortosa a Valencia, creció con la pesca hasta convertirse en un pequeño pueblo marinero de gran encanto. Cap Roig (Bandera Azul), les Avellanes y la Bassa de les Olles lo convierten en un punto de partida ideal para explorar el norte del parque.","EN":"L'Ampolla is the first delta village for those coming from Barcelona: 'the gateway to the delta'. Originally a roadside inn on the Tortosa to Valencia road, it grew with fishing into a small but charming fishing village. Cap Roig (Blue Flag), les Avellanes and la Bassa de les Olles make it an ideal base for exploring the north of the park.","FR":"L'Ampolla est le premier village du delta pour ceux qui viennent de Barcelone : 'la porte du delta'. Ancienne auberge sur la route de Tortosa à Valence, il a grandi avec la pêche pour devenir un petit village de pêcheurs très charmant. Cap Roig (Pavillon Bleu), les Avellanes et la Bassa de les Olles en font un point de départ idéal pour explorer le nord du parc.","DE":"L'Ampolla ist das erste Deltadorf für diejenigen, die aus Barcelona kommen: 'das Tor zum Delta'. Ursprünglich ein Gasthof an der Straße von Tortosa nach Valencia, wuchs es mit der Fischerei zu einem kleinen, aber charmanten Fischerdorf. Cap Roig (Blaue Flagge), les Avellanes und la Bassa de les Olles machen es zum idealen Ausgangspunkt für die Erkundung des Nordteils des Parks.","NL":"L'Ampolla is het eerste deltadorp voor wie vanuit Barcelona komt: 'de toegangspoort van de delta'. Oorspronkelijk een herberg aan de weg van Tortosa naar Valencia, groeide het met de visserij uit tot een klein maar charmant visserdorp. Cap Roig (Blauwe Vlag), les Avellanes en la Bassa de les Olles maken het tot een ideaal vertrekpunt voor het verkennen van het noorden van het park.","PT":"L'Ampolla é a primeira vila do delta para quem vem de Barcelona: 'a porta do delta'. Antiga estalagem na estrada de Tortosa a Valência, cresceu com a pesca até se tornar uma pequena vila piscatória de grande encanto. Cap Roig (Bandeira Azul), les Avellanes e a Bassa de les Olles tornam-na um ponto de partida ideal para explorar o norte do parque."},"lat":40.806,"lng":0.7},{"name":{"CA":"Poblenou del Delta","ES":"Poblenou del Delta","EN":"Poblenou del Delta","FR":"Poblenou del Delta","DE":"Poblenou del Delta","NL":"Poblenou del Delta","PT":"Poblenou del Delta"},"tagline":{"CA":"El poble blanc al cor de les llacunes","ES":"El pueblo blanco en el corazón de las lagunas","EN":"The white village at the heart of the lagoons","FR":"Le village blanc au cœur des lagunes","DE":"Das weiße Dorf im Herzen der Lagunen","NL":"Het witte dorp in het hart van de lagunes","PT":"A vila branca no coração das lagoas"},"lead":{"CA":"Poblenou del Delta és el poble més interior del hemidelta sud i un dels més fotogènics del delta. Amb els seus carrers empedrats i cases blanques, rodejat de la Encanyissada i la Tancada, és el punt ideal per al birdwatching, la bici i la gastronomia tranquil·la.","ES":"Poblenou del Delta es el pueblo más interior del hemidelta sur y uno de los más fotogénicos del delta. Con sus calles empedradas y casas blancas, rodeado de la Encanyissada y la Tancada, es el punto ideal para el birdwatching, la bici y la gastronomía tranquila.","EN":"Poblenou del Delta is the most inland village in the south hemidelta and one of the most photogenic in the delta. With its cobbled streets and white houses, surrounded by l'Encanyissada and la Tancada, it is the ideal spot for birdwatching, cycling and unhurried gastronomy.","FR":"Poblenou del Delta est le village le plus intérieur de l'hémidelta sud et l'un des plus photogéniques du delta. Avec ses rues pavées et ses maisons blanches, entouré de l'Encanyissada et de la Tancada, c'est le point idéal pour le birdwatching, le vélo et une gastronomie tranquille.","DE":"Poblenou del Delta ist das am weitesten im Landesinneren gelegene Dorf des Südhemideltas und eines der fotogensten im Delta. Mit seinen gepflasterten Straßen und weißen Häusern, umgeben von Encanyissada und Tancada, ist es der ideale Punkt für Vogelbeobachtung, Radfahren und entspannte Gastronomie.","NL":"Poblenou del Delta is het meest binnenlandse dorp in het zuidhemidelta en een van de meest fotogenieke in de delta. Met zijn geplaveide straten en witte huizen, omgeven door Encanyissada en Tancada, is het het ideale punt voor vogelspotten, fietsen en rustige gastronomie.","PT":"Poblenou del Delta é a vila mais interior do hemidelta sul e uma das mais fotogénicas do delta. Com as suas ruas empedradas e casas brancas, rodeada pela Encanyissada e a Tancada, é o ponto ideal para o birdwatching, a bicicleta e a gastronomia tranquila."},"lat":40.656,"lng":0.68},{"name":{"CA":"Alcanar i les Cases (fora del Delta)","ES":"Alcanar y les Cases (fuera del Delta)","EN":"Alcanar and les Cases (outside the Delta)","FR":"Alcanar et les Cases (hors du delta)","DE":"Alcanar und les Cases (außerhalb des Deltas)","NL":"Alcanar en les Cases (buiten de delta)","PT":"Alcanar e les Cases (fora do Delta)"},"tagline":{"CA":"L'últim poble de Catalunya, langostins i cítrics","ES":"El último pueblo de Cataluña, langostinos y cítricos","EN":"Catalonia's southernmost village, prawns and citrus","FR":"Le dernier village de Catalogne, crevettes et agrumes","DE":"Kataloniens südlichstes Dorf, Garnelen und Zitrusfrüchte","NL":"Het meest zuidelijke dorp van Catalonië, garnalen en citrus","PT":"A vila mais a sul da Catalunha, gambão e citrinos"},"lead":{"CA":"Alcanar és el municipi més al sud de Catalunya, just a la frontera amb el País Valencià. El seu barri de pescadors, les Cases d'Alcanar, té una de les Banderes Blaves més antigues del delta (des del 1994). Famós pels seus langostins, les cítrics amb IGP i les platges entre penya-segats i pinars.","ES":"Alcanar es el municipio más al sur de Cataluña, justo en la frontera con el País Valenciano. Su barrio de pescadores, les Cases d'Alcanar, tiene una de las Banderas Azules más antiguas del delta (desde 1994). Famoso por sus langostinos, los cítricos con IGP y las playas entre acantilados y pinares.","EN":"Alcanar is Catalonia's southernmost municipality, right on the border with the País Valencià. Its fishing quarter, les Cases d'Alcanar, has one of the delta's oldest Blue Flags (since 1994). Famous for its prawns, IGP-certified citrus fruit and beaches between cliffs and pine groves.","FR":"Alcanar est la commune la plus au sud de Catalogne, juste à la frontière avec le País Valencià. Son quartier de pêcheurs, les Cases d'Alcanar, possède l'un des Pavillons Bleus les plus anciens du delta (depuis 1994). Célèbre pour ses crevettes, ses agrumes IGP et ses plages entre falaises et pinèdes.","DE":"Alcanar ist die südlichste Gemeinde Kataloniens, direkt an der Grenze zum País Valencià. Sein Fischerviertel, les Cases d'Alcanar, hat eine der ältesten Blauen Flaggen des Deltas (seit 1994). Berühmt für seine Garnelen, IGP-zertifizierte Zitrusfrüchte und Strände zwischen Klippen und Kiefernwäldern.","NL":"Alcanar is de meest zuidelijke gemeente van Catalonië, vlak op de grens met het País Valencià. Zijn visserswijk, les Cases d'Alcanar, heeft een van de oudste Blauwe Vlaggen van de delta (sinds 1994). Beroemd om zijn garnalen, IGP-gecertificeerde citrusvruchten en stranden tussen kliffen en dennenbossen.","PT":"Alcanar é o município mais a sul da Catalunha, mesmo na fronteira com o País Valencià. O seu bairro de pescadores, les Cases d'Alcanar, tem uma das Bandeiras Azuis mais antigas do delta (desde 1994). Famoso pelos seus langostins, os citrinos com IGP e as praias entre penhascos e pinhais."},"lat":40.556,"lng":0.537},{"name":{"CA":"L'Aldea i Camarles","ES":"L'Aldea y Camarles","EN":"L'Aldea and Camarles","FR":"L'Aldea et Camarles","DE":"L'Aldea und Camarles","NL":"L'Aldea en Camarles","PT":"L'Aldea e Camarles"},"tagline":{"CA":"Porta d'entrada nord al delta","ES":"Puerta de entrada norte al delta","EN":"Northern gateway to the delta","FR":"Porte d'entrée nord du delta","DE":"Nördliches Eingangstor zum Delta","NL":"Noordelijke toegangspoort tot de delta","PT":"Porta de entrada norte do delta"},"lead":{"CA":"L'Aldea és el primer nucli urbà que trobareu venint de Tarragona o Barcelona pel corredor litoral. Disposa d'estació de tren (L'Aldea-Amposta-Tortosa) i és el punt d'accés al pont de l'Ebre que connecta amb Amposta i el hemidelta sud. Camarles, al seu costat, és un tranquil poble agrícola amb excel·lents miradories sobre els arrossars i l'orella de l'Ebre.","ES":"L'Aldea es el primer núcleo urbano que encontraréis llegando desde Tarragona o Barcelona por el corredor litoral. Dispone de estación de tren (L'Aldea-Amposta-Tortosa) y es el punto de acceso al puente del Ebro que conecta con Amposta y el hemidelta sur. Camarles, a su lado, es un tranquilo pueblo agrícola con excelentes miradores sobre los arrozales y la orilla del Ebro.","EN":"L'Aldea is the first town you encounter arriving from Tarragona or Barcelona along the coastal corridor. It has a train station (L'Aldea-Amposta-Tortosa) and is the access point to the Ebro bridge linking Amposta and the southern hemidelta. Camarles, next door, is a quiet farming village with excellent viewpoints over the rice fields and the Ebro riverbank.","FR":"L'Aldea est le premier noyau urbain que vous rencontrez en arrivant de Tarragone ou Barcelone par le couloir côtier. Elle dispose d'une gare ferroviaire (L'Aldea-Amposta-Tortosa) et constitue le point d'accès au pont de l'Èbre reliant Amposta et l'hémidelta sud. Camarles, à côté, est un village agricole tranquille offrant d'excellents points de vue sur les rizières et les rives de l'Èbre.","DE":"L'Aldea ist die erste Stadt, die Sie treffen, wenn Sie von Tarragona oder Barcelona über den Küstenkorridor anreisen. Sie verfügt über einen Bahnhof (L'Aldea-Amposta-Tortosa) und ist der Zugangspunkt zur Ebre-Brücke, die Amposta und das südliche Hemidelta verbindet. Camarles, nebenan, ist ein ruhiges Bauerndorf mit hervorragenden Aussichtspunkten über die Reisfelder und das Ufer des Ebro.","NL":"L'Aldea is de eerste stad die u tegenkomt vanuit Tarragona of Barcelona via de kustcorridor. Het heeft een treinstation (L'Aldea-Amposta-Tortosa) en is het toegangspunt tot de Ebre-brug die Amposta en het zuidelijke hemidelta verbindt. Camarles, ernaast, is een rustig landbouwdorp met uitstekende uitkijkpunten over de rijstvelden en de oever van de Ebre.","PT":"L'Aldea é o primeiro núcleo urbano que encontrará chegando de Tarragona ou Barcelona pelo corredor litoral. Tem estação de comboio (L'Aldea-Amposta-Tortosa) e é o ponto de acesso à ponte do Ebro que liga Amposta e o hemidelta sul. Camarles, ao lado, é uma tranquila aldeia agrícola com excelentes miradouros sobre os campos de arroz e a margem do Ebro."},"lat":40.773,"lng":0.613}];;

export const D_HIST = [{"name":{"CA":"Pirates i corsaris al delta","ES":"Piratas y corsarios en el delta","EN":"Pirates and corsairs in the delta","FR":"Pirates et corsaires dans le delta","DE":"Piraten und Korsaren im Delta","NL":"Piraten en kapers in de delta","PT":"Piratas e corsários no delta"},"tagline":{"CA":"Quan la badia dels Alfacs era el terror de la Mediterrània","ES":"Cuando la bahía de los Alfacs era el terror del Mediterráneo","EN":"When the Alfacs bay was the terror of the Mediterranean","FR":"Quand la baie des Alfacs était la terreur de la Méditerranée","DE":"Als die Alfacs-Bucht der Terror des Mittelmeers war","NL":"Toen de Alfacs-baai de terreur van de Middellandse Zee was","PT":"Quando a baía dos Alfacs era o terror do Mediterrâneo"},"lead":{"CA":"Durant els segles XVI i XVII, el delta de l'Ebre vivia sota l'amenaça constant dels corsaris berbèrs i sarraïns, procedents d'Alger, Tunis i Trípoli. La badia dels Alfacs —enorme, protegida i ben proveïda d'aigua dolça, sal i aliments— era per a ells el port perfecte des d'on atacar la costa catalana i valenciana. L'enginyer reial Cristobal Antonelli ho va resumir el 1580 amb una frase demolidora: «Este sitio es como estar junto a Argel».","ES":"Durante los siglos XVI y XVII, el delta del Ebro vivía bajo la amenaza constante de los corsarios berberiscos y sarracenos, procedentes de Argel, Túnez y Trípoli. La bahía de los Alfacs —enorme, protegida y bien provista de agua dulce, sal y alimentos— era para ellos el puerto perfecto desde donde atacar la costa catalana y valenciana. El ingeniero real Cristobal Antonelli lo resumió en 1580 con una frase demoledora: «Este sitio es como estar junto a Argel».","EN":"During the 16th and 17th centuries, the Ebro Delta lived under constant threat from Berber and Saracen corsairs from Algiers, Tunis and Tripoli. The Alfacs bay — vast, sheltered and well supplied with fresh water, salt and food — was for them the perfect port from which to raid the Catalan and Valencian coasts. The royal engineer Cristobal Antonelli summed it up in 1580 with a devastating phrase: «This place is like being next to Algiers».","FR":"Aux XVIe et XVIIe siècles, le delta de l'Èbre vivait sous la menace constante des corsaires berbères et sarrasins d'Alger, Tunis et Tripoli. La baie des Alfacs était pour eux le port parfait pour attaquer les côtes catalanes et valencienne. L'ingénieur royal Cristobal Antonelli le résuma en 1580: «Cet endroit, c'est comme être à côté d'Alger».","DE":"Im 16. und 17. Jahrhundert lebte das Ebro-Delta unter ständiger Bedrohung durch berberische und sarazenische Korsaren aus Algier, Tunis und Tripolis. Die Alfacs-Bucht war für sie der perfekte Hafen, um die katalanische und valencianische Küste zu überfallen. Königlicher Ingenieur Cristobal Antonelli fasste es 1580 zusammen: «Dieser Ort ist wie neben Algier zu sein».","NL":"In de 16e en 17e eeuw leefde de Ebro-delta onder de constante dreiging van Berberse en Saracenische kapers uit Algiers, Tunis en Tripoli. De Alfacs-baai was voor hen de perfecte haven om de Catalaanse en Valenciaanse kust te overvallen. Koninklijk ingenieur Cristobal Antonelli vatte het in 1580 samen: «Deze plek is als naast Algiers zijn».","PT":"Durante os séculos XVI e XVII, o delta do Ebro vivia sob ameaça constante dos corsários berberes e sarracenos de Argel, Tunes e Trípoli. A baía dos Alfacs era para eles o porto perfeito para atacar as costas catalã e valenciana. O engenheiro real Cristobal Antonelli resumiu em 1580: «Este sítio é como estar ao lado de Argel»."}},{"name":{"CA":"Port Fangós: quan el delta era la porta del Mediterrani","ES":"Port Fangós: cuando el delta era la puerta del Mediterráneo","EN":"Port Fangós: when the delta was the gateway to the Mediterranean","FR":"Port Fangós: quand le delta était la porte de la Méditerranée","DE":"Port Fangós: Als das Delta das Tor zum Mittelmeer war","NL":"Port Fangós: toen de delta de poort naar de Middellandse Zee was","PT":"Port Fangós: quando o delta era a porta para o Mediterrâneo"},"tagline":{"CA":"El port militar més important de la Corona d'Aragó va estar aquí","ES":"El puerto militar más importante de la Corona de Aragón estuvo aquí","EN":"The Crown of Aragon's most important military port was right here","FR":"Le port militaire le plus important de la Couronne d'Aragon était ici","DE":"Der wichtigste Militärhafen der Krone Aragoniens war hier","NL":"De belangrijkste militaire haven van de Kroon van Aragon was hier","PT":"O porto militar mais importante da Coroa de Aragão estava aqui"},"lead":{"CA":"Avui, quan mirem les llacunes i els arrossars del delta nord, és difícil imaginar que allà on ara hi ha silenci i flamencs, els segles XIII i XIV hi havia un dels ports militars més importants del Mediterrani occidental. El Port Fangós, que ocupava part dels actuals municipis de Sant Jaume d'Enveja i Deltebre, va ser l'escenari des d'on va partir la gran expansió mediterrània de la Corona d'Aragó: Sicília, Sardenya, Grècia, Atenes.","ES":"Hoy, cuando miramos las lagunas y los arrozales del delta norte, es difícil imaginar que donde ahora hay silencio y flamencos, en los siglos XIII y XIV había uno de los puertos militares más importantes del Mediterráneo occidental. El Port Fangós, que ocupaba parte de los actuales municipios de Sant Jaume d'Enveja y Deltebre, fue el escenario desde donde partió la gran expansión mediterránea de la Corona de Aragón: Sicilia, Cerdeña, Grecia, Atenas.","EN":"Today, looking out over the lagoons and rice fields of the northern delta, it is hard to imagine that where silence and flamingos now reign, in the 13th and 14th centuries one of the most important military ports in the western Mediterranean stood here. Port Fangós, occupying parts of what are now Sant Jaume d'Enveja and Deltebre, was the launching pad for the Crown of Aragon's great Mediterranean expansion: Sicily, Sardinia, Greece, Athens.","FR":"Aujourd'hui, en regardant les lagunes et les rizières du delta nord, il est difficile d'imaginer que là où règnent maintenant le silence et les flamants, aux XIIIe et XIVe siècles se trouvait l'un des ports militaires les plus importants de la Méditerranée occidentale. Port Fangós, occupant une partie des actuelles communes de Sant Jaume d'Enveja et Deltebre, fut la rampe de lancement de l'expansion méditerranéenne de la Couronne d'Aragon.","DE":"Heute, wenn wir über die Lagunen und Reisfelder des nördlichen Deltas blicken, ist es schwer vorstellbar, dass dort, wo jetzt Stille und Flamingos herrschen, im 13. und 14. Jahrhundert einer der wichtigsten Militärhäfen des westlichen Mittelmeers stand. Port Fangós, das Teile der heutigen Gemeinden Sant Jaume d'Enveja und Deltebre einnahm, war das Sprungbrett für die mediterrane Expansion der Krone Aragoniens.","NL":"Vandaag, als we over de lagunes en rijstvelden van de noordelijke delta kijken, is het moeilijk voor te stellen dat daar waar nu stilte en flamingo's heersen, in de 13e en 14e eeuw een van de belangrijkste militaire havens van de westelijke Middellandse Zee stond. Port Fangós, dat delen van de huidige gemeenten Sant Jaume d'Enveja en Deltebre besloeg, was het startpunt van de mediterrane expansie van de Kroon van Aragon.","PT":"Hoje, olhando para as lagoas e arrozais do delta norte, é difícil imaginar que onde agora reina o silêncio e os flamingos, nos séculos XIII e XIV existia um dos mais importantes portos militares do Mediterrâneo ocidental. Port Fangós, ocupando partes dos atuais municípios de Sant Jaume d'Enveja e Deltebre, foi a rampa de lançamento da expansão mediterrânica da Coroa de Aragão."}},{"name":{"CA":"Carles III i el gran projecte que no va ser","ES":"Carlos III y el gran proyecto que no fue","EN":"Charles III and the great project that never was","FR":"Charles III et le grand projet qui ne fut pas","DE":"Karl III. und das große Projekt, das nie war","NL":"Karel III en het grote project dat er nooit kwam","PT":"Carlos III e o grande projeto que não foi"},"tagline":{"CA":"La Ràpita hauria d'haver sigut la Cartagena catalana","ES":"La Ràpita debería haber sido la Cartagena catalana","EN":"La Ràpita was meant to be the Catalan Cartagena","FR":"La Ràpita aurait dû être la Carthagène catalane","DE":"La Ràpita hätte das katalanische Cartagena werden sollen","NL":"La Ràpita had het Catalaanse Cartagena moeten worden","PT":"La Ràpita devia ter sido a Cartagena catalã"},"lead":{"CA":"El 1780, Sant Carles de la Ràpita era una aldea de pescadors amb poc més d'una dotzena de cases. Carles III hi veia el futur: el lloc perfecte per construir una enorme base naval —la 'Cartagena catalana'— que dominés el Mediterrani occidental. Uns pocs anys de febrils obres i milers de jornalers van fer créixer el poble. Però el rei va morir el 1788 i el projecte es va abandonar. El port militar mai no es va acabar. L'únic llegat visible: un poble de traçat racional i elegant en mig del delta.","ES":"En 1780, Sant Carles de la Ràpita era una aldea de pescadores con poco más de una docena de casas. Carlos III veía allí el futuro: el lugar perfecto para construir una enorme base naval —la 'Cartagena catalana'— que dominara el Mediterráneo occidental. Unos pocos años de febriles obras y miles de jornaleros hicieron crecer el pueblo. Pero el rey murió en 1788 y el proyecto se abandonó. El puerto militar nunca se acabó. El único legado visible: un pueblo de trazado racional y elegante en medio del delta.","EN":"In 1780, Sant Carles de la Ràpita was a fishing hamlet of barely a dozen houses. Charles III saw the future there: the perfect spot for a vast naval base — the 'Catalan Cartagena' — that would dominate the western Mediterranean. A few years of feverish construction and thousands of day labourers made the village grow. But the king died in 1788 and the project was abandoned. The military port was never completed. The only visible legacy: a town of rational, elegant grid design in the middle of the delta.","FR":"En 1780, Sant Carles de la Ràpita était un hameau de pêcheurs d'une douzaine de maisons. Charles III y voyait l'avenir: l'endroit parfait pour une immense base navale — la 'Carthagène catalane' — qui dominerait la Méditerranée occidentale. Quelques années de travaux frénétiques firent grandir le village. Mais le roi mourut en 1788 et le projet fut abandonné. Le port militaire ne fut jamais achevé. Le seul héritage visible: une ville au plan rationnel et élégant au milieu du delta.","DE":"1780 war Sant Carles de la Ràpita ein Fischerdorf mit kaum einem Dutzend Häusern. Karl III. sah die Zukunft dort: der perfekte Ort für eine riesige Marinebasis — das 'katalanische Cartagena' — die das westliche Mittelmeer beherrschen würde. Einige Jahre fieberhafter Bauarbeiten ließen das Dorf wachsen. Aber der König starb 1788 und das Projekt wurde aufgegeben. Der Militärhafen wurde nie fertiggestellt. Das einzig sichtbare Erbe: eine Stadt mit rationalem, elegantem Grundriss mitten im Delta.","NL":"In 1780 was Sant Carles de la Ràpita een vissersdorp van nauwelijks een dozijn huizen. Karel III zag de toekomst er: de perfecte plek voor een enorme marinebasis — het 'Catalaanse Cartagena' — die de westelijke Middellandse Zee zou domineren. Enkele jaren koortsachtige bouw lieten het dorp groeien. Maar de koning stierf in 1788 en het project werd opgegeven. De militaire haven werd nooit voltooid. De enige zichtbare erfenis: een stad met een rationeel, elegant stadsplan midden in de delta.","PT":"Em 1780, Sant Carles de la Ràpita era uma aldeia de pescadores com pouco mais de uma dúzia de casas. Carlos III via ali o futuro: o local perfeito para uma enorme base naval — a 'Cartagena catalã' — que dominaria o Mediterrâneo ocidental. Alguns anos de obras febris e milhares de jornaleiros fizeram crescer a aldeia. Mas o rei morreu em 1788 e o projeto foi abandonado. O porto militar nunca foi concluído. O único legado visível: uma cidade de traçado racional e elegante no meio do delta."}},{"name":{"CA":"La conquesta de l'arròs: com va néixer el delta d'avui","ES":"La conquista del arroz: cómo nació el delta de hoy","EN":"The rice conquest: how today's delta was born","FR":"La conquête du riz: comment naquit le delta d'aujourd'hui","DE":"Die Reiseroberung: Wie das heutige Delta entstand","NL":"De rijstverovering: hoe het huidige delta ontstond","PT":"A conquista do arroz: como nasceu o delta de hoje"},"tagline":{"CA":"Abans de l'arròs, el delta era una terra erma de por i paludisme","ES":"Antes del arroz, el delta era una tierra yerma de miedo y paludismo","EN":"Before rice, the delta was a wasteland of fear and malaria","FR":"Avant le riz, le delta était une terre déserte de peur et de paludisme","DE":"Vor dem Reis war das Delta ein Ödland aus Angst und Malaria","NL":"Vóór de rijst was de delta een woestenij van angst en malaria","PT":"Antes do arroz, o delta era uma terra erma de medo e malária"},"lead":{"CA":"Costa molt d'imaginar-ho, però el paisatge verd i ordenat d'arrossars que avui defineix el delta és obra dels últims 150 anys. Abans de 1860, el delta era una immensitat de terres ermes, aiguamolls i llacunes. La gent hi vivia miserablement de la caça, la pesca, la sal, i del cultiu de la sosa i la regalèssia a les vores del riu. La malària —'la passa'— era endèmica. Gairebé ningú volia viure al delta. El canvi va arribar amb l'obertura dels canals de reg.","ES":"Cuesta mucho imaginarlo, pero el paisaje verde y ordenado de arrozales que hoy define el delta es obra de los últimos 150 años. Antes de 1860, el delta era una inmensidad de tierras yermas, marismas y lagunas. La gente vivía miserablemente de la caza, la pesca, la sal, y del cultivo de la sosa y la regaliz a las orillas del río. La malaria —'la passa'— era endémica. Casi nadie quería vivir en el delta. El cambio llegó con la apertura de los canales de riego.","EN":"It is hard to imagine, but the green, ordered landscape of rice fields that defines the delta today is the work of the last 150 years. Before 1860, the delta was a vast expanse of wasteland, marshes and lagoons. People lived miserably off hunting, fishing, salt, and cultivating soda ash and liquorice on the riverbanks. Malaria — 'la passa' — was endemic. Almost nobody wanted to live in the delta. The change came with the opening of irrigation canals.","FR":"Il est difficile de l'imaginer, mais le paysage vert et ordonné de rizières qui définit aujourd'hui le delta est l'œuvre des 150 dernières années. Avant 1860, le delta était une immensité de terres arides, de marais et de lagunes. Les gens vivaient misérablement de la chasse, de la pêche, du sel et de la culture de la soude et de la réglisse. La malaria était endémique. Presque personne ne voulait vivre dans le delta. Le changement vint avec l'ouverture des canaux d'irrigation.","DE":"Es ist schwer vorstellbar, aber die grüne, geordnete Reisfeldlandschaft, die das Delta heute prägt, ist das Werk der letzten 150 Jahre. Vor 1860 war das Delta eine riesige Ödlandschaft aus Sümpfen und Lagunen. Die Menschen lebten kümmerlich von Jagd, Fischerei, Salz und dem Anbau von Soda und Süßholz. Malaria war endemisch. Fast niemand wollte im Delta leben. Die Veränderung kam mit der Öffnung der Bewässerungskanäle.","NL":"Het is moeilijk voor te stellen, maar het groene, geordende rijstveldlandschap dat de delta vandaag definieert, is het werk van de laatste 150 jaar. Vóór 1860 was de delta een uitgestrektheid van woestenij, moerassen en lagunes. Mensen leefden armzalig van jacht, visserij, zout en het verbouwen van soda en zoethout. Malaria was endemisch. Bijna niemand wilde in de delta wonen. De verandering kwam met de opening van irrigatiekanalen.","PT":"É difícil de imaginar, mas a paisagem verde e ordenada de arrozais que hoje define o delta é obra dos últimos 150 anos. Antes de 1860, o delta era uma imensidão de terras ermas, pântanos e lagoas. As pessoas viviam miseravelmente da caça, pesca, sal e do cultivo de soda e alcaçuz. A malária — 'la passa' — era endémica. Quase ninguém queria viver no delta. A mudança chegou com a abertura dos canais de rega."}},{"name":{"CA":"La Batalla de l'Ebre: 115 dies que van canviar Espanya","ES":"La Batalla del Ebro: 115 días que cambiaron España","EN":"The Battle of the Ebro: 115 days that changed Spain","FR":"La Bataille de l'Èbre: 115 jours qui changèrent l'Espagne","DE":"Die Ebro-Schlacht: 115 Tage, die Spanien veränderten","NL":"De Slag om de Ebro: 115 dagen die Spanje veranderden","PT":"A Batalha do Ebro: 115 dias que mudaram Espanha"},"tagline":{"CA":"La batalla més llarga i sagnant de la Guerra Civil va tenir lloc aquí","ES":"La batalla más larga y sangrienta de la Guerra Civil tuvo lugar aquí","EN":"The longest and bloodiest battle of the Civil War took place here","FR":"La bataille la plus longue et la plus sanglante de la Guerre Civile eut lieu ici","DE":"Die längste und blutigste Schlacht des Bürgerkriegs fand hier statt","NL":"De langste en bloedigste slag van de Burgeroorlog vond hier plaats","PT":"A batalha mais longa e sangrenta da Guerra Civil aconteceu aqui"},"lead":{"CA":"A les 00:15 h del 25 de juliol de 1938, una nit sense lluna, sis mil soldats republicans van creuar el riu Ebre en silenci. Sobre pasadores fràgils de suro, a bord de barques de pesca i ajudats per mules, van travessar el riu entre Amposta i Mequinensa sense que l'enemic franquista se n'adonés. Estava a punt de començar la operació militar més gran de la Guerra Civil espanyola, i la batalla que la sellaria: 115 dies d'infern entre els arrossars, la pedra dels ports de Tortosa-Beseit i el fang de l'Ebre. Quan va acabar, el balanç era esgarrifós: 30.000 morts, 75.000 ferits i 15.000 presoners.","ES":"A las 00:15 h del 25 de julio de 1938, una noche sin luna, seis mil soldados republicanos cruzaron el río Ebro en silencio. Sobre pasarelas frágiles de corcho, a bordo de barcas de pesca y ayudados por mulas, cruzaron el río entre Amposta y Mequinenza sin que el enemigo franquista se diera cuenta. Estaba a punto de comenzar la operación militar más grande de la Guerra Civil española, y la batalla que la sellaría: 115 días de infierno entre los arrozales, la piedra de los puertos de Tortosa-Beseit y el barro del Ebro. Cuando acabó, el balance era escalofriante: 30.000 muertos, 75.000 heridos y 15.000 prisioneros.","EN":"At 00:15 on 25 July 1938, on a moonless night, six thousand Republican soldiers crossed the Ebro in silence. On fragile cork floats, in fishing boats and helped by mules, they crossed the river between Amposta and Mequinensa without the Francoist enemy noticing. The largest military operation of the Spanish Civil War was about to begin, and the battle that would seal its fate: 115 days of hell among the rice fields, the stone of the Tortosa-Beseit mountain passes and the mud of the Ebro. When it ended, the toll was horrifying: 30,000 dead, 75,000 wounded and 15,000 prisoners.","FR":"À 00h15 le 25 juillet 1938, par une nuit sans lune, six mille soldats républicains traversèrent l'Ebro en silence. Sur de fragiles radeaux de liège, à bord de barques de pêche, aidés par des mules, ils traversèrent le fleuve entre Amposta et Mequinensa sans que l'ennemi franquiste ne s'en aperçoive. La plus grande opération militaire de la Guerre Civile espagnole allait commencer: 115 jours d'enfer. Bilan: 30 000 morts, 75 000 blessés et 15 000 prisonniers.","DE":"Um 00:15 Uhr des 25. Juli 1938, in einer mondlosen Nacht, überquerten 6.000 republikanische Soldaten den Ebro im Stillen. Die größte Militäroperation des Spanischen Bürgerkriegs begann: 115 Tage Hölle. Bilanz: 30.000 Tote, 75.000 Verwundete und 15.000 Gefangene.","NL":"Om 00:15 uur op 25 juli 1938, in een maanloze nacht, staken 6.000 republikeinse soldaten de Ebro in stilte over. De grootste militaire operatie van de Spaanse Burgeroorlog begon: 115 dagen hel. Eindstand: 30.000 doden, 75.000 gewonden en 15.000 gevangenen.","PT":"À 00h15 do dia 25 de julho de 1938, numa noite sem lua, seis mil soldados republicanos atravessaram o Ebro em silêncio. A maior operação militar da Guerra Civil espanhola começou: 115 dias de inferno. Balanço: 30.000 mortos, 75.000 feridos e 15.000 prisioneiros."}}];

export const D_BICI = [{"id":"r1","name":{"CA":"Ruta de les Llacunes (hemidelta sud)","ES":"Ruta de las Lagunas (hemidelta sur)","EN":"Lagoon Route (south hemidelta)","FR":"Route des Lagunes (hémidelta sud)","DE":"Lagunenroute (Südhemidelta)","NL":"Laguneroute (zuidhemidelta)","PT":"Rota das Lagoas (hemidelta sul)"},"tagline":{"CA":"Circuit familiar clàssic: Encanyissada, Trabucador i Tancada","ES":"Circuito familiar clásico: Encanyissada, Trabucador y Tancada","EN":"Classic family loop: Encanyissada, Trabucador and Tancada","FR":"Circuit familial classique : Encanyissada, Trabucador et Tancada","DE":"Klassische Familienrunde: Encanyissada, Trabucador und Tancada","NL":"Klassieke gezinsronde: Encanyissada, Trabucador en Tancada","PT":"Circuito familiar clássico: Encanyissada, Trabucador e Tancada"},"desc":{"CA":"La ruta estrella del hemidelta sud. Circuit completament pla que recorre les dues grans llacunes del delta —l'Encanyissada i la Tancada— i arriba fins al Trabucador, la barra de sorra on el Mediterrani i la badia dels Alfacs es troben. Flamencos garantits, arrossars a dreta i esquerra i alguns dels millors miradors de la Tancada a últim hora de la tarda.","ES":"La ruta estrella del hemidelta sur. Circuito completamente llano que recorre las dos grandes lagunas del delta —la Encanyissada y la Tancada— y llega hasta el Trabucador, la barra de arena donde el Mediterráneo y la bahía de los Alfacs se encuentran. Flamencos garantizados, arrozales a derecha e izquierda y algunos de los mejores miradores de la Tancada a última hora de la tarde.","EN":"The star route of the south hemidelta. A completely flat circuit running through the delta's two great lagoons — l'Encanyissada and la Tancada — reaching El Trabucador, the sandbar where the Mediterranean and Alfacs bay meet. Flamingos guaranteed, rice fields on both sides and some of the best Tancada viewpoints in the late afternoon.","FR":"Le circuit star de l'hémidelta sud. Parfaitement plat, il parcourt les deux grandes lagunes du delta — l'Encanyissada et la Tancada — jusqu'au Trabucador, la barre de sable où la Méditerranée et la baie des Alfacs se rejoignent.","DE":"Die Sternenroute des Südhemideltas. Komplett flache Runde durch die zwei großen Lagunen — Encanyissada und Tancada — bis zum Trabucador, der Sandbank wo das Mittelmeer und die Alfacs-Bucht aufeinandertreffen.","NL":"De sterroute van het zuidhemidelta. Volledig vlakke ronde door de twee grote lagunes — Encanyissada en Tancada — tot El Trabucador, de zandbank waar de Middellandse Zee en de Alfacs-baai elkaar ontmoeten.","PT":"A rota estrela do hemidelta sul. Circuito completamente plano que percorre as duas grandes lagoas do delta — Encanyissada e Tancada — chegando ao Trabucador, a barra de areia onde o Mediterrâneo e a baía dos Alfacs se encontram."},"dist":"32 km","time":"2-3h","diff":{"CA":"Fàcil","ES":"Fácil","EN":"Easy","FR":"Facile","DE":"Leicht","NL":"Makkelijk","PT":"Fácil"},"elev":"15m ↑","type":"circuit","start":{"CA":"Casa de Fusta (Amposta) o Poblenou del Delta","ES":"Casa de Fusta (Amposta) o Poblenou del Delta","EN":"Casa de Fusta (Amposta) or Poblenou del Delta","FR":"Casa de Fusta (Amposta) ou Poblenou del Delta","DE":"Casa de Fusta (Amposta) oder Poblenou del Delta","NL":"Casa de Fusta (Amposta) of Poblenou del Delta","PT":"Casa de Fusta (Amposta) ou Poblenou del Delta"},"tip":{"CA":"Fes la primera part al matí (lagunes i flamencos) i la tarda al Trabucador. Lloguer de bici a la Casa de Fusta i a Amposta (Deltaventur).","ES":"Haz la primera parte por la mañana (lagunas y flamencos) y la tarde en el Trabucador. Alquiler de bici en la Casa de Fusta y en Amposta (Deltaventur).","EN":"Do the first part in the morning (lagoons and flamingos) and the afternoon at El Trabucador. Bike hire at Casa de Fusta and in Amposta (Deltaventur).","FR":"Faites la première partie le matin (lagunes et flamants) et l'après-midi au Trabucador. Location de vélo à la Casa de Fusta et à Amposta (Deltaventur).","DE":"Den ersten Teil morgens (Lagunen und Flamingos) und nachmittags am Trabucador machen. Fahrradverleih bei Casa de Fusta und in Amposta (Deltaventur).","NL":"De eerste ochtend (lagunes en flamingo's) en de middag bij El Trabucador. Fietsverhuur bij Casa de Fusta en in Amposta (Deltaventur).","PT":"Faz a primeira parte de manhã (lagoas e flamingos) e a tarde no Trabucador. Aluguer de bici na Casa de Fusta e em Amposta (Deltaventur)."},"lat":40.665,"lng":0.68},{"id":"r2","name":{"CA":"Deltebre · Riumar · Garxal · Far","ES":"Deltebre · Riumar · Garxal · Faro","EN":"Deltebre · Riumar · Garxal · Lighthouse","FR":"Deltebre · Riumar · Garxal · Phare","DE":"Deltebre · Riumar · Garxal · Leuchtturm","NL":"Deltebre · Riumar · Garxal · Vuurtoren","PT":"Deltebre · Riumar · Garxal · Farol"},"tagline":{"CA":"La ruta més popular del nord: arrossars, desembocadura i el far del Garxal","ES":"La ruta más popular del norte: arrozales, desembocadura y el faro del Garxal","EN":"The north's most popular route: rice fields, river mouth and the Garxal lighthouse","FR":"La route la plus populaire du nord : rizières, embouchure et phare du Garxal","DE":"Die beliebteste Route im Norden: Reisfelder, Flussmündung und Garxal-Leuchtturm","NL":"De populairste route in het noorden: rijstvelden, riviermonding en vuurtoren Garxal","PT":"A rota mais popular do norte: arrozais, desembocadura e o farol do Garxal"},"desc":{"CA":"La ruta ciclista número 2 oficial del Parc Natural és la preferida dels visitants del nord. Surt de l'Ecomuseu, baixa pel Passeig Fluvial fins al Canal Vell i arriba a Riumar passant per arrossars interiors. De Riumar, una pista de terra porta fins al far del Garxal i al mirador del Zigurat, amb vistes simultànies a la desembocadura, l'Illa de Buda i les dunes. El 30% del recorregut va per carril bici exclusiu.","ES":"La ruta ciclista número 2 oficial del Parque Natural es la preferida de los visitantes del norte. Sale del Ecomuseo, baja por el Paseo Fluvial hasta el Canal Vell y llega a Riumar pasando por arrozales interiores. De Riumar, una pista lleva hasta el faro del Garxal y el mirador del Zigurat.","EN":"The official Nature Park cycling route number 2 is the favourite of northern visitors. It leaves the Ecomuseum, descends along the Riverside Walk to Canal Vell and reaches Riumar through inland rice fields. From Riumar, a track leads to the Garxal lighthouse and the Zigurat viewpoint, with simultaneous views of the river mouth, Illa de Buda and the dunes.","FR":"La route cycliste officielle n°2 du Parc naturel est la préférée des visiteurs du nord. Elle part de l'Écomusée, descend par la Promenade fluviale jusqu'au Canal Vell et atteint Riumar en passant par des rizières intérieures.","DE":"Die offizielle Fahrradroute Nr. 2 des Naturparks ist die Lieblingsroute der nördlichen Besucher. Sie beginnt am Ecomuseum, führt entlang der Flusspromenade zum Canal Vell und erreicht Riumar durch innere Reisfelder.","NL":"De officiële fietsroute nr. 2 van het Natuurpark is de favoriet van noordelijke bezoekers. Vertrekt bij het Ecomuseum, daalt langs de Rivierboulevard naar Canal Vell en bereikt Riumar via binnenlandse rijstvelden.","PT":"A rota ciclista oficial nº 2 do Parque Natural é a preferida dos visitantes do norte. Sai do Ecomuseu, desce pelo Passeio Fluvial até ao Canal Vell e chega a Riumar passando por arrozais interiores."},"dist":"24 km","time":"2h","diff":{"CA":"Fàcil","ES":"Fácil","EN":"Easy","FR":"Facile","DE":"Leicht","NL":"Makkelijk","PT":"Fácil"},"elev":"10m ↑","type":"circuit","start":{"CA":"Ecomuseu de Deltebre (Av. del Canal)","ES":"Ecomuseo de Deltebre (Av. del Canal)","EN":"Deltebre Ecomuseum (Av. del Canal)","FR":"Écomusée de Deltebre (Av. del Canal)","DE":"Ecomuseum Deltebre (Av. del Canal)","NL":"Ecomuseum Deltebre (Av. del Canal)","PT":"Ecomuseu de Deltebre (Av. del Canal)"},"tip":{"CA":"La pista de terra entre Riumar i el Garxal (uns 3 km) pot ser enfangada al hivern o après de pluja. Si vols evitar-la, queda't a Riumar i torna per la mateixa carretera.","ES":"La pista de tierra entre Riumar y el Garxal (unos 3 km) puede estar enfangada en invierno o después de lluvia. Si quieres evitarla, quédate en Riumar y vuelve por la misma carretera.","EN":"The dirt track between Riumar and el Garxal (about 3 km) can be muddy in winter or after rain. If you want to avoid it, stay at Riumar and return on the same road.","FR":"La piste de terre entre Riumar et el Garxal (environ 3 km) peut être boueuse en hiver ou après la pluie.","DE":"Der Schotterweg zwischen Riumar und el Garxal (ca. 3 km) kann im Winter oder nach Regen schlammig sein.","NL":"Het onverharde pad tussen Riumar en el Garxal (ca. 3 km) kan modderig zijn in de winter of na regen.","PT":"A pista de terra entre Riumar e o Garxal (cerca de 3 km) pode estar enlameada no inverno ou após chuva."},"lat":40.721,"lng":0.83},{"id":"r3","name":{"CA":"Deltebre · Marquesa · Punta del Fangar","ES":"Deltebre · Marquesa · Punta del Fangar","EN":"Deltebre · La Marquesa · Punta del Fangar","FR":"Deltebre · Marquesa · Punta del Fangar","DE":"Deltebre · la Marquesa · Punta del Fangar","NL":"Deltebre · la Marquesa · Punta del Fangar","PT":"Deltebre · la Marquesa · Punta del Fangar"},"tagline":{"CA":"Les dunes més espectaculars de Catalunya i el far","ES":"Las dunas más espectaculares de Cataluña y el faro","EN":"Catalonia's most spectacular dunes and the lighthouse","FR":"Les dunes les plus spectaculaires de Catalogne et le phare","DE":"Kataloniens spektakulärste Dünen und der Leuchtturm","NL":"Katalonië's meest spectaculaire duinen en de vuurtoren","PT":"As dunas mais espetaculares da Catalunha e o farol"},"desc":{"CA":"De Deltebre a la platja de la Marquesa en bici (uns 10 km d'asfalt i camí de terra), i des de la Marquesa fins a la Punta del Fangar a peu (4 km per la barra de sorra, obligatori a peu per protecció de les dunes). El far del Fangar és un dels paisatges més únics del delta: miralls d'arena, miratges i dunes vives. Compte: no hi ha ombra ni aigua al Fangar. Porta provisions.","ES":"De Deltebre a la playa de la Marquesa en bici (unos 10 km de asfalto y camino de tierra), y desde la Marquesa hasta la Punta del Fangar a pie (4 km por la barra de arena, obligatorio a pie). El faro del Fangar: espejos de arena, espejismos y dunas vivas. Atención: no hay sombra ni agua en el Fangar.","EN":"From Deltebre to la Marquesa beach by bike (about 10 km of tarmac and dirt track), then from la Marquesa to Punta del Fangar on foot (4 km along the sandbar, walking is compulsory). The Fangar lighthouse: sand mirrors, mirages and live dunes. Warning: no shade or water at the Fangar. Bring supplies.","FR":"De Deltebre à la plage de la Marquesa à vélo (environ 10 km), puis de la Marquesa à la Punta del Fangar à pied (4 km le long de la barre de sable, obligatoire). Le phare du Fangar : miroirs de sable, mirages et dunes vives.","DE":"Von Deltebre zum Strand la Marquesa mit dem Fahrrad (ca. 10 km), dann von der Marquesa zur Punta del Fangar zu Fuß (4 km entlang der Sandbank, Pflicht). Der Fangar-Leuchtturm: Sandspiegel, Fata Morgana und lebende Dünen.","NL":"Van Deltebre naar strand la Marquesa per fiets (ca. 10 km), dan van la Marquesa naar Punta del Fangar te voet (4 km langs de zandbank, verplicht). De Fangar-vuurtoren: spiegels van zand, luchtspiegelingen en levende duinen.","PT":"De Deltebre à praia da Marquesa de bicicleta (cerca de 10 km), e da Marquesa à Punta del Fangar a pé (4 km pela barra de areia, obrigatório a pé). O farol do Fangar: espelhos de areia, miragens e dunas vivas."},"dist":"28 km","time":"2,5h","diff":{"CA":"Fàcil","ES":"Fácil","EN":"Easy","FR":"Facile","DE":"Leicht","NL":"Makkelijk","PT":"Fácil"},"elev":"10m ↑","type":"retour","start":{"CA":"Deltebre (Ecomuseu) o cotxe fins a Marquesa","ES":"Deltebre (Ecomuseo) o coche hasta la Marquesa","EN":"Deltebre (Ecomuseum) or drive to la Marquesa","FR":"Deltebre (Écomusée) ou voiture jusqu'à la Marquesa","DE":"Deltebre (Ecomuseum) oder mit Auto zur Marquesa","NL":"Deltebre (Ecomuseum) of auto naar la Marquesa","PT":"Deltebre (Ecomuseu) ou de carro até à Marquesa"},"tip":{"CA":"Surt molt d'hora a l'estiu: a les 10h el Fangar ja crema. Porta més d'1 litre d'aigua per persona. Si vas en cotxe fins a la Marquesa, el tram de bici és d'uns 10 km totals.","ES":"Sal muy temprano en verano: a las 10h el Fangar ya quema. Lleva más de 1 litro de agua por persona. Si vas en coche hasta la Marquesa, el tramo de bici es de unos 10 km totales.","EN":"Set off very early in summer: by 10am the Fangar is already scorching. Bring more than 1 litre of water per person. If you drive to la Marquesa, the cycling section is about 10 km in total.","FR":"Partez très tôt en été : à 10h le Fangar brûle déjà. Emportez plus d'1 litre d'eau par personne.","DE":"Im Sommer sehr früh aufbrechen: Um 10 Uhr brennt der Fangar bereits. Mehr als 1 Liter Wasser pro Person mitbringen.","NL":"'s Zomers vroeg vertrekken: om 10u brandt de Fangar al. Meer dan 1 liter water per persoon meenemen.","PT":"Sai muito cedo no verão: às 10h o Fangar já queima. Leva mais de 1 litro de água por pessoa."},"lat":40.748,"lng":0.82},{"id":"r4","name":{"CA":"Camí de Sirga del Delta (riu Ebre)","ES":"Camino de Sirga del Delta (río Ebro)","EN":"Delta Towpath (Ebro river)","FR":"Chemin de Halage du Delta (fleuve Èbre)","DE":"Delta-Treidelpfad (Fluss Ebro)","NL":"Delta Jaagpad (Ebro rivier)","PT":"Caminho de Sirga do Delta (rio Ebro)"},"tagline":{"CA":"Vorejant l'Ebre de cap a la gola: el camí més tranquil","ES":"Bordeando el Ebro hacia la desembocadura: el camino más tranquilo","EN":"Following the Ebro to its mouth: the most peaceful path","FR":"Longer l'Èbre vers l'embouchure : le chemin le plus tranquille","DE":"Dem Ebro bis zur Mündung folgen: der ruhigste Weg","NL":"Langs de Ebro naar de monding: het rustigste pad","PT":"Seguindo o Ebro até à foz: o caminho mais tranquilo"},"desc":{"CA":"El Camí de Sirga és l'antiga via de remolc dels barquers de l'Ebre. Avui és un camí de terra i asphalte que voreja el riu des d'Amposta fins a la gola de Migjorn, prop de la desembocadura. 22 km totalment plans, sense cotxes, amb el riu sempre a vista. El millor tram és entre Deltebre i la gola: la llum de la tarda sobre l'Ebre és memorable.","ES":"El Camino de Sirga es la antigua vía de remolque de los barqueros del Ebro. Hoy es un camino de tierra y asfalto que bordea el río desde Amposta hasta la gola de Migjorn, cerca de la desembocadura. 22 km totalmente planos, sin coches, con el río siempre a la vista.","EN":"The Camí de Sirga is the old towpath used by Ebro river barges. Today it is a dirt and tarmac path that follows the river from Amposta to the gola de Migjorn, near the river mouth. 22 km completely flat, no traffic, river always in sight. The best section is between Deltebre and the gola: the afternoon light on the Ebro is memorable.","FR":"Le Camí de Sirga est l'ancien chemin de halage des bateliers de l'Èbre. Aujourd'hui c'est un chemin de terre et de goudron qui longe le fleuve depuis Amposta jusqu'à la gola de Migjorn. 22 km complètement plats, sans voitures, fleuve toujours en vue.","DE":"Der Camí de Sirga ist der alte Treidelweg der Ebro-Flussschiffer. Heute ist es ein Dirt- und Asphaltweg, der dem Fluss von Amposta bis zur gola de Migjorn folgt. 22 km komplett flach, kein Verkehr, immer Flussblick.","NL":"De Camí de Sirga is het oude jaagpad van de Ebro-schippers. Vandaag is het een onverhard en geasfalteerd pad dat de rivier volgt van Amposta tot de gola de Migjorn. 22 km volledig vlak, geen verkeer, altijd rivierzicht.","PT":"O Camí de Sirga é o antigo caminho de sirga dos barqueiros do Ebro. Hoje é um caminho de terra e asfalto que acompanha o rio de Amposta até à gola de Migjorn. 22 km completamente planos, sem carros, sempre com o rio à vista."},"dist":"22 km","time":"1,5-2h","diff":{"CA":"Fàcil","ES":"Fácil","EN":"Easy","FR":"Facile","DE":"Leicht","NL":"Makkelijk","PT":"Fácil"},"elev":"5m ↑","type":"linear","start":{"CA":"Amposta (Pont Penjant) o Deltebre","ES":"Amposta (Pont Penjant) o Deltebre","EN":"Amposta (Pont Penjant) or Deltebre","FR":"Amposta (Pont Penjant) ou Deltebre","DE":"Amposta (Pont Penjant) oder Deltebre","NL":"Amposta (Pont Penjant) of Deltebre","PT":"Amposta (Pont Penjant) ou Deltebre"},"tip":{"CA":"Ruta lineal: organitza un vehicle a l'extrem o fes la meitat i torna. La millor opció per a qui s'allotja a Deltebre: pots arribar a Amposta i tornar pel mateix camí sense repetir paisatge.","ES":"Ruta lineal: organiza un vehículo en el extremo o haz la mitad y vuelve. La mejor opción para quien se aloja en Deltebre: puedes llegar a Amposta y volver por el mismo camino sin repetir paisaje.","EN":"Linear route: arrange a vehicle at the far end or do half and return. Best for those staying in Deltebre: you can reach Amposta and return on the same path without repeating the scenery.","FR":"Route linéaire : prévoyez un véhicule à l'autre extrémité ou faites la moitié et revenez.","DE":"Lineare Route: Fahrzeug am anderen Ende organisieren oder die Hälfte machen und zurückkehren.","NL":"Lineaire route: zorg voor een voertuig aan het andere uiteinde of doe de helft en keer terug.","PT":"Rota linear: organiza um veículo no outro extremo ou faz metade e regressa."},"lat":40.7,"lng":0.68},{"id":"r5","name":{"CA":"La Ràpita · Poblenou · Ullals de Baltasar","ES":"La Ràpita · Poblenou · Ullals de Baltasar","EN":"La Ràpita · Poblenou · Ullals de Baltasar","FR":"La Ràpita · Poblenou · Ullals de Baltasar","DE":"La Ràpita · Poblenou · Ullals de Baltasar","NL":"La Ràpita · Poblenou · Ullals de Baltasar","PT":"La Ràpita · Poblenou · Ullals de Baltasar"},"tagline":{"CA":"El millor del sud en un circuit: llacunes, ullals i el poble blanc","ES":"Lo mejor del sur en un circuito: lagunas, ullals y el pueblo blanco","EN":"The south's best in one loop: lagoons, ullals and the white village","FR":"Le meilleur du sud en circuit : lagunes, ullals et le village blanc","DE":"Das Beste des Südens in einer Runde: Lagunen, Ullals und das weiße Dorf","NL":"Het beste van het zuiden in één ronde: lagunes, ullals en het witte dorp","PT":"O melhor do sul num circuito: lagoas, ullals e a vila branca"},"desc":{"CA":"Circuit que connecta les millors atraccions del hemidelta sud des de la Ràpita. Comença al port pesquer, agafa el camí fins a la Casa de Fusta (Encanyissada), puja als Ullals de Baltasar —les surgències d'aigua dolça entre arrossars—, arriba a Poblenou del Delta (cases blanques, Moll de les Madalenes) i torna vorejant la Tancada. Un circuit molt variat amb flamencos, arrossars i un dels pobles més fotogènics del delta.","ES":"Circuito que conecta las mejores atracciones del hemidelta sur desde la Ràpita. Empieza en el puerto pesquero, toma el camino hasta la Casa de Fusta (Encanyissada), sube a los Ullals de Baltasar, llega a Poblenou del Delta y vuelve bordeando la Tancada.","EN":"A circuit connecting the south hemidelta's best attractions from la Ràpita. Starts at the fishing harbour, heads to Casa de Fusta (Encanyissada), climbs to the Ullals de Baltasar — the freshwater springs among rice fields — reaches Poblenou del Delta and returns along la Tancada.","FR":"Circuit qui relie les meilleures attractions de l'hémidelta sud depuis la Ràpita. Commence au port de pêche, va vers la Casa de Fusta (Encanyissada), monte aux Ullals de Baltasar, atteint Poblenou del Delta et revient le long de la Tancada.","DE":"Runde die die besten Attraktionen des Südhemideltas von la Ràpita verbindet. Beginnt am Fischerhafen, geht zur Casa de Fusta (Encanyissada), steigt zu den Ullals de Baltasar auf, erreicht Poblenou del Delta und kehrt entlang la Tancada zurück.","NL":"Ronde die de beste attracties van het zuidhemidelta verbindt vanaf la Ràpita. Begint bij de vissershaven, gaat naar Casa de Fusta (Encanyissada), klimt naar de Ullals de Baltasar, bereikt Poblenou del Delta en keert terug langs la Tancada.","PT":"Circuito que liga as melhores atrações do hemidelta sul desde a Ràpita. Começa no porto pesqueiro, vai à Casa de Fusta (Encanyissada), sobe aos Ullals de Baltasar, chega a Poblenou del Delta e regressa pela Tancada."},"dist":"31 km","time":"2,5-3h","diff":"mod","elev":"20m ↑","type":"circuit","start":{"CA":"Sant Carles de la Ràpita (port)","ES":"Sant Carles de la Ràpita (puerto)","EN":"Sant Carles de la Ràpita (harbour)","FR":"Sant Carles de la Ràpita (port)","DE":"Sant Carles de la Ràpita (Hafen)","NL":"Sant Carles de la Ràpita (haven)","PT":"Sant Carles de la Ràpita (porto)"},"tip":{"CA":"Als Ullals de Baltasar val la pena baixar de la bici i fer el sender a peu (20 min): les surgències entre nenúfars no es poden gaudir des de la bicicleta.","ES":"En los Ullals de Baltasar vale la pena bajar de la bici y hacer el sendero a pie (20 min): las surgencias entre nenúfares no se pueden disfrutar desde la bicicleta.","EN":"At the Ullals de Baltasar it's worth getting off the bike and walking the trail (20 min): the freshwater springs among water lilies can't be appreciated from the saddle.","FR":"Aux Ullals de Baltasar, il vaut la peine de descendre du vélo et de faire le sentier à pied (20 min).","DE":"Bei den Ullals de Baltasar lohnt es sich, vom Fahrrad zu steigen und den Weg zu Fuß zu gehen (20 Min.).","NL":"Bij de Ullals de Baltasar is het de moeite waard om af te stappen en het pad te voet te bewandelen (20 min).","PT":"Nos Ullals de Baltasar vale a pena descer da bici e fazer o trilho a pé (20 min)."},"lat":40.64,"lng":0.638},{"id":"r6","name":{"CA":"L'Aldea · Camarles · Bassa de les Olles · l'Ampolla","ES":"L'Aldea · Camarles · Bassa de les Olles · l'Ampolla","EN":"L'Aldea · Camarles · Bassa de les Olles · l'Ampolla","FR":"L'Aldea · Camarles · Bassa de les Olles · l'Ampolla","DE":"L'Aldea · Camarles · Bassa de les Olles · l'Ampolla","NL":"L'Aldea · Camarles · Bassa de les Olles · l'Ampolla","PT":"L'Aldea · Camarles · Bassa de les Olles · l'Ampolla"},"tagline":{"CA":"Des de l'estació de tren fins a les llacunes del nord i la platja","ES":"Desde la estación de tren hasta las lagunas del norte y la playa","EN":"From the train station to the northern lagoons and beach","FR":"De la gare jusqu'aux lagunes du nord et à la plage","DE":"Vom Bahnhof zu den nördlichen Lagunen und zum Strand","NL":"Van het treinstation naar de noordelijke lagunes en het strand","PT":"Da estação de comboio até às lagoas do norte e a praia"},"desc":{"CA":"La ruta perfecta per als qui arriben en tren: des de l'estació de l'Aldea-Amposta-Tortosa (les Euromed hi paren) fins a l'Ampolla per carreteres secundàries i camins. Passa per l'ermita medieval de l'Aldea, les torres de vigilància de Camarles, la Bassa de les Olles (flamencos i martins pescadors) i arriba al port i la platja de l'Ampolla.","ES":"La ruta perfecta para quienes llegan en tren: desde la estación de l'Aldea-Amposta-Tortosa hasta l'Ampolla por carreteras secundarias y caminos. Pasa por la ermita medieval de l'Aldea, las torres de vigilancia de Camarles, la Bassa de les Olles y llega al puerto y la playa de l'Ampolla.","EN":"The perfect route for those arriving by train: from l'Aldea-Amposta-Tortosa station to l'Ampolla along secondary roads and paths. Passes through l'Aldea's medieval hermitage, Camarles' watchtowers, the Bassa de les Olles (flamingos and kingfishers) and reaches l'Ampolla port and beach.","FR":"La route parfaite pour ceux qui arrivent en train : de la gare de l'Aldea-Amposta-Tortosa à l'Ampolla par routes secondaires. Passe par l'ermitage médiéval de l'Aldea, les tours de guet de Camarles, la Bassa de les Olles et arrive au port et à la plage de l'Ampolla.","DE":"Die perfekte Route für Zugreisende: von Bahnhof l'Aldea-Amposta-Tortosa nach l'Ampolla auf Nebenstraßen. Führt durch das mittelalterliche Kloster l'Aldea, die Wachtürme von Camarles, Bassa de les Olles und erreicht Hafen und Strand l'Ampolla.","NL":"De perfecte route voor treinreizigers: van station l'Aldea-Amposta-Tortosa naar l'Ampolla via secundaire wegen. Passeert het middeleeuwse klooster van l'Aldea, de wachttorens van Camarles, Bassa de les Olles en bereikt haven en strand l'Ampolla.","PT":"A rota perfeita para quem chega de comboio: da estação de l'Aldea-Amposta-Tortosa a l'Ampolla por estradas secundárias. Passa pela ermida medieval de l'Aldea, as torres de vigia de Camarles, a Bassa de les Olles e chega ao porto e à praia de l'Ampolla."},"dist":"28 km","time":"2-2,5h","diff":{"CA":"Fàcil","ES":"Fácil","EN":"Easy","FR":"Facile","DE":"Leicht","NL":"Makkelijk","PT":"Fácil"},"elev":"15m ↑","type":"circuit","start":{"CA":"Estació de tren de l'Aldea-Amposta-Tortosa","ES":"Estación de tren de l'Aldea-Amposta-Tortosa","EN":"L'Aldea-Amposta-Tortosa train station","FR":"Gare de l'Aldea-Amposta-Tortosa","DE":"Bahnhof L'Aldea-Amposta-Tortosa","NL":"Treinstation L'Aldea-Amposta-Tortosa","PT":"Estação de comboio de l'Aldea-Amposta-Tortosa"},"tip":{"CA":"Lloguer de bici a l'Ampolla (Delta Touristic & Rent). Pots tornar en tren des de l'Ampolla: l'estació l'Ampolla-El Perelló té trens regionals que tornen cap a Tarragona i Barcelona.","ES":"Alquiler de bici en l'Ampolla (Delta Touristic & Rent). Puedes volver en tren desde l'Ampolla: la estación l'Ampolla-El Perelló tiene trenes regionales hacia Tarragona y Barcelona.","EN":"Bike hire in l'Ampolla (Delta Touristic & Rent). You can return by train from l'Ampolla: l'Ampolla-El Perelló station has regional trains back to Tarragona and Barcelona.","FR":"Location de vélo à l'Ampolla (Delta Touristic & Rent). Vous pouvez revenir en train depuis l'Ampolla.","DE":"Fahrradverleih in l'Ampolla (Delta Touristic & Rent). Rückfahrt mit dem Zug von l'Ampolla möglich: Bahnhof l'Ampolla-El Perelló hat Regionalzüge.","NL":"Fietsverhuur in l'Ampolla (Delta Touristic & Rent). Terug per trein vanuit l'Ampolla: station l'Ampolla-El Perelló heeft regionale treinen.","PT":"Aluguer de bici em l'Ampolla (Delta Touristic & Rent). Podes regressar de comboio desde l'Ampolla: estação l'Ampolla-El Perelló tem comboios regionais."},"lat":40.8,"lng":0.69}];

export const D_MUSEUS = [{"icon":"🏛️","cat":{"CA":"Museu","ES":"Museo","EN":"Museum","FR":"Musée","DE":"Museum","NL":"Museum","PT":"Museu"},"name":"Museu de les Terres de l'Ebre","addr":{"CA":"C/ Gran Capità, 34 · Amposta","ES":"C/ Gran Capitán, 34 · Amposta","EN":"C/ Gran Capità, 34 · Amposta","FR":"C/ Gran Capità, 34 · Amposta","DE":"C/ Gran Capità, 34 · Amposta","NL":"C/ Gran Capità, 34 · Amposta","PT":"C/ Gran Capità, 34 · Amposta"},"desc":{"CA":"Museu de referència de les Terres de l'Ebre. Col·leccions d'arqueologia (prehistòria, ibers, romans), etnologia i entorn natural. Inclou el Castell d'Amposta. Centre del Consorci \"Ebre, natura & cultura\".","ES":"Museo de referencia de las Terres de l'Ebre. Colecciones de arqueología (prehistoria, íberos, romanos), etnología y entorno natural. Incluye el Castell d'Amposta.","EN":"Reference museum of the Terres de l'Ebre. Archaeology (prehistory, Iberian, Roman), ethnology and natural environment. Includes Amposta Castle.","FR":"Musée de référence des Terres de l'Ebre. Collections d'archéologie, ethnologie et environnement naturel.","DE":"Referenzmuseum der Terres de l'Ebre. Archäologie (Vorgeschichte, Iberer, Römer), Ethnologie und Naturumgebung.","NL":"Referentiemuseum van de Terres de l'Ebre. Archeologie, etnologie en natuuromgeving.","PT":"Museu de referência das Terres de l'Ebre. Arqueologia, etnologia e ambiente natural."},"tagline":{"CA":"Museu","ES":"Museo","EN":"Museum","FR":"Musée","DE":"Museum","NL":"Museum","PT":"Museu"}},{"icon":"🌳","cat":{"CA":"Ecomuseu","ES":"Ecomuseo","EN":"Ecomuseum","FR":"Écomusée","DE":"Ökomuseum","NL":"Ecomuseum","PT":"Ecomuseu"},"name":"Ecomuseu del Parc Natural del Delta de l'Ebre","addr":{"CA":"C/ Doctor Martí Buera, 22 · Deltebre","ES":"C/ Doctor Martí Buera, 22 · Deltebre","EN":"C/ Doctor Martí Buera, 22 · Deltebre","FR":"C/ Doctor Martí Buera, 22 · Deltebre","DE":"C/ Doctor Martí Buera, 22 · Deltebre","NL":"C/ Doctor Martí Buera, 22 · Deltebre","PT":"C/ Doctor Martí Buera, 22 · Deltebre"},"desc":{"CA":"Centre d'informació i interpretació del Parc Natural del Delta. Introdueix els visitants en el món del delta: ecosistemes, arrossars, pesca, aqüícultura i aus. Recorregut adaptat per a persones amb necessitats especials. Tel. 977 489 679.","ES":"Centro de información e interpretación del Parque Natural del Delta. Introduce a los visitantes en el delta: ecosistemas, arrozales, pesca, acuicultura y aves. Recorrido adaptado. Tel. 977 489 679.","EN":"Information and interpretation centre of the Natural Park. Introduces visitors to the delta world: ecosystems, rice fields, fishing, aquaculture and birds. Adapted route for special needs. Tel. 977 489 679.","FR":"Centre d'information et d'interprétation du Parc Naturel. Introduit les visiteurs au monde du delta: écosystèmes, rizières, pêche et oiseaux. Parcours adapté. Tél. 977 489 679.","DE":"Informationszentrum des Naturparks. Führt Besucher in die Welt des Deltas: Ökosysteme, Reisfelder, Fischerei und Vögel. Adaptierter Weg. Tel. 977 489 679.","NL":"Informatiecentrum van het Natuurpark. Introduceert bezoekers in de deltawereld: ecosystemen, rijstvelden, visserij en vogels. Aangepaste route. Tel. 977 489 679.","PT":"Centro de informação do Parque Natural. Introduz visitantes no mundo do delta: ecossistemas, arrozais, pesca e aves. Percurso adaptado. Tel. 977 489 679."},"tagline":{"CA":"Ecomuseu","ES":"Ecomuseo","EN":"Ecomuseum","FR":"Écomusée","DE":"Ökomuseum","NL":"Ecomuseum","PT":"Ecomuseu"}},{"icon":"🐦","cat":{"CA":"Museu Ornitològic","ES":"Museo Ornitológico","EN":"Ornithological Museum","FR":"Musée Ornithologique","DE":"Ornithologisches Museum","NL":"Ornithologisch Museum","PT":"Museu Ornitológico"},"name":"Casa de la Fusta","addr":{"CA":"Bassa de l'Encanyissada · Poblenou del Delta","ES":"Bassa de l'Encanyissada · Poblenou del Delta","EN":"Encanyissada lagoon · Poblenou del Delta","FR":"Lagune Encanyissada · Poblenou del Delta","DE":"Encanyissada-Lagune · Poblenou del Delta","NL":"Encanyissada-lagune · Poblenou del Delta","PT":"Lagoa Encanyissada · Poblenou del Delta"},"desc":{"CA":"Construida el 1926 per caçadors barcelonins atrets per les aus de l'Encanyissada, avui és el museu ornitològic del delta. Col·lecció d'ocells naturalitzats i exposicions \"Les basses del Delta\" i \"La brossa marina és cosa nostra\". A l'exterior, mirador sobre la llacuna ideal per observar aus. Tel. 977 261 022.","ES":"Construida en 1926 por cazadores barceloneses atraídos por las aves de la Encanyissada, hoy es el museo ornitológico del delta. Colección de aves naturalizadas y exposiciones sobre las lagunas del delta. Mirador exterior sobre la Encanyissada. Tel. 977 261 022.","EN":"Built in 1926 by Barcelona hunters attracted by Encanyissada birds, today it is the delta's ornithological museum. Collection of taxidermied birds and exhibitions on the delta lagoons. Exterior viewpoint over the Encanyissada lagoon. Tel. 977 261 022.","FR":"Construit en 1926 par des chasseurs barcelonais, c'est aujourd'hui le musée ornithologique du delta. Collection d'oiseaux naturalisés, expositions sur les lagunes. Belvédère extérieur sur l'Encanyissada. Tél. 977 261 022.","DE":"1926 von Barcel-Jägern erbaut, heute ornithologisches Museum des Deltas. Naturalisierte Vögel, Ausstellungen über die Deltalagune. Aussichtspunkt über die Encanyissada. Tel. 977 261 022.","NL":"Gebouwd in 1926 door Barcelonese jagers, nu ornithologisch museum van de delta. Opgezette vogels, tentoonstellingen over de deltalagunes. Uitkijkpunt over de Encanyissada. Tel. 977 261 022.","PT":"Construída em 1926 por caçadores barceloneses, hoje museu ornitológico do delta. Coleção de aves naturalizadas, exposições sobre as lagoas. Miradouro exterior sobre a Encanyissada. Tel. 977 261 022."},"tagline":{"CA":"Museu Ornitològic","ES":"Museo Ornitológico","EN":"Ornithological Museum","FR":"Musée Ornithologique","DE":"Ornithologisches Museum","NL":"Ornithologisch Museum","PT":"Museu Ornitológico"}},{"icon":"⚓","cat":{"CA":"Museu","ES":"Museo","EN":"Museum","FR":"Musée","DE":"Museum","NL":"Museum","PT":"Museu"},"name":"Museu de la Mar de l'Ebre","addr":{"CA":"Sant Carles de la Ràpita","ES":"Sant Carles de la Ràpita","EN":"Sant Carles de la Ràpita","FR":"Sant Carles de la Ràpita","DE":"Sant Carles de la Ràpita","NL":"Sant Carles de la Ràpita","PT":"Sant Carles de la Ràpita"},"desc":{"CA":"Museu dedicat a la memòria i la cultura marínera de les Terres de l'Ebre: pesca artesanal, embarcacions tradicionals i la vida als ports de la badia dels Alfacs.","ES":"Museo dedicado a la memoria y cultura marinera de las Terres de l'Ebre: pesca artesanal, embarcaciones tradicionales y la vida en los puertos de la bahía de los Alfacs.","EN":"Museum dedicated to the maritime memory and culture of the Terres de l'Ebre: artisan fishing, traditional boats and life in the Alfacs bay ports.","FR":"Musée dédié à la mémoire maritime des Terres de l'Ebre: pêche artisanale, embarcations traditionnelles.","DE":"Museum über die maritime Erinnerung der Terres de l'Ebre: Handwerksfischerei, traditionelle Boote.","NL":"Museum gewijd aan de maritieme herinnering van de Terres de l'Ebre.","PT":"Museu dedicado à memória marínheira das Terres de l'Ebre."},"tagline":{"CA":"Museu","ES":"Museo","EN":"Museum","FR":"Musée","DE":"Museum","NL":"Museum","PT":"Museu"}},{"icon":"🏘️","cat":{"CA":"Centre d'Interpretació","ES":"Centro de Interpretación","EN":"Interpretation Centre","FR":"Centre d'interprétation","DE":"Besucherzentrum","NL":"Informatiecentrum","PT":"Centro de Interpretação"},"name":"CI de les Barraques del Delta","addr":{"CA":"C/ Carles I, 22 · Sant Jaume d'Enveja","ES":"C/ Carles I, 22 · Sant Jaume d'Enveja","EN":"C/ Carles I, 22 · Sant Jaume d'Enveja","FR":"C/ Carles I, 22 · Sant Jaume d'Enveja","DE":"C/ Carles I, 22 · Sant Jaume d'Enveja","NL":"C/ Carles I, 22 · Sant Jaume d'Enveja","PT":"C/ Carles I, 22 · Sant Jaume d'Enveja"},"desc":{"CA":"Les barraques de delta són l'arquitectura popular més singular del territori. Maquetes, objectes originals, fotografies i audiovisuals per descobrir aquest patrimoni mil·lenari que va ser l'habitatge dels habitants de la plana deltaica.","ES":"Las barracas del delta son la arquitectura popular más singular del territorio. Maquetas, objetos originales, fotografías y audiovisuales para descubrir este patrimonio milenario.","EN":"Delta barraques are the most distinctive vernacular architecture of the region. Scale models, original objects, photos and audiovisuals to discover this millennial heritage.","FR":"Les barraques du delta sont l'architecture vernaculaire la plus distinctive de la région. Maquettes, objets originaux, photos et audiovisuels.","DE":"Die Barraques des Deltas sind die markanteste Volksarchitektur der Region. Modelle, Originalobjekte, Fotos und Audiovisuals.","NL":"De barraques van de delta zijn de meest typerende volksarchitectuur van de regio. Maquettes, originele objecten, foto's en audiovisueel.","PT":"As barraques do delta são a arquitectura popular mais singular da região."},"tagline":{"CA":"Centre d'Interpretació","ES":"Centro de Interpretación","EN":"Interpretation Centre","FR":"Centre d'interprétation","DE":"Besucherzentrum","NL":"Informatiecentrum","PT":"Centro de Interpretação"}},{"icon":"⚔️","cat":{"CA":"Espai Històric","ES":"Espacio Histórico","EN":"Historic Site","FR":"Site historique","DE":"Historischer Ort","NL":"Historische plek","PT":"Espaço Histórico"},"name":"Espais de la Batalla de l'Ebre (1938)","addr":{"CA":"Múltiples ubicacions · Terra Alta, Ribera d'Ebre i Baix Ebre","ES":"Múltiples ubicaciones · Terra Alta, Ribera d'Ebro y Bajo Ebro","EN":"Multiple locations · Terra Alta, Ribera d'Ebre and Baix Ebre","FR":"Multiples sites · Terra Alta, Ribera d'Ebre et Baix Ebre","DE":"Mehrere Orte · Terra Alta, Ribera d'Ebre und Baix Ebre","NL":"Meerdere locaties · Terra Alta, Ribera d'Ebre en Baix Ebre","PT":"Vários locais · Terra Alta, Ribera d'Ebre e Baix Ebre"},"desc":{"CA":"La Batalla de l'Ebre (25 juliol – 16 novembre 1938) va ser la més sangínosa de la Guerra Civil espanyola i el punt d'inflexió que va propiciar la caiguda de Catalunya. El territori conserva trinxeres, refugis museitzats i monuments. Des del delta (Tortosa, Amposta) són a 30-45 min els centres més propers.","ES":"La Batalla del Ebro (25 julio – 16 noviembre 1938) fue la más sangrienta de la Guerra Civil española y el punto de inflexión que propició la caída de Cataluña. El territorio conserva trincheras, refugios museizados y monumentos. Desde el delta (Tortosa, Amposta) a 30-45 min.","EN":"The Battle of the Ebro (25 July – 16 Nov 1938) was the bloodiest of the Spanish Civil War and the turning point that led to the fall of Catalonia. The area preserves trenches, musealised shelters and monuments. From the delta (Tortosa, Amposta) 30-45 min drive.","FR":"La Bataille de l'Ebre (25 juillet – 16 nov. 1938) fut la plus sanglante de la Guerre Civile espagnole. Le territoire conserve des tranchées, des abris muséalisés. À 30-45 min du delta.","DE":"Die Schlacht am Ebro (25. Juli – 16. Nov. 1938) war die blutigste des Spanischen Bürgerkriegs. Das Gebiet bewahrt Schützengraben und museale Schutzräume. Vom Delta 30-45 Minuten.","NL":"De Slag om de Ebro was de bloedigste van de Spaanse Burgeroorlog. Het gebied bewaart loopgraven en museale schuilkelders. Vanuit de delta 30-45 min.","PT":"A Batalha do Ebro (25 jul. – 16 nov. 1938) foi a mais sangrenta da Guerra Civil espanhola. O território conserva trincheiras e abrigos musealiz."},"tagline":{"CA":"Espai Històric","ES":"Espacio Histórico","EN":"Historic Site","FR":"Site historique","DE":"Historischer Ort","NL":"Historische plek","PT":"Espaço Histórico"}},{"icon":"🌉","cat":{"CA":"Monument","ES":"Monumento","EN":"Monument","FR":"Monument","DE":"Denkmal","NL":"Monument","PT":"Monumento"},"name":"Pont Penjant d'Amposta","addr":{"CA":"Riu Ebre · Amposta","ES":"Río Ebro · Amposta","EN":"River Ebro · Amposta","FR":"Rio Ebre · Amposta","DE":"Fluss Ebro · Amposta","NL":"Rivier Ebro · Amposta","PT":"Rio Ebro · Amposta"},"desc":{"CA":"Un dels ponts penjants més llargs d'Espanya (172 m) i l'icona d'Amposta. Construït el 1921, uneix les dues ribes de l'Ebre i permet creuar a peu o amb bicicleta. Les vistes del riu i el delta des del pont són excepcionals.","ES":"Uno de los puentes colgantes más largos de España (172 m) y el icono de Amposta. Construido en 1921, une las dos orillas del Ebro y permite cruzar a pie o en bici. Las vistas del río y el delta desde el puente son excepcionales.","EN":"One of Spain's longest suspension bridges (172 m) and the icon of Amposta. Built in 1921, it links the two banks of the Ebro and can be crossed on foot or by bike. Exceptional views of the river and delta.","FR":"L'un des ponts suspendus les plus longs d'Espagne (172 m) et l'icône d'Amposta. Construit en 1921, il relie les deux rives de l'Ebre.","DE":"Eine der längsten Hängenbrücken Spaniens (172 m) und das Wahrzeichen von Amposta. Gebaut 1921.","NL":"Een van de langste hangbruggen van Spanje (172 m) en het icoon van Amposta. Gebouwd in 1921.","PT":"Uma das maiores pontes pensáteis de Espanha (172 m) e ícone de Amposta. Construída em 1921."},"tagline":{"CA":"Monument","ES":"Monumento","EN":"Monument","FR":"Monument","DE":"Denkmal","NL":"Monument","PT":"Monumento"}},{"icon": "🦩", "cat": {"CA": "Centre d'Interpretació", "ES": "Centro de Interpretación", "EN": "Interpretation Centre", "FR": "Centre d'Interprétation", "DE": "Interpretationszentrum", "NL": "Interpretatiecentrum", "PT": "Centro de Interpretação"}, "name": "MónNatura Delta de l'Ebre", "addr": {"CA": "Partida la Tancada, s/n · Amposta", "ES": "Partida la Tancada, s/n · Amposta", "EN": "Partida la Tancada, s/n · Amposta", "FR": "Partida la Tancada, s/n · Amposta", "DE": "Partida la Tancada, s/n · Amposta", "NL": "Partida la Tancada, s/n · Amposta", "PT": "Partida la Tancada, s/n · Amposta"}, "desc": {"CA": "Centre d'interpretació de la Fundació Catalunya-La Pedrera a les antigues salines de la Tancada. La sal, la pesca tradicional i l'observació d'ocells en són els fils conductors, amb un Mirador 360º i un aguait. Un dels millors llocs per veure flamencs.", "ES": "Centro de interpretación de la Fundación Catalunya-La Pedrera en las antiguas salinas de la Tancada. La sal, la pesca tradicional y la observación de aves son sus hilos conductores, con un Mirador 360º y un aguait. Uno de los mejores sitios para ver flamencos.", "EN": "Catalunya-La Pedrera interpretation centre on the former Tancada saltworks. Salt, traditional fishing and birdwatching are its themes, with a 360º viewpoint and a hide. One of the best places to see flamingos.", "FR": "Centre d'interprétation de la Fondation Catalunya-La Pedrera sur les anciennes salines de la Tancada. Le sel, la pêche traditionnelle et l'observation des oiseaux en sont les fils conducteurs, avec un belvédère 360º et un observatoire. L'un des meilleurs endroits pour voir les flamants.", "DE": "Interpretationszentrum der Stiftung Catalunya-La Pedrera in den ehemaligen Salinen von la Tancada. Salz, traditioneller Fischfang und Vogelbeobachtung sind die Leitthemen, mit einem 360º-Aussichtspunkt und einem Beobachtungsstand. Einer der besten Orte für Flamingos.", "NL": "Bezoekerscentrum van de Stichting Catalunya-La Pedrera op de voormalige zoutpannen van la Tancada. Zout, traditionele visserij en vogels kijken zijn de thema's, met een 360º-uitkijkpunt en een kijkhut. Een van de beste plekken voor flamingo's.", "PT": "Centro de interpretação da Fundação Catalunya-La Pedrera nas antigas salinas da Tancada. O sal, a pesca tradicional e a observação de aves são os fios condutores, com um Miradouro 360º e um observatório. Um dos melhores locais para ver flamingos."}, "tagline": {"CA": "Sal, pesca i flamencs", "ES": "Sal, pesca y flamencos", "EN": "Salt, fishing and flamingos", "FR": "Sel, pêche et flamants", "DE": "Salz, Fischfang und Flamingos", "NL": "Zout, visserij en flamingo's", "PT": "Sal, pesca e flamingos"}},{"icon": "🌾", "cat": {"CA": "Centre d'Interpretació", "ES": "Centro de Interpretación", "EN": "Interpretation Centre", "FR": "Centre d'Interprétation", "DE": "Interpretationszentrum", "NL": "Interpretatiecentrum", "PT": "Centro de Interpretação"}, "name": "CI de l'Arròs «La Torra»", "addr": {"CA": "La Torra · Camarles", "ES": "La Torra · Camarles", "EN": "La Torra · Camarles", "FR": "La Torra · Camarles", "DE": "La Torra · Camarles", "NL": "La Torra · Camarles", "PT": "La Torra · Camarles"}, "desc": {"CA": "Centre d'interpretació de l'arròs a Camarles. Explica el conreu, la història i la cultura de l'arròs al delta, el cultiu que defineix el paisatge i l'economia de la zona.", "ES": "Centro de interpretación del arroz en Camarles. Explica el cultivo, la historia y la cultura del arroz en el delta, el cultivo que define el paisaje y la economía de la zona.", "EN": "Rice interpretation centre in Camarles. It explains the cultivation, history and culture of rice in the delta, the crop that shapes the area's landscape and economy.", "FR": "Centre d'interprétation du riz à Camarles. Il présente la culture, l'histoire et la tradition du riz dans le delta, la production qui façonne le paysage et l'économie de la région.", "DE": "Reis-Interpretationszentrum in Camarles. Es erklärt Anbau, Geschichte und Kultur des Reises im Delta, der Landschaft und Wirtschaft der Gegend prägt.", "NL": "Interpretatiecentrum van de rijst in Camarles. Het verklaart de teelt, geschiedenis en cultuur van de rijst in de delta, het gewas dat het landschap en de economie bepaalt.", "PT": "Centro de interpretação do arroz em Camarles. Explica o cultivo, a história e a cultura do arroz no delta, a cultura que define a paisagem e a economia da zona."}, "tagline": {"CA": "La cultura de l'arròs", "ES": "La cultura del arroz", "EN": "Rice culture", "FR": "La culture du riz", "DE": "Die Reiskultur", "NL": "De rijstcultuur", "PT": "A cultura do arroz"}},{"icon": "🧭", "cat": {"CA": "Centre de Visitants", "ES": "Centro de Visitantes", "EN": "Visitor Centre", "FR": "Centre de Visiteurs", "DE": "Besucherzentrum", "NL": "Bezoekerscentrum", "PT": "Centro de Visitantes"}, "name": "Ebre Terra, Centre d'Inspiració Turística", "addr": {"CA": "Ebre Terra · Deltebre", "ES": "Ebre Terra · Deltebre", "EN": "Ebre Terra · Deltebre", "FR": "Ebre Terra · Deltebre", "DE": "Ebre Terra · Deltebre", "NL": "Ebre Terra · Deltebre", "PT": "Ebre Terra · Deltebre"}, "desc": {"CA": "Centre d'inspiració turística a Deltebre, punt de partida per descobrir el delta. Ofereix informació, propostes d'experiències i una primera mirada al territori abans de recórrer-lo.", "ES": "Centro de inspiración turística en Deltebre, punto de partida para descubrir el delta. Ofrece información, propuestas de experiencias y una primera mirada al territorio antes de recorrerlo.", "EN": "Tourist inspiration centre in Deltebre, a starting point to discover the delta. It offers information, experience ideas and a first look at the area before exploring it.", "FR": "Centre d'inspiration touristique à Deltebre, point de départ pour découvrir le delta. Il propose des informations, des idées d'expériences et un premier aperçu du territoire.", "DE": "Touristisches Inspirationszentrum in Deltebre, Ausgangspunkt zur Entdeckung des Deltas. Es bietet Informationen, Erlebnisvorschläge und einen ersten Einblick in die Gegend.", "NL": "Toeristisch inspiratiecentrum in Deltebre, vertrekpunt om de delta te ontdekken. Het biedt informatie, ervaringsideeën en een eerste blik op het gebied.", "PT": "Centro de inspiração turística em Deltebre, ponto de partida para descobrir o delta. Oferece informação, propostas de experiências e um primeiro olhar sobre o território."}, "tagline": {"CA": "Comença aquí el delta", "ES": "Empieza aquí el delta", "EN": "Start the delta here", "FR": "Le delta commence ici", "DE": "Hier beginnt das Delta", "NL": "Hier begint de delta", "PT": "Comece aqui o delta"}},{"icon": "🍚", "cat": {"CA": "Museu", "ES": "Museo", "EN": "Museum", "FR": "Musée", "DE": "Museum", "NL": "Museum", "PT": "Museu"}, "name": "Molí de Rafelet", "addr": {"CA": "Molí de Rafelet · Deltebre", "ES": "Molí de Rafelet · Deltebre", "EN": "Molí de Rafelet · Deltebre", "FR": "Molí de Rafelet · Deltebre", "DE": "Molí de Rafelet · Deltebre", "NL": "Molí de Rafelet · Deltebre", "PT": "Molí de Rafelet · Deltebre"}, "desc": {"CA": "Petit museu de l'arròs en un antic molí de fusta a Deltebre. Mostra el cultiu, l'elaboració i l'envasat de l'arròs, les varietats i les formes tradicionals de cuinar-lo.", "ES": "Pequeño museo del arroz en un antiguo molino de madera en Deltebre. Muestra el cultivo, la elaboración y el envasado del arroz, las variedades y las formas tradicionales de cocinarlo.", "EN": "A small rice museum in an old wooden mill in Deltebre. It shows the cultivation, processing and packaging of rice, its varieties and traditional ways of cooking it.", "FR": "Petit musée du riz dans un ancien moulin en bois à Deltebre. Il présente la culture, la transformation et le conditionnement du riz, ses variétés et les façons traditionnelles de le cuisiner.", "DE": "Kleines Reismuseum in einer alten Holzmühle in Deltebre. Es zeigt Anbau, Verarbeitung und Verpackung des Reises, seine Sorten und traditionelle Zubereitungen.", "NL": "Klein rijstmuseum in een oude houten molen in Deltebre. Het toont de teelt, verwerking en verpakking van rijst, de variëteiten en traditionele bereidingswijzen.", "PT": "Pequeno museu do arroz num antigo moinho de madeira em Deltebre. Mostra o cultivo, o processamento e o embalamento do arroz, as variedades e as formas tradicionais de o cozinhar."}, "tagline": {"CA": "L'arròs, del molí al plat", "ES": "El arroz, del molino al plato", "EN": "Rice, from mill to plate", "FR": "Le riz, du moulin à l'assiette", "DE": "Reis, von der Mühle zum Teller", "NL": "Rijst, van molen tot bord", "PT": "O arroz, do moinho ao prato"}},{"icon": "🗼", "cat": {"CA": "Centre d'Interpretació", "ES": "Centro de Interpretación", "EN": "Interpretation Centre", "FR": "Centre d'Interprétation", "DE": "Interpretationszentrum", "NL": "Interpretatiecentrum", "PT": "Centro de Interpretação"}, "name": "CI de les Torres de Guaita", "addr": {"CA": "Ctra. de l'Ermita (antiga estació) · l'Aldea", "ES": "Ctra. de l'Ermita (antiga estació) · l'Aldea", "EN": "Ctra. de l'Ermita (antiga estació) · l'Aldea", "FR": "Ctra. de l'Ermita (antiga estació) · l'Aldea", "DE": "Ctra. de l'Ermita (antiga estació) · l'Aldea", "NL": "Ctra. de l'Ermita (antiga estació) · l'Aldea", "PT": "Ctra. de l'Ermita (antiga estació) · l'Aldea"}, "desc": {"CA": "Centre d'interpretació de les torres de guaita, a la Torre de l'Ermita de l'Aldea. Explica el sistema de torres de vigilància que protegien la costa i el riu de la pirateria, instal·lat en una antiga estació de tren.", "ES": "Centro de interpretación de las torres de vigía, en la Torre de l'Ermita de l'Aldea. Explica el sistema de torres de vigilancia que protegían la costa y el río de la piratería, instalado en una antigua estación de tren.", "EN": "Interpretation centre on the watchtowers, at the Torre de l'Ermita in l'Aldea. It explains the system of lookout towers that protected the coast and river from piracy, set in a former railway station.", "FR": "Centre d'interprétation des tours de guet, à la Torre de l'Ermita de l'Aldea. Il explique le système de tours de surveillance qui protégeaient la côte et le fleuve de la piraterie, installé dans une ancienne gare.", "DE": "Interpretationszentrum der Wachtürme, am Torre de l'Ermita in l'Aldea. Es erklärt das System der Wachtürme, die Küste und Fluss vor Piraterie schützten, in einem ehemaligen Bahnhof.", "NL": "Interpretatiecentrum over de wachttorens, bij de Torre de l'Ermita in l'Aldea. Het verklaart het systeem van uitkijktorens die kust en rivier tegen piraterij beschermden, in een voormalig treinstation.", "PT": "Centro de interpretação das torres de vigia, na Torre de l'Ermita de l'Aldea. Explica o sistema de torres de vigilância que protegiam a costa e o rio da pirataria, instalado numa antiga estação de comboio."}, "tagline": {"CA": "Vigies de costa i riu", "ES": "Vigías de costa y río", "EN": "Watchers of coast and river", "FR": "Guetteurs de côte et de fleuve", "DE": "Wächter von Küste und Fluss", "NL": "Wachters van kust en rivier", "PT": "Vigias de costa e rio"}}];

export const D_FAM = [{"icon":"🚢","name":{"CA":"Creuer per la desembocadura del riu","ES":"Crucero por la desembocadura del río","EN":"River mouth boat trip","FR":"Croisière à l'embouchure du fleuve","DE":"Bootsfahrt zur Flussmündung","NL":"Bootreis naar de riviermonding","PT":"Cruzeiro pela foz do rio"},"age":{"CA":"A partir de 5 anys","ES":"A partir de 5 años","EN":"From 5 years old","FR":"Dès 5 ans","DE":"Ab 5 Jahren","NL":"Vanaf 5 jaar","PT":"A partir de 5 anos"},"desc":{"CA":"Navegar des de Deltebre fins a la desembocadura per veure l'Illa de Buda, els arrossars i les aus nidificants. Una de les activitats més recomanades amb nens. Preu: nens (5–10 anys) 9€, adults 11€.","ES":"Navegar desde Deltebre hasta la desembocadura para ver la Isla de Buda, los arrozales y las aves nidificantes. Una de las actividades más recomendadas con niños. Precio: niños (5–10 años) 9€, adultos 11€.","EN":"Cruise from Deltebre to the river mouth to see Buda Island, rice fields and nesting birds. One of the most recommended activities with kids. Price: children (5-10) €9, adults €11.","FR":"Croisière de Deltebre à l'embouchure pour voir l'Île de Buda, les rizières et les oiseaux nicheurs. Une des activités les plus recommandées. Prix: enfants 9€, adultes 11€.","DE":"Kreuzfahrt von Deltebre zur Mündung: Buda-Insel, Reisfelder und Nistvögel. Preis: Kinder 9€, Erwachsene 11€.","NL":"Cruise van Deltebre naar de monding: Buda-eiland, rijstvelden en broedvogels. Prijs: kinderen 9€, volwassenen 11€.","PT":"Cruzeiro de Deltebre até à foz: Ilha de Buda, arrozais e aves. Preço: crianças 9€, adultos 11€."}},{"icon":"🌡️","name":{"CA":"MónNatura Delta de l'Ebre (Poblenou)","ES":"MónNatura Delta del Ebro (Poblenou)","EN":"MónNatura Delta de l'Ebre (Poblenou)","FR":"MónNatura Delta de l'Ebre (Poblenou)","DE":"MónNatura Delta de l'Ebre (Poblenou)","NL":"MónNatura Delta de l'Ebre (Poblenou)","PT":"MónNatura Delta de l'Ebre (Poblenou)"},"age":{"CA":"A partir de 3 anys","ES":"A partir de 3 años","EN":"From 3 years old","FR":"Dès 3 ans","DE":"Ab 3 Jahren","NL":"Vanaf 3 jaar","PT":"A partir de 3 anos"},"desc":{"CA":"Centre familiar al Parc Natural. Tallers educatius sobre flamencs, aus, sal i pesca tradicional. Barques de perxar per al canal, mirador 360º amb binòculs, itinerari lliure. Preu: nens (5–12 anys) 6€, adults 10€.","ES":"Centro familiar en el Parque Natural. Talleres educativos sobre flamencos, aves, sal y pesca tradicional. Barcos de palanca para el canal, mirador 360º con binóculos, itinerario libre. Precio: niños 6€, adultos 10€.","EN":"Family centre in the Natural Park. Educational workshops on flamingos, birds, salt and traditional fishing. Punt boats for the canal, 360º viewpoint with binoculars, self-guided trail. Price: children €6, adults €10.","FR":"Centre familial dans le Parc Naturel. Ateliers sur les flamants, oiseaux, sel et pêche traditionnelle. Barques à perche, belvédère 360º. Prix: enfants 6€, adultes 10€.","DE":"Familienzentrum im Naturpark. Workshops über Flamingos, Vögel, Salz. Stocherkahne, 360º-Aussicht. Preise: Kinder 6€, Erwachsene 10€.","NL":"Familiecentrum in het Natuurpark. Workshops over flamingo's, vogels, zout. Prikbootjes, 360º-uitkijkpunt. Prijs: kinderen 6€, volwassenen 10€.","PT":"Centro familiar no Parque Natural. Workshops sobre flamingos, aves, sal. Barcos de pértega, miradouro 360º. Preço: crianças 6€, adultos 10€."}},{"icon":"🚲","name":{"CA":"Rutes en bici pels arrossars","ES":"Rutas en bici por los arrozales","EN":"Bike routes through the rice fields","FR":"Routes à vélo dans les rizières","DE":"Fahrradtouren durch die Reisfelder","NL":"Fietsroutes door de rijstvelden","PT":"Rotas de bici pelos arrozais"},"age":{"CA":"Des de 4 anys (bici-car disponible)","ES":"Desde 4 años (bici-carro disponible)","EN":"From 4 years (bike-car available)","FR":"Dès 4 ans (vélo-voiture disponible)","DE":"Ab 4 Jahren (Fahrradauto verfügbar)","NL":"Vanaf 4 jaar (fietsauto beschikbaar)","PT":"A partir de 4 anos (bici-carro disponível)"},"desc":{"CA":"El delta és pla i segur per a bicicleta familiar. Les empreses de lloguer ofereixen bici-cars (cotxes de pedals) per als més petits. La ruta més suau: Deltebre → Sant Jaume d'Enveja per Lo Passador (8 km). A la tardor (setembre-octubre) els arrossars es tornen daurats i la collita és espectacular.","ES":"El delta es plano y seguro para bicicleta familiar. Las empresas de alquiler ofrecen bici-carros (coches de pedales) para los más pequeños. Ruta más suave: Deltebre → Sant Jaume d'Enveja por Lo Passador (8 km). En otoño los arrozales se vuelven dorados.","EN":"The delta is flat and safe for family cycling. Hire companies offer bike-cars (pedal cars) for small children. Easiest route: Deltebre → Sant Jaume d'Enveja via Lo Passador (8 km). In autumn rice fields turn golden.","FR":"Le delta est plat et sûr pour le cyclisme familial. Les loueurs proposent des vélo-voitures. Itinéraire le plus doux: Deltebre → Sant Jaume (8 km). En automne les rizières deviennent dorées.","DE":"Das Delta ist flach und sicher für Familien-Radtouren. Verleih bietet Fahrraduros an. Einfachste Route: Deltebre → Sant Jaume (8 km). Im Herbst werden Reisfelder golden.","NL":"De delta is vlak en veilig voor familietochten. Verhuur biedt fietsauto's aan. Makkelijkste route: Deltebre → Sant Jaume (8 km). In het najaar worden rijstvelden goud.","PT":"O delta é plano e seguro para ciclismo familiar. Aluguer de bici-carros. Rota mais suave: Deltebre → Sant Jaume (8 km). No outono os arrozais ficam dourados."}},{"icon":"🦩","name":{"CA":"Observació de flamencs","ES":"Observación de flamencos","EN":"Flamingo watching","FR":"Observation de flamants","DE":"Flamingo-Beobachtung","NL":"Flamingo's spotten","PT":"Observação de flamingos"},"age":{"CA":"Totes les edats","ES":"Todas las edades","EN":"All ages","FR":"Tous âges","DE":"Alle Altersgruppen","NL":"Alle leeftijden","PT":"Todas as idades"},"desc":{"CA":"Els flamencs són presents al delta tot l'any (més nombrosos a l'estiu). Els millors llocs: Llacuna de l'Encanyissada (mirador), Llacuna de la Tancada, Bassa de les Olles. Porta binòculs. Entrada gratuita als miradors.","ES":"Los flamencos están presentes en el delta todo el año (más numerosos en verano). Los mejores lugares: Laguna de l'Encanyissada (mirador), Laguna de la Tancada, Bassa de les Olles. Lleva prismáticos. Entrada gratuita a los miradores.","EN":"Flamingos are present in the delta all year (more numerous in summer). Best spots: Encanyissada lagoon (viewpoint), Tancada lagoon, Bassa de les Olles. Bring binoculars. Viewpoints are free.","FR":"Les flamants sont présents dans le delta toute l'année (plus nombreux en été). Meilleurs endroits: lagune de l'Encanyissada, lagune de la Tancada, Bassa de les Olles. Jumelles recommandées.","DE":"Flamingos sind das ganze Jahr über im Delta (im Sommer zahlreicher). Beste Punkte: Encanyissada-Lagune, Tancada-Lagune, Bassa de les Olles. Fernglas empfohlen.","NL":"Flamingo's zijn het hele jaar aanwezig (meer in de zomer). Beste plekken: Encanyissada-lagune, Tancada-lagune, Bassa de les Olles. Verrekijker aanbevolen.","PT":"Os flamingos estão presentes no delta todo o ano. Melhores locais: lagoa Encanyissada, lagoa Tancada, Bassa de les Olles."}},{"icon":"🏖️","name":{"CA":"Platges segures per a nens","ES":"Playas seguras para niños","EN":"Safe beaches for kids","FR":"Plages sûres pour enfants","DE":"Sichere Strände für Kinder","NL":"Veilige stranden voor kinderen","PT":"Praias seguras para crianças"},"age":{"CA":"Totes les edats","ES":"Todas las edades","EN":"All ages","FR":"Tous âges","DE":"Alle Altersgruppen","NL":"Alle leeftijden","PT":"Todas as idades"},"desc":{"CA":"Les millors platges per a famílies: Riumar (dunes gegants per jugar), Platja de les Delícies (Bandera Blava, aigues molt poc profundes), Platja del Garbí (la Ràpita, protegida de la Tramuntana). A l'estiu hi ha socorristes i Creu Roja a les platges de Bandera Blava.","ES":"Las mejores playas para familias: Riumar (dunas gigantes para jugar), Platja de les Delícies (Bandera Azul, aguas muy poco profundas), Platja del Garbí (la Ràpita, protegida de la Tramontana). En verano hay socorristas y Cruz Roja en las playas de Bandera Azul.","EN":"Best beaches for families: Riumar (giant dunes to play in), Platja de les Delícies (Blue Flag, very shallow water), Platja del Garbí (la Ràpita, protected from the Tramontana). In summer lifeguards and Red Cross at Blue Flag beaches.","FR":"Meilleures plages pour familles: Riumar (grandes dunes), Platja de les Delícies (Pavillon Bleu, eaux peu profondes), Platja du Garbí (la Ràpita, protégée du Tramontane).","DE":"Beste Strände für Familien: Riumar (riesige Dünen), Platja de les Delícies (Blaue Flagge, flaches Wasser), Platja del Garbí (la Ràpita).","NL":"Beste stranden voor families: Riumar (grote duinen), Platja de les Delícies (Blauwe Vlag, ondiep water), Platja del Garbí (la Ràpita).","PT":"Melhores praias para famílias: Riumar (dunas gigantes), Platja de les Delícies (Bandeira Azul, água rasa), Platja do Garbí (la Ràpita)."}},{"icon":"🌅","name":{"CA":"Dunes de Riumar: la croqueta!","ES":"Dunas de Riumar: ¡la croqueta!","EN":"Riumar Dunes: the roll!","FR":"Dunes de Riumar: le rollé!","DE":"Dünen von Riumar: rollen!","NL":"Duinen van Riumar: rollen!","PT":"Dunas de Riumar: rolar!"},"age":{"CA":"Especialment 3–12 anys","ES":"Especialmente 3–12 años","EN":"Especially 3–12 years","FR":"Surtout 3–12 ans","DE":"Besonders 3–12 Jahre","NL":"Vooral 3–12 jaar","PT":"Especialmente 3–12 anos"},"desc":{"CA":"Les dunes de la punta de Riumar són un dels espais més emblemàtics del delta. Baixar-les fent la \"croqueta\" (rodant per la sorra) és un clàssic de visitar el delta amb nens. Gratuita. A peu des de l'aparcament de Riumar (20 min).","ES":"Las dunas de la punta de Riumar son uno de los espacios más emblemáticos del delta. Bajarlas haciendo la \"croqueta\" (rodando por la arena) es un clásico. Gratuito. A pie desde el aparcamiento de Riumar (20 min).","EN":"The dunes at Riumar point are one of the delta's most iconic spots. Rolling down them (the \"croqueta\") is a classic with kids. Free. On foot from Riumar car park (20 min).","FR":"Les dunes de la pointe de Riumar sont l'un des endroits les plus icôniques du delta. Descendre en roulant (la \"croqueta\") est un classique avec les enfants. Gratuit.","DE":"Die Dünen an der Riumar-Spitze sind eine der ikonischsten Stellen des Deltas. Das Rollen (\"Croqueta\") ist ein Klassiker für Kinder. Kostenlos.","NL":"De duinen bij Riumar-punt zijn een van de meest iconische plekken van de delta. Erover rollen (\"croqueta\") is klassiek met kinderen. Gratis.","PT":"As dunas da ponta de Riumar são um dos locais mais icónicos do delta. Rolar por elas (\"a croquete\") é clássico com crianças. Gratuito."}},{"icon":"🌲","name":{"CA":"DeltaVentura (L'Ampolla)","ES":"DeltaVentura (L'Ampolla)","EN":"DeltaVentura (L'Ampolla)","FR":"DeltaVentura (L'Ampolla)","DE":"DeltaVentura (L'Ampolla)","NL":"DeltaVentura (L'Ampolla)","PT":"DeltaVentura (L'Ampolla)"},"age":{"CA":"A partir de 6 anys","ES":"A partir de 6 años","EN":"From 6 years old","FR":"Dès 6 ans","DE":"Ab 6 Jahren","NL":"Vanaf 6 jaar","PT":"A partir de 6 anos"},"desc":{"CA":"Parc d'aventura al bosc de pins de L'Ampolla. Circuits de tirolina, ponts penjants, escales de corda i elements de multiaventura a diferents altures. Diverses rutes classificades per dificultat (verd, blau, vermell). Obert d'abril a octubre. Preu aprox.: nens 14€, adults 18€. Reserva online recomanada.","ES":"Parque de aventura en el bosque de pinos de L'Ampolla. Circuitos de tirolina, puentes colgantes, escaleras de cuerda y multiaventura a diferentes alturas. Varias rutas clasificadas por dificultad. Abierto de abril a octubre. Precio aprox.: niños 14€, adultos 18€. Reserva online recomendada.","EN":"Adventure park in the pine forest of L'Ampolla. Zip-line circuits, suspension bridges, rope ladders and multi-adventure elements at different heights. Several routes by difficulty level. Open April to October. Price approx.: children €14, adults €18. Online booking recommended.","FR":"Parc d'aventure dans la pinède de L'Ampolla. Circuits de tyrolienne, ponts suspendus, échelles de corde. Ouvert d'avril à octobre. Prix: enfants 14€, adultes 18€.","DE":"Abenteuerpark im Kiefernwald von L'Ampolla. Seilbahn-Parcours, Hängbrücken, Seilleitern. April bis Oktober. Preise: Kinder 14€, Erwachsene 18€.","NL":"Avonturenpark in het dennenbos van L'Ampolla. Zipline-parcours, hangbruggen, touwen. Open april tot oktober. Prijs: kinderen 14€, volwassenen 18€.","PT":"Parque de aventura no pinhal de L'Ampolla. Circuitos de tirolesa, pontes suspensas. Aberto de abril a outubro. Preço: crianças 14€, adultos 18€."}},{"icon":"🌊","name":{"CA":"Kayak i paddleboard familiar","ES":"Kayak y paddleboard familiar","EN":"Family kayak and paddleboard","FR":"Kayak et paddle en famille","DE":"Familien-Kajak und Paddelbrett","NL":"Familie kayak en paddleboard","PT":"Kayak e paddleboard familiar"},"age":{"CA":"A partir de 5 anys (acompanyats)","ES":"A partir de 5 años (acompañados)","EN":"From 5 years (accompanied)","FR":"Dès 5 ans (accompagnés)","DE":"Ab 5 Jahren (begleitet)","NL":"Vanaf 5 jaar (begeleid)","PT":"A partir de 5 anos (acompanhados)"},"desc":{"CA":"Les aigües calm des del delta són ideals per a kayak familiar. Diverses empreses ofereixen lloguer i activitats guiades pels canals i les llacunes. Activitat molt recomanada a la badia dels Alfacs (la Ràpita) i als canals del hemidelta nord (Deltebre, Sant Jaume). Preu: kayak doble ~15-20€/hora.","ES":"Las aguas tranquilas del delta son ideales para kayak familiar. Varias empresas ofrecen alquiler y actividades guiadas por canales y lagunas. Muy recomendado en la bahía de los Alfacs (la Ràpita) y canales del hemidelta norte. Precio: kayak doble ~15-20€/hora.","EN":"The calm delta waters are ideal for family kayaking. Several companies offer rentals and guided activities through canals and lagoons. Highly recommended in Alfacs Bay (la Ràpita) and northern hemidelta canals. Price: double kayak ~€15-20/hour.","FR":"Les eaux calmes du delta sont idéales pour le kayak familial. Baie des Alfacs et canaux du delta nord recommandés. Prix: kayak double ~15-20€/h.","DE":"Die ruhigen Deltawasser sind ideal für Familien-Kajak. Alfacs-Bucht und Nordkanal empfohlen. Preis: Doppelkajak ~15-20€/Std.","NL":"De rustige deltawateren zijn ideaal voor familie-kayak. Alfacs-baai en noordelijke kanalen aanbevolen. Prijs: dubbele kajak ~15-20€/uur.","PT":"As águas calmas do delta são ideais para kayak familiar. Baía dos Alfacs e canais recomendados. Preço: caiaque duplo ~15-20€/hora."}},{"icon":"🚜","name":{"CA":"Visita a una granja d'arròs","ES":"Visita a una granja de arroz","EN":"Visit a rice farm","FR":"Visite d'une ferme de riz","DE":"Besuch einer Reisfarm","NL":"Bezoek aan een rijstboerderij","PT":"Visita a uma quinta de arroz"},"age":{"CA":"A partir de 3 anys","ES":"A partir de 3 años","EN":"From 3 years old","FR":"Dès 3 ans","DE":"Ab 3 Jahren","NL":"Vanaf 3 jaar","PT":"A partir de 3 anos"},"desc":{"CA":"El delta produeix 130.000 tones d'arròs l'any. Algunes granges ofereixen visites guiades: veure com funciona el sistema de canals, la sembra i la collita (setembre-octubre), degustar arròs local. Época de collita (setembre-octubre): espectacle de llums i aus als arrossars inundats. Pregunta a la oficina de turisme per les granges que fan visites.","ES":"El delta produce 130.000 toneladas de arroz al año. Algunas granjas ofrecen visitas guiadas: ver el sistema de canales, la siembra y la cosecha (sept-oct), degustar arroz local. Cosecha (sept-oct): espectáculo de luces y aves en los arrozales inundados.","EN":"The delta produces 130,000 tonnes of rice per year. Some farms offer guided tours: see the canal system, planting and harvest (Sept-Oct), taste local rice. Harvest season (Sept-Oct): spectacular light and bird show in flooded paddies.","FR":"Le delta produit 130 000 tonnes de riz par an. Certaines fermes proposent des visites: système de canaux, semis et récolte (sept-oct), dégustation.","DE":"Das Delta produziert 130.000 Tonnen Reis pro Jahr. Einige Farmen bieten Führungen an: Kanalsystem, Anbau und Ernte (Sept-Okt), Verkostung.","NL":"De delta produceert 130.000 ton rijst per jaar. Sommige boerderijen bieden rondleidingen aan: kanaal, zaaien en oogst (sept-okt), proeven.","PT":"O delta produz 130.000 toneladas de arroz por ano. Algumas quintas oferecem visitas: sistema de canais, sementeira e colheita (set-out), degustação."}}];

export const D_LOCALS = [{"id":"muum","type":"disco","name":"MUUM Discoteca","town":{"CA":"Deltebre","ES":"Deltebre","EN":"Deltebre","FR":"Deltebre","DE":"Deltebre","NL":"Deltebre","PT":"Deltebre"},"desc":{"CA":"La discoteca de Deltebre. Dues sales amb ambient diferent: comercial i techno. Entrada ~10€. Seguretat professional i bon ambient.","ES":"La discoteca de Deltebre. Dos salas: comercial y techno. Entrada ~10€. Seguridad profesional y buen ambiente.","EN":"Deltebre's nightclub. Two rooms: commercial and techno. Entry ~€10. Professional security and good atmosphere.","FR":"La discothèque de Deltebre. Deux salles: commerciale et techno. Entrée ~10€.","DE":"Die Diskothek von Deltebre. Zwei Räume: kommerziell und Techno. Eintritt ~10€.","NL":"De discotheek van Deltebre. Twee ruimten: commercieel en techno. Toegang ~€10.","PT":"A discoteca de Deltebre. Duas salas: comercial e techno. Entrada ~10€."},"lat":40.7253021,"lng":0.7125157,"pid":"ChIJrz9hXDIEoRIRhPj_Iv7hthw"},{"id":"papua","type":"pub","name":"Pub Papua","town":{"CA":"L'Ampolla","ES":"L'Ampolla","EN":"L'Ampolla","FR":"L'Ampolla","DE":"L'Ampolla","NL":"L'Ampolla","PT":"L'Ampolla"},"desc":{"CA":"El pub de referència de l'Ampolla. Decoració tropical, música animada i ambient molt local. A la Plaça Eloy Mestre, al cor del poble.","ES":"El pub de referencia de L'Ampolla. Decoración tropical, música animada y ambiente muy local. En la Plaza Eloy Mestre.","EN":"L'Ampolla's go-to pub. Tropical decor, upbeat music and very local atmosphere. In Plaça Eloy Mestre.","FR":"Le pub de référence de L'Ampolla. Décor tropical et musique entraînante. Plaça Eloy Mestre.","DE":"L'Ampollas Stammkneipe. Tropisches Dekor und lebhafte Musik. Plaça Eloy Mestre.","NL":"L'Ampollas vaste pub. Tropisch decor en levendige muziek. Plaça Eloy Mestre.","PT":"O pub de referência de L'Ampolla. Decoração tropical e música animada. Plaça Eloy Mestre."},"lat":40.8108192,"lng":0.7069753,"pid":"ChIJXaFHcSQboRIRhfq2IZ3JPqo"},{"id":"boca","type":"disco","name":"BOCAaBOCA Club","town":{"CA":"Amposta","ES":"Amposta","EN":"Amposta","FR":"Amposta","DE":"Amposta","NL":"Amposta","PT":"Amposta"},"desc":{"CA":"El club nocturn de referència d'Amposta. Poliesportiu reconvertit en sala de festes amb gran pista de ball i barra llarga. Festes temàtiques regularment.","ES":"El club nocturno de referencia de Amposta. Polideportivo reconvertido en sala de fiestas con gran pista de baile y barra larga. Fiestas temáticas regularmente.","EN":"Amposta's reference nightclub. Sports venue converted into a dance hall with large dancefloor and long bar. Regular themed parties.","FR":"Le club nocturne de référence d'Amposta. Salle de fêtes avec grande piste de danse et long bar. Fêtes thématiques régulièrement.","DE":"Der Referenz-Nachtclub von Amposta. Sportarena, umgebaut zur Diskothek mit großer Tanzfläche und langer Bar. Regelmäßige Mottopartys.","NL":"De referentie nachtclub van Amposta. Sporthal omgebouwd tot feestzaal met grote dansvloer en lange bar. Regelmatig themafeesten.","PT":"O clube noturno de referência de Amposta. Pavilhão convertido em sala de festas com grande pista e barra comprida. Festas temáticas regularmente."},"lat":40.7047862,"lng":0.5586154,"pid":"ChIJS4nYCiH_oBIRXaullANRDGg","phone":"+34 642 31 62 31"},{"id":"legend","type":"disco","name":"Legend Music Club","town":{"CA":"Amposta","ES":"Amposta","EN":"Amposta","FR":"Amposta","DE":"Amposta","NL":"Amposta","PT":"Amposta"},"desc":{"CA":"Discoteca al cor d'Amposta, a la sala polivalent de La Lira Ampostina. Excel·lent ambient, bon tracte de la seguretat i el personal de barra. Programació variada amb DJ sessions i artistes en directe. Una de les poques discoteques de la zona del delta.","ES":"Discoteca en el corazón de Amposta, en la sala polivalente de La Lira Ampostina. Excelente ambiente, buen trato de la seguridad y el personal de barra. Programación variada con DJ sessions y artistas en directo. Una de las pocas discotecas de la zona del delta.","EN":"Nightclub at the heart of Amposta, in the multipurpose hall of La Lira Ampostina. Excellent atmosphere, good staff and security. Varied programme with DJ sessions and live artists. One of the few real nightclubs in the delta area.","FR":"Boîte de nuit au cœur d'Amposta, dans la salle polyvalente de La Lira Ampostina. Excellente atmosphère, bon personnel et sécurité. Programme varié avec sessions DJ et artistes live.","DE":"Diskothek im Herzen von Amposta, in der Mehrzweckhalle der Lira Ampostina. Ausgezeichnete Atmosphäre, gutes Personal und Sicherheit. Abwechslungsreiches Programm.","NL":"Discotheek in het hart van Amposta, in de multifunctionele zaal van La Lira Ampostina. Uitstekende sfeer, goed personeel en beveiliging.","PT":"Discoteca no coração de Amposta, na sala polivalente da Lira Ampostina. Excelente ambiente e pessoal. Programa variado com sessões de DJ e artistas ao vivo."},"lat":40.7112288,"lng":0.577476,"pid":"ChIJbbcX4iH_oBIR0sjcledbLV8"},{"id":"guarida","type":"pub","name":"Pub La Guarida","town":{"CA":"Amposta","ES":"Amposta","EN":"Amposta","FR":"Amposta","DE":"Amposta","NL":"Amposta","PT":"Amposta"},"desc":{"CA":"Pub musical de referència a Amposta. Bon ambient i programació regular d'esdeveniments musicals. Punt de partida habitual de la nit ampostina.","ES":"Pub musical de referencia en Amposta. Buen ambiente y programación regular de eventos musicales. Punto de partida habitual de la noche ampostina.","EN":"Reference music pub in Amposta. Good atmosphere and regular music events. The usual starting point for a night out in Amposta.","FR":"Pub musical de référence à Amposta. Bonne atmosphère et programme régulier d'événements musicaux.","DE":"Referenz-Musikpub in Amposta. Gute Atmosphäre und regelmäßige Musikveranstaltungen.","NL":"Referentie muziekpub in Amposta. Goede sfeer en regelmatige muziekprogramma's.","PT":"Pub musical de referência em Amposta. Boa atmosfera e programação regular de eventos musicais."},"lat":40.706,"lng":0.58},{"id":"oqio","type":"pub","name":"Oqio Lounge","town":{"CA":"Amposta","ES":"Amposta","EN":"Amposta","FR":"Amposta","DE":"Amposta","NL":"Amposta","PT":"Amposta"},"desc":{"CA":"Bar lounge modern a Amposta. Ambient relaxat entre setmana i més animat el cap de setmana amb DJ. Bon servei de coctelèria.","ES":"Bar lounge moderno en Amposta. Ambiente relajado entre semana y más animado el fin de semana con DJ. Buen servicio de coctelería.","EN":"Modern lounge bar in Amposta. Relaxed vibe on weekdays and livelier at weekends with DJ. Good cocktail service.","FR":"Bar lounge moderne à Amposta. Ambiance décontractée en semaine et plus animée le week-end avec DJ. Bon service cocktail.","DE":"Moderner Lounge-Bar in Amposta. Entspannte Atmosphäre unter der Woche und lebhafter am Wochenende mit DJ. Guter Cocktailservice.","NL":"Moderne lounge bar in Amposta. Relaxte sfeer door de week en levendiger in het weekend met DJ. Goede cocktailservice.","PT":"Bar lounge moderno em Amposta. Ambiente descontraído durante a semana e mais animado ao fim de semana com DJ. Bom serviço de cocktails."},"lat":40.705,"lng":0.581},{"id":"bohemia","type":"beach","name":"Bohemia Mar","town":{"CA":"El Perelló","ES":"El Perelló","EN":"El Perelló","FR":"El Perelló","DE":"El Perelló","NL":"El Perelló","PT":"El Perelló"},"desc":{"CA":"Xiringuito de referència a la platja de Santa Llúcia d'El Perelló. Vistes espectaculars al mar amb programació musical de dimecres a diumenge: artistes de diversos gèneres actuen sota els arbres amb el so de les ones de fons. A l'estiu s'omple de visitants que fan la ruta del GR-92 entre l'Ametlla i l'Ampolla. Cuina mediterrània de dia i marxa musical de nit.","ES":"Chiringuito de referencia en la playa de Santa Llúcia de El Perelló. Vistas espectaculares al mar con programación musical de miércoles a domingo: artistas de diversos géneros actúan bajo los árboles con el sonido de las olas de fondo. En verano se llena de visitantes que hacen la ruta GR-92 entre l'Ametlla y l'Ampolla.","EN":"Reference beach bar on Santa Llúcia beach, El Perelló. Spectacular sea views with music programming Wed–Sun: artists of various genres perform under the trees to the sound of waves. In summer it fills with hikers doing the GR-92 coastal path between l'Ametlla and l'Ampolla.","FR":"Bar de plage de référence à la plage de Santa Llúcia, El Perelló. Vues spectaculaires sur la mer avec programmation musicale mer.–dim. : artistes de différents genres sous les arbres, au son des vagues.","DE":"Referenz-Strandbar am Strand Santa Llúcia, El Perelló. Spektakuläre Meeresblicke mit Musikprogramm Mi.–So.: Künstler verschiedener Genres unter den Bäumen zum Rauschen der Wellen.","NL":"Referentie strandbar op het strand Santa Llúcia, El Perelló. Spectaculair uitzicht op zee met muziekprogramma wo.–zo.: artiesten van diverse genres onder de bomen, met het geluid van de golven.","PT":"Bar de praia de referência na praia de Santa Llúcia, El Perelló. Vistas espetaculares ao mar com programação musical qua.–dom.: artistas de vários géneros sob as árvores com o som das ondas."},"phone":"+34 621 14 79 87","lat":40.8303794,"lng":0.741447,"pid":"ChIJvY1RJZoboRIRCl-oGfo6Rmo"},{"id":"estiu","type":"beach","name":{"CA":"Bars de platja i chiringuitos (Estiu)","ES":"Bares de playa y chiringuitos (Verano)","EN":"Beach bars & chiringuitos (Summer)","FR":"Bars de plage et chiringuitos (Été)","DE":"Strandbar und Chiringuitos (Sommer)","NL":"Strandbar en chiringuitos (Zomer)","PT":"Bares de praia e chiringuitos (Verão)"},"town":{"CA":"Riumar, l'Ampolla, les Cases d'Alcanar","ES":"Riumar, l'Ampolla, les Cases d'Alcanar","EN":"Riumar, l'Ampolla, les Cases d'Alcanar","FR":"Riumar, l'Ampolla, les Cases d'Alcanar","DE":"Riumar, l'Ampolla, les Cases d'Alcanar","NL":"Riumar, l'Ampolla, les Cases d'Alcanar","PT":"Riumar, l'Ampolla, les Cases d'Alcanar"},"desc":{"CA":"A l'estiu (juliol-agost), els pobles costaners s'animen especialment a la nit. Riumar té bars informals a la urbanització. L'Ampolla anima el passeig marítim. Les Cases d'Alcanar té terrasses al port fins ben entrada la nit. L'oferta varia molt d'any en any.","ES":"En verano (julio-agosto), los pueblos costeros se animan especialmente por la noche. Riumar tiene bares informales en la urbanización. L'Ampolla anima el paseo marítimo. Les Cases d'Alcanar tiene terrazas en el puerto hasta bien entrada la noche. La oferta varía mucho de un año a otro.","EN":"In summer (July-August), coastal villages come alive at night. Riumar has informal bars in the resort area. l'Ampolla animates its seafront promenade. Les Cases d'Alcanar has port terrace bars open late into the night. The offer varies greatly year to year.","FR":"En été (juillet-août), les villages côtiers s'animent la nuit. Riumar a des bars informels dans la station. L'Ampolla anime sa promenade. Les Cases d'Alcanar a des terrasses au port jusqu'au bout de la nuit.","DE":"Im Sommer (Juli-August) belebten sich die Küstendörfer nachts. Riumar hat informelle Bars im Resort. l'Ampolla belebt seine Strandpromenade. Les Cases d'Alcanar hat Hafenterrassen bis spät in die Nacht.","NL":"In de zomer (juli-augustus) leeft het op aan de kust. Riumar heeft informele bars in het resort. l'Ampolla animeert zijn boulevard. Les Cases d'Alcanar heeft haventterassen open tot laat in de nacht.","PT":"No verão (julho-agosto), as localidades costeiras animam-se à noite. Riumar tem bares informais na urbanização. l'Ampolla anima o seu passeio marítimo."},"lat":40.748,"lng":0.864}];

